const DEFAULT_NO_LEARNER_ASSIGNED_LABEL = "No learner assigned";
const DEFAULT_NO_PRIMARY_SP_ASSIGNED_LABEL = "No primary SP assigned";

const FacultyContactForm = memo(function FacultyContactForm({
  sourceDraft,
  saving,
  variant,
  fallbackFacultyText,
  simContactPlaceholder,
  mutedColor,
  chipStyle,
  inputBaseStyle,
  textareaBaseStyle,
  onSave,
  renderExtraActions,
}: {
  sourceDraft: FacultyContactDraft;
  saving: boolean;
  variant: "central" | "dock";
  fallbackFacultyText: string;
  simContactPlaceholder: string;
  mutedColor: string;
  chipStyle: React.CSSProperties;
  inputBaseStyle: React.CSSProperties;
  textareaBaseStyle: React.CSSProperties;
  onSave: (draft: FacultyContactDraft) => void;
  renderExtraActions?: (draft: FacultyContactDraft, dirty: boolean) => React.ReactNode;
}) {
  const [draft, setDraft] = useState<FacultyContactDraft>(sourceDraft);

  useEffect(() => {
    setDraft(sourceDraft);
  }, [sourceDraft]);

  const draftKey = useMemo(() => JSON.stringify(draft), [draft]);
  const sourceKey = useMemo(() => JSON.stringify(sourceDraft), [sourceDraft]);
  const dirty = draftKey !== sourceKey;

  const fields = [
    { key: "faculty_names" as const, label: "Faculty name", placeholder: fallbackFacultyText || "Faculty name" },
    { key: "faculty_program" as const, label: "Program / course", placeholder: "Program or course" },
    { key: "faculty_email" as const, label: "Faculty email", placeholder: "name@school.edu" },
    { key: "faculty_phone" as const, label: "Faculty phone", placeholder: "Phone" },
    { key: "sim_contact" as const, label: "Sim team / event lead", placeholder: simContactPlaceholder || "Sim lead or event lead" },
  ];

  const gridTemplateColumns =
    variant === "central"
      ? "repeat(auto-fit, minmax(170px, 1fr))"
      : "repeat(auto-fit, minmax(110px, 1fr))";

  return (
    <div style={{ display: "grid", gap: variant === "central" ? "8px" : "10px" }}>
      <div style={{ display: "grid", gridTemplateColumns, gap: variant === "central" ? "8px" : "10px", marginTop: variant === "dock" ? "12px" : 0 }}>
        {fields.map((field) => (
          <label
            key={`faculty-contact-draft-${variant}-${field.key}`}
            style={{
              display: "grid",
              gap: variant === "central" ? "5px" : "6px",
              gridColumn: field.key === "sim_contact" ? "1 / -1" : undefined,
            }}
          >
            <span style={{ ...statLabel, color: mutedColor }}>{field.label}</span>
            <input
              value={draft[field.key]}
              onChange={(event) => {
                const value = event.target.value;
                setDraft((current) => ({ ...current, [field.key]: value }));
              }}
              disabled={saving}
              placeholder={field.placeholder}
              data-admin-field={field.key}
              style={inputBaseStyle}
            />
          </label>
        ))}
        <label style={{ display: "grid", gap: variant === "central" ? "5px" : "6px", gridColumn: "1 / -1" }}>
          <span style={{ ...statLabel, color: mutedColor }}>Internal notes</span>
          <textarea
            value={draft.contact_internal_notes}
            onChange={(event) => {
              const value = event.target.value;
              setDraft((current) => ({ ...current, contact_internal_notes: value }));
            }}
            disabled={saving}
            placeholder="Internal context, escalation notes, or faculty preferences"
            style={textareaBaseStyle}
          />
        </label>
      </div>
      <div style={{ display: "flex", gap: "6px", flexWrap: "wrap", alignItems: "center" }}>
        <button
          type="button"
          onClick={() => onSave(draft)}
          disabled={saving}
          style={{ ...buttonStyle, padding: variant === "central" ? "7px 10px" : "8px 12px", opacity: saving ? 0.65 : 1 }}
        >
          {saving ? "Saving..." : "Save Faculty Info"}
        </button>
        {renderExtraActions ? renderExtraActions(draft, dirty) : null}
        {dirty ? (
          <span style={{ ...chipStyle, background: "rgba(245, 158, 11, 0.14)", color: "var(--cfsp-warning)" }}>
            Unsaved changes
          </span>
        ) : null}
      </div>
    </div>
  );
});

function normalizeOperationalBadgeKey(label: unknown) {
  const normalized = asText(label)
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  if (normalized === "in person" || normalized === "inperson") return "in person";
  return normalized;
}

function isNeedsSpOperationalBadge(label: unknown) {
  const key = normalizeOperationalBadgeKey(label);
  return key === "needs sps" || key === "needs sp" || key === "needs staffing";
}

type OperationalBadgePipelineItem = {
  key: string;
  label: string;
  style?: React.CSSProperties;
  showInHeader?: boolean;
  showInSummary?: boolean;
};

function buildOperationalBadgePipeline(badges: OperationalBadgePipelineItem[]) {
  const merged = new Map<string, OperationalBadgePipelineItem>();

  badges.forEach((badge) => {
    const key = normalizeOperationalBadgeKey(badge.label);
    if (!key) return;

    const existing = merged.get(key);
    if (existing) {
      merged.set(key, {
        ...existing,
        showInHeader: Boolean(existing.showInHeader || badge.showInHeader),
        showInSummary: Boolean(existing.showInSummary || badge.showInSummary),
        style: existing.style || badge.style,
      });
      return;
    }

    merged.set(key, badge);
  });

  return Array.from(merged.values());
}

function normalizeEventRecordingStatusValue(value: unknown): EventRecordingStatusValue | "" {
  const normalized = asText(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");

  if (!normalized) return "";
  if (normalized === "not_required" || normalized === "not_recorded" || normalized === "not_recorded_but_required" || normalized === "disabled") return "not_required";
  if (
    normalized === "recorded" ||
    normalized === "recording_complete" ||
    normalized === "complete" ||
    normalized === "finished" ||
    normalized === "recording_enabled" ||
    normalized === "recording_live" ||
    normalized === "live_recording"
  ) {
    return "recorded";
  }
  if (
    normalized === "recording_planned" ||
    normalized === "planned" ||
    normalized === "recording_scheduled"
  ) return "recording_planned";
  if (
    normalized === "recording_in_progress" ||
    normalized === "in_progress" ||
    normalized === "pending" ||
    normalized === "recording_pending"
  ) {
    return "recording_in_progress";
  }
  if (normalized === "missing" || normalized === "not_found") return "missing";
  return "";
}

function getEventRecordingStatusOption(value: unknown) {
  const normalized = normalizeEventRecordingStatusValue(value);
  return normalized
    ? eventRecordingStatusOptions.find((option) => option.value === normalized) || null
    : null;
}

function normalizeTrainingRecordingStatusValue(value: unknown): TrainingRecordingStatusValue | "" {
  const normalized = asText(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");

  if (!normalized) return "";
  if (normalized === "not_recorded" || normalized === "disabled") return "not_recorded";
  if (
    normalized === "recorded" ||
    normalized === "recording_enabled" ||
    normalized === "recording_live" ||
    normalized === "live_recording"
  ) {
    return "recorded";
  }
  if (normalized === "recording_planned" || normalized === "planned") return "recording_planned";
  if (normalized === "recording_pending" || normalized === "pending") return "recording_pending";
  if (normalized === "recording_not_allowed" || normalized === "not_allowed") return "recording_not_allowed";
  return "";
}

function getTrainingRecordingStatusOption(value: unknown) {
  const normalized = normalizeTrainingRecordingStatusValue(value);
  return normalized
    ? trainingRecordingStatusOptions.find((option) => option.value === normalized) || null
    : null;
}

function normalizeTrainingRequirementValue(value: unknown): TrainingRequirementValue {
  const normalized = asText(value).toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
  if (["yes", "required", "training_required", "true"].includes(normalized)) return "yes";
  if (["no", "not_required", "training_not_required", "false"].includes(normalized)) return "no";
  return "tbd";
}

function normalizeTrainingOwnershipValue(value: unknown): TrainingOwnershipValue {
  const normalized = asText(value).toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
  if (["faculty", "faculty_led", "faculty_lead", "faculty_owned"].includes(normalized)) return "faculty_led";
  if (["internal", "internal_sim", "sim", "sim_team", "sim_center", "simulation_team"].includes(normalized)) return "internal_sim";
  if (["shared", "co_led", "coled", "shared_co_led"].includes(normalized)) return "shared";
  return "tbd";
}

function normalizeTrainingSchedulingValue(value: unknown): TrainingSchedulingValue {
  const normalized = asText(value).toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
  if (["complete", "completed", "done"].includes(normalized)) return "completed";
  if (["scheduled", "confirmed"].includes(normalized)) return "scheduled";
  if (["planned", "preferred", "window_planned", "preferred_window_planned"].includes(normalized)) return "planned";
  return "not_scheduled";
}

function getTrainingRequirementLabel(value: TrainingRequirementValue) {
  return trainingRequirementOptions.find((option) => option.value === value)?.label || "TBD";
}

function getTrainingOwnershipLabel(value: TrainingOwnershipValue) {
  return trainingOwnershipOptions.find((option) => option.value === value)?.label || "TBD";
}

function getTrainingSchedulingLabel(value: TrainingSchedulingValue) {
  return trainingSchedulingOptions.find((option) => option.value === value)?.label || "Not scheduled";
}

function isMetadataYes(value: unknown) {
  return ["yes", "true", "1", "required", "planned"].includes(asText(value).toLowerCase());
}

function isMetadataNo(value: unknown) {
  return ["no", "false", "0", "not_required", "not required", "none"].includes(asText(value).toLowerCase());
}

function normalizeMaterialsReadinessValue(value: unknown): MaterialsReadinessValue | "" {
  const normalized = asText(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");
  const aliases: Record<string, MaterialsReadinessValue> = {
    not_reviewed: "materials_not_reviewed",
    materials_not_reviewed: "materials_not_reviewed",
    materials_needed: "materials_needed",
    needs_materials: "materials_needed",
    awaiting_faculty_materials: "awaiting_faculty_materials",
    faculty_materials_pending: "awaiting_faculty_materials",
    materials_uploaded: "materials_uploaded",
    uploaded: "materials_uploaded",
    review_requested: "materials_uploaded",
    materials_review_requested: "materials_uploaded",
    materials_ready: "materials_ready",
    ready: "materials_ready",
    materials_not_required: "materials_not_required",
    not_required: "materials_not_required",
  };
  return aliases[normalized] || "";
}

function getMaterialsReadinessOption(value: unknown) {
  const normalized = normalizeMaterialsReadinessValue(value);
  return normalized
    ? materialsReadinessOptions.find((option) => option.value === normalized) || null
    : null;
}

function RecordingStatusIndicator({
  label,
  compact = false,
  hot = false,
  liveMode = false,
  planningMode = false,
}: {
  label: string;
  compact?: boolean;
  hot?: boolean;
  liveMode?: boolean;
  planningMode?: boolean;
}) {
  const className = [
    "cfsp-recording-indicator",
    compact ? "is-compact" : "",
    hot ? "is-hot" : "",
    liveMode ? "is-live" : "",
    planningMode ? "is-planning" : "",
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <span className={className} aria-label={`Recording status: ${label}`} title={`Recording status: ${label}`}>
      <span className="cfsp-recording-dot" aria-hidden="true" />
      <span>{label}</span>
    </span>
  );
}

function getFullName(sp: SPRow) {
  const explicit = normalizeDisplayText(sp.full_name);
  if (explicit) return explicit;

  const joined = [sp.first_name, sp.last_name].map(normalizeDisplayText).filter(Boolean).join(" ");
  return joined || "Unnamed SP";
}

function getInitials(value: string) {
  const parts = asText(value).split(/\s+/).filter(Boolean);
  if (!parts.length) return "SP";
  const first = parts[0]?.[0] || "";
  const last = parts.length > 1 ? parts[parts.length - 1]?.[0] || "" : parts[0]?.[1] || "";
  return `${first}${last}`.toUpperCase() || "SP";
}

type RoundOperationAvatarRole = "student" | "sp" | "operations";
type OperationalPresenceAvatarKind = "sp" | "learner" | "backup" | "faculty";
type OperationalPresenceAvatarStatus = "expected" | "arrived" | "in-room" | "late" | "missing";
type OperationalPresenceAvatarSize = "sm" | "md" | "lg";

function getRoundOperationAvatarLabel(value: string, role: RoundOperationAvatarRole) {
  const text = asText(value).trim();
  if (!text) {
    return role === "sp" ? "SP" : role === "student" ? "L" : "OP";
  }

  return role === "operations" ? "OP" : getInitials(text);
}

function OperationalPresenceAvatar({
  name,
  initials,
  kind,
  status = "expected",
  size = "md",
  selected = false,
  onClick,
}: {
  name: string;
  initials?: string;
  kind: OperationalPresenceAvatarKind;
  status?: OperationalPresenceAvatarStatus;
  size?: OperationalPresenceAvatarSize;
  selected?: boolean;
  onClick?: () => void;
}) {
  const label = asText(name).trim() || (kind === "learner" ? "Learner" : kind === "backup" ? "Backup SP" : kind.toUpperCase());
  const resolvedInitials = (asText(initials) || getInitials(label)).slice(0, 3).toUpperCase();
  const present = status === "arrived" || status === "in-room";
  const statusLabel = getEventAttendanceStatusLabel(status === "in-room" ? "in_room" : status);
  const className = [
    "cfsp-operational-presence-avatar",
    "cfsp-hologram-avatar",
    `is-${kind}`,
    `is-${size}`,
    `status-${status}`,
    selected ? "is-selected" : "",
    present ? "is-present" : "",
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <span
      className={className}
      aria-hidden={onClick ? undefined : "true"}
      aria-label={onClick ? `${label} - ${statusLabel}` : undefined}
      title={`${label}${status ? ` - ${statusLabel}` : ""}`}
      onClick={onClick}
      onKeyDown={(event) => {
        if (!onClick) return;
        if (isTypingTarget(event.target)) return;
        if (event.key === "Enter" || event.key === " ") {
          event.preventDefault();
          onClick();
        }
      }}
      role={onClick ? "button" : undefined}
      tabIndex={onClick ? 0 : undefined}
    >
      <span className="cfsp-hologram-avatar-aura" aria-hidden="true" />
      <span className="cfsp-hologram-avatar-scan" aria-hidden="true" />
      <span className="cfsp-hologram-avatar-figure" aria-hidden="true">
        <span className="cfsp-hologram-avatar-head" />
        <span className="cfsp-hologram-avatar-neck" />
        <span className="cfsp-hologram-avatar-shoulders" />
        <span className="cfsp-hologram-avatar-core" />
      </span>
      <span className="cfsp-hologram-avatar-badge" aria-hidden="true">
        {resolvedInitials}
      </span>
      {present ? <span className="cfsp-hologram-avatar-check" aria-hidden="true">✓</span> : null}
    </span>
  );
}

function RoundOperationAvatar({
  name,
  role,
  onClick,
}: {
  name: string;
  role: RoundOperationAvatarRole;
  onClick?: () => void;
}) {
  return (
    <OperationalPresenceAvatar
      name={name}
      initials={getRoundOperationAvatarLabel(name, role)}
      kind={role === "sp" ? "sp" : role === "student" ? "learner" : "faculty"}
      status="expected"
      size="sm"
      onClick={onClick}
    />
  );
}

function getEventAttendanceStatusLabel(value: unknown) {
  const status = asText(value).toLowerCase();
  if (status === "arrived") return "Arrived";
  if (status === "late") return "Late";
  if (status === "missing" || status === "absent") return "Missing";
  if (status === "in_room") return "In Room";
  if (status === "completed") return "Completed";
  return "Expected";
}

function isEventAttendancePresentStatus(value: unknown) {
  const status = normalizeEventAttendanceStatus(value);
  return status === "arrived" || status === "in_room" || status === "completed";
}

function getEventAttendanceStatusColors(value: unknown) {
  const status = asText(value).toLowerCase();
  if (status === "arrived") {
    return { ring: "#059669", bg: "rgba(16, 185, 129, 0.16)", text: "#064e3b" };
  }
  if (status === "late") {
    return { ring: "#b45309", bg: "rgba(245, 158, 11, 0.16)", text: "#7c2d12" };
  }
  if (status === "missing" || status === "absent") {
    return { ring: "#dc2626", bg: "rgba(248, 113, 113, 0.16)", text: "#7f1d1d" };
  }
  if (status === "in_room") {
    return { ring: "#0f766e", bg: "rgba(20, 184, 166, 0.16)", text: "#134e4a" };
  }
  if (status === "completed") {
    return { ring: "#16a34a", bg: "rgba(34, 197, 94, 0.16)", text: "#14532d" };
  }
  return { ring: "#7aa3c2", bg: "rgba(232, 244, 255, 0.82)", text: "#12324d" };
}

function normalizeEventAttendanceStatus(value: unknown): EventAttendanceFilter {
  const status = asText(value).toLowerCase();
  if (status === "arrived") return "arrived";
  if (status === "late") return "late";
  if (status === "missing" || status === "absent") return "missing";
  if (status === "in_room") return "in_room";
  if (status === "completed") return "completed";
  return "expected";
}

function getNextAttendanceToggleStatus(
  status: EventAttendanceFilter,
  options?: { inRoomWhenCurrent?: boolean }
): "expected" | "arrived" | "in_room" {
  if (isEventAttendancePresentStatus(status)) return "expected";
  if (options?.inRoomWhenCurrent) return "in_room";
  return "arrived";
}

function getAttendanceToggleLabel(
  name: string,
  status: EventAttendanceFilter,
  options?: { inRoomWhenCurrent?: boolean }
) {
  const personName = asText(name) || "Participant";
  const nextStatus = getNextAttendanceToggleStatus(status, options);
  return `Mark ${personName} ${nextStatus === "expected" ? "expected" : nextStatus === "in_room" ? "in room" : "arrived"}`;
}

type EventAttendanceAvatarRole = "sp" | "learner";

function EventAttendanceHologramAvatar({
  name,
  role,
  status,
  selected = false,
  compact = false,
}: {
  name: string;
  role: EventAttendanceAvatarRole;
  status: EventAttendanceFilter;
  selected?: boolean;
  compact?: boolean;
}) {
  const initials = getRoundOperationAvatarLabel(name, role === "sp" ? "sp" : "student");
  const operationalStatus: OperationalPresenceAvatarStatus =
    status === "arrived"
      ? "arrived"
      : status === "in_room" || status === "completed"
        ? "in-room"
        : status === "late"
          ? "late"
          : status === "missing"
            ? "missing"
            : "expected";
  return (
    <OperationalPresenceAvatar
      name={name}
      initials={initials}
      kind={role === "sp" ? "sp" : "learner"}
      status={operationalStatus}
      size={compact ? "sm" : "md"}
      selected={selected}
    />
  );
}

function getRoomDisplayNumber(label?: string | null) {
  const match = asText(label).match(/\d+/);
  return match ? Number.parseInt(match[0], 10) : null;
}

function compareRoomLabels(a?: string | null, b?: string | null) {
  const aText = asText(a);
  const bText = asText(b);
  const aNumber = getRoomDisplayNumber(aText);
  const bNumber = getRoomDisplayNumber(bText);

  if (aNumber !== null && bNumber !== null && aNumber !== bNumber) return aNumber - bNumber;
  if (aNumber !== null && bNumber === null) return -1;
  if (aNumber === null && bNumber !== null) return 1;

  return aText.localeCompare(bText, undefined, {
    numeric: true,
    sensitivity: "base",
  });
}

function sortRoomLabelsForDisplay(rooms: string[]) {
  return [...rooms].sort(compareRoomLabels);
}

function getHighestRoomDisplayNumber(labels: Array<string | null | undefined>) {
  return labels.reduce((highest, label) => {
    const number = getRoomDisplayNumber(label);
    return number !== null ? Math.max(highest, number) : highest;
  }, 0);
}

function isRoomPlaceholderLabel(label?: string | null) {
  const normalized = asText(label).trim().toLowerCase();
  return !normalized || /\b(tbd|to be determined|to-be-determined)\b/.test(normalized);
}

function getFallbackRoomLabel(index: number, roomContext: RoomNamingContext = {}) {
  return getRoomDisplayLabelFromIndex("", index, roomContext);
}

function buildRoomLabelFromTemplate(
  template: string,
  roomNumber: number,
  roomContext: RoomNamingContext = {}
) {
  const text = asText(template);
  const safeRoomNumber = Math.max(1, Number.isFinite(roomNumber) ? roomNumber : 1);
  if (!text) {
    return getRoomDisplayLabel(
      text,
      safeRoomNumber,
      roomContext,
      resolveRoomTypeHint(text)
    );
  }
  if (roomNumber <= 0) {
    return getRoomDisplayLabel(text, 1, roomContext, resolveRoomTypeHint(text));
  }
  if (/\d+/.test(text)) {
    return text.replace(/(\d+)/, String(safeRoomNumber));
  }
  return `${getRoomTypeLabel(roomContext)} ${safeRoomNumber}`;
}

function resolveRoomTypeHint(roomName: string | null | undefined): RoomTypeHint | undefined {
  const text = asText(roomName).toLowerCase();
  if (/\bbreakout\b/.test(text) || /^room\s*\d*$/.test(text)) return "breakout";
  if (/\bvirtual\b/.test(text)) return "virtual";
  if (/\bflex\b/.test(text)) return "flex";
  if (/\boverflow\b/.test(text)) return "overflow";
  if (/\bexam\b/.test(text)) return "exam";
  if (/\broom\b/.test(text)) return "exam";
  return undefined;
}

function buildFullNumericRoomDisplayEntries(
  roomLabels: Array<string | null | undefined>,
  expectedRoomCount: number,
  fallbackPrefix = "",
  roomContext: RoomNamingContext = {}
): RoomDisplayEntry[] {
  const resolvedRoomContext = roomContext;
  const resolvedFallbackPrefix = fallbackPrefix || getRoomTypeLabel(roomContext);
  const fallbackTypeHint = resolveRoomTypeHint(resolvedFallbackPrefix);
  const seen = new Set<string>();
  const cleanedLabels = roomLabels
    .map((label, sourceIndex) => ({ roomName: asText(label), sourceIndex }))
    .filter((entry) => Boolean(entry.roomName))
    .filter((entry) => {
      const label = entry.roomName;
      const key = label.toLowerCase();
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  const sortedLabels = [...cleanedLabels].sort(
    (a, b) => compareRoomLabels(a.roomName, b.roomName) || a.sourceIndex - b.sourceIndex
  );
  const labelsByNumber = new Map<number, RoomDisplayEntry>();
  const unnumberedLabels: RoomDisplayEntry[] = [];

  sortedLabels.forEach((entry) => {
    const number = getRoomDisplayNumber(entry.roomName);
    if (number !== null && number > 0) {
      if (!labelsByNumber.has(number)) labelsByNumber.set(number, entry);
      return;
    }
    unnumberedLabels.push(entry);
  });

  if (!labelsByNumber.size && sortedLabels.length >= expectedRoomCount && expectedRoomCount > 0) {
    return sortedLabels;
  }

  if (!labelsByNumber.size) {
    const fallbackCount = Math.max(expectedRoomCount, sortedLabels.length, 1);
    return Array.from({ length: fallbackCount }, (_, index) => ({
      roomName:
        sortedLabels[index]?.roomName ||
        getRoomDisplayLabelFromIndex(
          sortedLabels[index]?.roomName || "",
          index,
          resolvedRoomContext,
          fallbackTypeHint
        ),
      sourceIndex: sortedLabels[index]?.sourceIndex ?? -1,
    }));
  }

  const numericRoomCount = Math.max(expectedRoomCount, ...Array.from(labelsByNumber.keys()), 0);
  if (numericRoomCount <= 0) {
    const fallbackCount = Math.max(expectedRoomCount, sortedLabels.length, 1);
    return Array.from({ length: fallbackCount }, (_, index) => ({
      roomName:
        sortedLabels[index]?.roomName ||
        getRoomDisplayLabelFromIndex(
          sortedLabels[index]?.roomName || "",
          index,
          resolvedRoomContext,
          fallbackTypeHint
        ),
      sourceIndex: sortedLabels[index]?.sourceIndex ?? -1,
    }));
  }

  const template =
    sortedLabels.find((entry) => getRoomDisplayNumber(entry.roomName) !== null)?.roomName ||
    getRoomDisplayLabelFromIndex("", 0, resolvedRoomContext, fallbackTypeHint);
  const numericEntries = Array.from({ length: numericRoomCount }, (_, index) => {
    const roomNumber = index + 1;
    const existingEntry = labelsByNumber.get(roomNumber);
    return {
      roomName:
        existingEntry?.roomName ||
        buildRoomLabelFromTemplate(template, roomNumber, resolvedRoomContext),
      sourceIndex: existingEntry?.sourceIndex ?? -1,
    };
  });

  return [
    ...numericEntries,
    ...unnumberedLabels,
  ];
}

function buildRoomSlotAssignmentPlan(
  roomSlotEntries: RoomDisplayEntry[],
  explicitAssignments: Array<AssignmentRow | null>,
  confirmedAssignments: AssignmentRow[],
  roomContext: RoomNamingContext = {},
  options?: { allowConfirmedRosterBackfill?: boolean }
): RoomSlotAssignmentPlan {
  const roomCount = roomSlotEntries.length;
  const assignments: RoomSlotAssignmentProjection[] = roomSlotEntries.map((room, index) => {
    const assignment = explicitAssignments[index] || null;
    return {
      assignment,
      isExplicit: Boolean(assignment),
      isAutoMapped: false,
    };
  });

  const explicitMappedCount = assignments.reduce((acc, item) => acc + (item.isExplicit ? 1 : 0), 0);

  if (!roomCount || confirmedAssignments.length < roomCount || !options?.allowConfirmedRosterBackfill) {
    return {
      assignments,
      explicitMappedCount,
      unmappedRoomNames: assignments
        .map((entry, index) =>
          entry.isExplicit
            ? null
            : roomSlotEntries[index]?.roomName || getRoomDisplayLabelFromIndex("", index, roomContext, resolveRoomTypeHint(fallbackPrefixFromContext(roomContext)))
        )
        .filter((name): name is string => Boolean(name)),
    };
  }

  const explicitAssignmentIds = new Set(
    assignments
      .filter((item) => item.isExplicit && item.assignment)
      .map((item) => asText(item.assignment?.id).trim())
      .filter(Boolean)
  );

  const fallbackConfirmedPool = confirmedAssignments.filter((assignment) => {
    const assignmentId = asText(assignment.id).trim();
    return !assignmentId || !explicitAssignmentIds.has(assignmentId);
  });

  let fallbackIndex = 0;

  assignments.forEach((item) => {
    if (item.isExplicit) return;
    const next = fallbackConfirmedPool[fallbackIndex++] || null;
    if (next) {
      item.assignment = next;
      item.isAutoMapped = true;
    }
  });

  return {
    assignments,
    explicitMappedCount,
    unmappedRoomNames: assignments
      .map((entry, index) =>
        entry.isExplicit
          ? null
          : roomSlotEntries[index]?.roomName || getRoomDisplayLabelFromIndex("", index, roomContext, resolveRoomTypeHint(fallbackPrefixFromContext(roomContext)))
      )
      .filter((name): name is string => Boolean(name)),
  };
}

function fallbackPrefixFromContext(roomContext: RoomNamingContext = {}) {
  return getRoomTypeLabel(roomContext);
}

function buildFullRoomSlotsForRound(
  round: RotationRound | null | undefined,
  options: {
    roomLabels?: Array<string | null | undefined>;
    metadataRoomCount?: number;
    fallbackRoomCount?: number;
    fallbackPrefix?: string;
    roomContext?: RoomNamingContext;
  } = {}
) {
  const sourceLabels = (options.roomLabels?.length ? options.roomLabels : round?.rooms || []).map(asText).filter(Boolean);
  const sourceRoomCount = Math.max(sourceLabels.length, getHighestRoomDisplayNumber(sourceLabels));
  // Round slots are the display source of truth. Imported/global room counts only fill in when no slots exist.
  const expectedRoomCount = sourceRoomCount || Math.max(options.metadataRoomCount || 0, options.fallbackRoomCount || 0);

  if (!sourceLabels.length && expectedRoomCount <= 0) return [] as RoomDisplayEntry[];
  return buildFullNumericRoomDisplayEntries(
    sourceLabels,
    expectedRoomCount,
    options.fallbackPrefix || "",
    options.roomContext || {}
  );
}

function getEmail(sp: SPRow) {
  return asText(sp.working_email) || asText(sp.email);
}

function getEmailSource(sp: SPRow) {
  if (asText(sp.working_email)) return "sps.working_email";
  if (asText(sp.email)) return "sps.email";
  return "";
}

function sortSPs(a: SPRow, b: SPRow) {
  return getFullName(a).localeCompare(getFullName(b));
}

function getCandidateSearchText(sp: SPRow) {
  return [
    getFullName(sp),
    sp.schedule_name,
    getEmail(sp),
    sp.phone,
    sp.notes,
    sp.telehealth,
    sp.pt_preferred,
    sp.other_roles,
  ]
    .map(asText)
    .join(" ")
    .toLowerCase();
}

function isActiveSp(sp: SPRow) {
  const status = asText(sp.status).toLowerCase();
  return !status || status === "active";
}

function speaksSpanish(sp: SPRow) {
  const value = sp.speaks_spanish;
  return value === true || ["yes", "true", "y"].includes(asText(value).toLowerCase());
}

function hasTelehealth(sp: SPRow) {
  return Boolean(asText(sp.telehealth));
}

function hasPtPreferred(sp: SPRow) {
  const value = asText(sp.pt_preferred).toLowerCase();
  return Boolean(value) && !["no", "n", "false"].includes(value);
}

function getAssignmentStatus(assignment: AssignmentRow): AssignmentStatus {
  const rawStatus = asText(assignment.status) as AssignmentStatus;
  if (assignmentStatuses.includes(rawStatus)) return rawStatus;
  return assignment.confirmed === true ? "confirmed" : "invited";
}

const HIRE_CONFIRMATION_SELECTION_BLOCK = "CFSP_HIRE_CONFIRMATION_SELECTION";

function getHireConfirmationSelectionDetail(assignment: AssignmentRow) {
  const notes = asText(assignment.notes);
  const pattern = new RegExp(`\\[${HIRE_CONFIRMATION_SELECTION_BLOCK}\\]([\\s\\S]*?)\\[\\/${HIRE_CONFIRMATION_SELECTION_BLOCK}\\]`);
  const match = notes.match(pattern);
  if (!match?.[1]) return null;
  try {
    const parsed = JSON.parse(match[1]) as Record<string, unknown>;
    return parsed && typeof parsed === "object" ? parsed : null;
  } catch {
    return null;
  }
}

function removeHireConfirmationSelectionDetail(notes: unknown) {
  const pattern = new RegExp(`\\[${HIRE_CONFIRMATION_SELECTION_BLOCK}\\][\\s\\S]*?\\[\\/${HIRE_CONFIRMATION_SELECTION_BLOCK}\\]`, "g");
  return asText(notes).replace(pattern, "\n").replace(/\n{3,}/g, "\n\n").trim();
}

function isHireConfirmationPendingAssignment(assignment: AssignmentRow) {
  if (assignment.confirmed === true || getAssignmentStatus(assignment) === "confirmed") return false;
  const detail = getHireConfirmationSelectionDetail(assignment);
  return asText(detail?.confirmation_status).toLowerCase() === "pending";
}

function getHireConfirmationPendingAssignmentType(assignment: AssignmentRow): "primary" | "backup" {
  const detail = getHireConfirmationSelectionDetail(assignment);
  return asText(detail?.assignment_type).toLowerCase() === "backup" ? "backup" : "primary";
}

function isAssignmentConfirmed(assignment: AssignmentRow) {
  return assignment.confirmed === true || getAssignmentStatus(assignment) === "confirmed";
}

function getCommandCenterAssignmentLabel(assignment: AssignmentRow) {
  const status = getAssignmentStatus(assignment);
  if (status === "confirmed") return "Confirmed";
  if (status === "declined" || status === "no_show") return "Declined";
  if (status === "backup") return "Backup";
  return "Contacted";
}

function getCommandCenterAssignmentTone(assignment: AssignmentRow): "confirmed" | "pending" {
  return isAssignmentConfirmed(assignment) ? "confirmed" : "pending";
}

function getEventTypeButtonStyle(type: EventDisplayType, active: boolean): React.CSSProperties {
  const palettes: Record<EventDisplayType, { background: string; border: string; color: string }> = {
    simulation: {
      background: "rgba(20, 91, 150, 0.14)",
      border: "rgba(120, 180, 255, 0.24)",
      color: "var(--cfsp-blue)",
    },
    didactic: {
      background: "rgba(245, 158, 11, 0.14)",
      border: "rgba(245, 158, 11, 0.26)",
      color: "#a16207",
    },
    skills: {
      background: "var(--cfsp-skills-soft)",
      border: "var(--cfsp-skills-border)",
      color: "var(--cfsp-skills-text)",
    },
    sp: {
      background: "rgba(20, 91, 150, 0.14)",
      border: "rgba(120, 180, 255, 0.24)",
      color: "var(--cfsp-blue)",
    },
    hifi: {
      background: "rgba(141, 121, 255, 0.14)",
      border: "rgba(141, 121, 255, 0.24)",
      color: "#b9a7ff",
    },
    training: {
      background: "var(--cfsp-warning-soft)",
      border: "rgba(243, 187, 103, 0.24)",
      color: "var(--cfsp-warning)",
    },
    virtual: {
      background: "rgba(20, 91, 150, 0.14)",
      border: "rgba(120, 180, 255, 0.24)",
      color: "var(--cfsp-blue)",
    },
  };

  const palette = palettes[type];

  return {
    borderRadius: "999px",
    padding: "7px 12px",
    fontWeight: 900,
    fontSize: "11px",
    border: `1px solid ${active ? palette.border : "var(--cfsp-border)"}`,
    background: active ? palette.background : "var(--cfsp-surface)",
    color: active ? palette.color : "var(--cfsp-text-muted)",
    minWidth: "64px",
    textAlign: "center",
  };
}

function getFilenameFromUrl(value: string) {
  const text = asText(value);
  if (!text) return "";
  try {
    const pathname = new URL(text).pathname;
    return decodeURIComponent(pathname.split("/").filter(Boolean).pop() || "");
  } catch {
    return text.split("/").filter(Boolean).pop() || text;
  }
}

function getDisplayFileStem(value: string | null | undefined) {
  return getFilenameFromUrl(asText(value)).replace(/\.[^.]+$/, "");
}

function getFileExtension(value: string) {
  const fileName = getFilenameFromUrl(value).toLowerCase();
  const dotIndex = fileName.lastIndexOf(".");
  return dotIndex >= 0 ? fileName.slice(dotIndex + 1) : "";
}

function hasDocumentStyleCaseName(value: unknown) {
  return /\.(pdf|doc|docx)$/i.test(asText(value));
}

function getMaterialPreviewKind(fileName: string, ...sources: string[]): MaterialPreviewKind {
  const extension = (
    getFileExtension(fileName) ||
    sources.map((source) => getFileExtension(source)).find(Boolean) ||
    ""
  ).toLowerCase();
  if (extension === "pdf") return "pdf";
  if (["png", "jpg", "jpeg", "gif", "webp", "svg", "bmp"].includes(extension)) return "image";
  if (["txt", "log", "json"].includes(extension)) return "text";
  if (["csv", "doc", "docx", "xls", "xlsx", "ppt", "pptx"].includes(extension)) return "unsupported";
  return "iframe";
}

function buildTrainingMaterialAssetUrls(args: {
  eventId: string;
  rawUrl: string;
  storagePath: string;
  fileName: string;
}) {
  const rawUrl = asText(args.rawUrl);
  const storagePath = asText(args.storagePath);
  const fileName = asText(args.fileName) || getFilenameFromUrl(rawUrl) || getFilenameFromUrl(storagePath) || "training-material";

  if (!storagePath || !args.eventId) {
    return {
      previewUrl: rawUrl,
      downloadUrl: rawUrl,
      openInNewTabUrl: rawUrl,
      fileName,
    };
  }

  const baseParams = new URLSearchParams({
    eventId: args.eventId,
    path: storagePath,
    filename: fileName,
  });

  return {
    previewUrl: `/api/uploads/training-material?${baseParams.toString()}&mode=preview`,
    downloadUrl: `/api/uploads/training-material?${baseParams.toString()}&mode=download`,
    openInNewTabUrl: `/api/uploads/training-material?${baseParams.toString()}&mode=preview`,
    fileName,
  };
}

function isSameOriginPreviewUrl(value: string) {
  const rawUrl = asText(value);
  if (!rawUrl || typeof window === "undefined") return false;
  try {
    const resolved = new URL(rawUrl, window.location.origin);
    return resolved.origin === window.location.origin;
  } catch {
    return false;
  }
}

function getMaterialPreviewLoadError(response?: Response | null) {
  if (response?.status === 401 || response?.status === 403 || response?.status === 404 || response?.status === 410) {
    return "File missing or access expired. Please download the file or upload it again.";
  }
  return "Could not load preview. Please download the file.";
}

function normalizeCaseRoleEntries(value: unknown, caseId: string) {
  if (!Array.isArray(value)) return [] as CaseRoleEntry[];
  return value
    .map((role, index) => {
      const record = role && typeof role === "object" ? (role as Record<string, unknown>) : {};
      const name = normalizeDisplayText(record.name ?? role);
      if (!name) return null;
      return {
        id: normalizeDisplayText(record.id) || `${caseId || "case"}-role-${index + 1}`,
        name,
      };
    })
    .filter((role): role is CaseRoleEntry => Boolean(role));
}

function hasCaseFileDocumentEvidence(value: {
  name?: string | null;
  url?: string | null;
  storagePath?: string | null;
  documentName?: string | null;
  documentUrl?: string | null;
  fileUrl?: string | null;
  hasDocument?: boolean | null;
}) {
  return Boolean(
    asText(value.url) ||
      asText(value.storagePath) ||
      asText(value.documentUrl) ||
      asText(value.fileUrl) ||
      value.hasDocument ||
      hasDocumentStyleCaseName(value.documentName) ||
      hasDocumentStyleCaseName(value.name)
  );
}

function normalizeCaseFileEntry(value: Partial<CaseFileEntry>, fallbackIndex: number): CaseFileEntry | null {
  const url = asText(value.url);
  const storagePath = asText(value.storagePath);
  const name = asText(value.name) || getFilenameFromUrl(url) || (storagePath ? getFilenameFromUrl(storagePath) : "");
  if (!url && !storagePath && !name) return null;
  const id = asText(value.id) || `${storagePath || url || name || "case"}-${fallbackIndex}`;
  const roles = normalizeCaseRoleEntries(value.roles, id);

  return {
    id,
    name: name || `Case ${fallbackIndex + 1}`,
    url,
    storagePath,
    uploadedAt: asText(value.uploadedAt),
    uploadedBy: asText(value.uploadedBy),
    encounterMinutes: asText(value.encounterMinutes),
    checklistMinutes: asText(value.checklistMinutes),
    feedbackMinutes: asText(value.feedbackMinutes),
    notes: asText(value.notes),
    roomAssignment: asText(value.roomAssignment),
    status: value.status === "inactive" ? "inactive" : "active",
    hasRoles: Boolean(value.hasRoles || roles.length),
    roles,
  };
}

function parseCaseFileEntries(value: string | null | undefined) {
  const text = asText(value);
  if (!text) return [] as CaseFileEntry[];
  try {
    const parsed = JSON.parse(text);
    if (!Array.isArray(parsed)) return [] as CaseFileEntry[];
    return parsed
      .map((entry, index) =>
        normalizeCaseFileEntry(
          {
            id: (entry as Partial<CaseFileEntry>)?.id,
            name: (entry as Partial<CaseFileEntry>)?.name,
            url: (entry as Partial<CaseFileEntry>)?.url,
            storagePath:
              (entry as Partial<CaseFileEntry>)?.storagePath ||
              (entry as { storage_path?: string })?.storage_path,
            uploadedAt:
              (entry as Partial<CaseFileEntry>)?.uploadedAt ||
              (entry as { uploaded_at?: string })?.uploaded_at,
            uploadedBy:
              (entry as Partial<CaseFileEntry>)?.uploadedBy ||
              (entry as { uploaded_by?: string })?.uploaded_by,
            encounterMinutes:
              (entry as Partial<CaseFileEntry>)?.encounterMinutes ||
              (entry as { encounter_minutes?: string })?.encounter_minutes,
            checklistMinutes:
              (entry as Partial<CaseFileEntry>)?.checklistMinutes ||
              (entry as { checklist_minutes?: string })?.checklist_minutes,
            feedbackMinutes:
              (entry as Partial<CaseFileEntry>)?.feedbackMinutes ||
              (entry as { feedback_minutes?: string })?.feedback_minutes,
            notes: (entry as Partial<CaseFileEntry>)?.notes,
            roomAssignment:
              (entry as Partial<CaseFileEntry>)?.roomAssignment ||
              (entry as { room_assignment?: string })?.room_assignment,
            status: (entry as Partial<CaseFileEntry>)?.status,
            hasRoles:
              (entry as Partial<CaseFileEntry>)?.hasRoles ||
              (entry as { has_roles?: boolean })?.has_roles,
            roles: (entry as Partial<CaseFileEntry>)?.roles,
          },
          index
        )
      )
      .filter((entry): entry is CaseFileEntry => Boolean(entry));
  } catch {
    return [] as CaseFileEntry[];
  }
}

function serializeCaseFileEntries(entries: CaseFileEntry[]) {
  return JSON.stringify(
    entries.map((entry, index) => ({
      id: entry.id || `${entry.storagePath || entry.url || entry.name || "case"}-${index}`,
      name: entry.name,
      url: entry.url,
      storagePath: entry.storagePath,
      uploadedAt: entry.uploadedAt,
      uploadedBy: entry.uploadedBy,
      encounterMinutes: asText(entry.encounterMinutes),
      checklistMinutes: asText(entry.checklistMinutes),
      feedbackMinutes: asText(entry.feedbackMinutes),
      notes: asText(entry.notes),
      roomAssignment: asText(entry.roomAssignment),
      status: entry.status === "inactive" ? "inactive" : "active",
      hasRoles: Boolean(entry.hasRoles),
      roles: normalizeCaseRoleEntries(entry.roles, entry.id),
    }))
  );
}

function mergeLegacyCaseFileEntry(
  entries: CaseFileEntry[],
  legacyEntry: CaseFileEntry | null
) {
  if (!legacyEntry) return entries;
  const existingIndex = entries.findIndex((entry) =>
    [entry.storagePath, entry.url, entry.name].some((value) =>
      value && [legacyEntry.storagePath, legacyEntry.url, legacyEntry.name].includes(value)
    )
  );
  if (existingIndex >= 0) {
    const nextEntries = [...entries];
    nextEntries[existingIndex] = { ...legacyEntry, ...nextEntries[existingIndex] };
    return nextEntries;
  }
  return [legacyEntry, ...entries];
}

function patchCaseFileEntry(entries: CaseFileEntry[], index: number, partial: Partial<CaseFileEntry>) {
  return entries.map((entry, entryIndex) =>
    entryIndex === index
      ? normalizeCaseFileEntry({ ...entry, ...partial }, entryIndex) || entry
      : entry
  );
}

function findCaseFileEntryForLabel(entries: CaseFileEntry[], label: unknown) {
  const normalizedLabel = normalizeDisplayText(label).toLowerCase();
  if (!normalizedLabel) return null;
  return (
    entries.find((entry) => normalizeDisplayText(entry.name).toLowerCase() === normalizedLabel) ||
    entries.find((entry) => normalizeDisplayText(entry.id).toLowerCase() === normalizedLabel) ||
    null
  );
}

function resolveCaseRoleLabel(caseEntry: CaseFileEntry | null, roleId?: string | null, fallbackLabel?: string | null) {
  const normalizedRoleId = normalizeDisplayText(roleId);
  if (caseEntry && normalizedRoleId) {
    const role = (caseEntry.roles || []).find((item) => item.id === normalizedRoleId);
    if (role?.name) return role.name;
  }
  return normalizeDisplayText(fallbackLabel);
}

function findAssignmentBySpDisplayName(
  assignments: AssignmentRow[],
  spsById: Map<string, SPRow>,
  spName: string
) {
  const normalizedSpName = asText(spName).toLowerCase();
  if (!normalizedSpName) return null;
  return (
    assignments.find((candidate) => {
      const candidateSp = candidate.sp_id ? spsById.get(candidate.sp_id) : null;
      return asText(getFullName(candidateSp || emptySpRow)).toLowerCase() === normalizedSpName;
    }) || null
  );
}

function getAvailabilitySpId(row: AvailabilityRow) {
  return asText(row.sp_id);
}

function getAvailabilityDate(row: AvailabilityRow) {
  return (
    asText(row.availability_date) ||
    asText(row.date) ||
    asText(row.start_date) ||
    "Date TBD"
  );
}

function normalizeDateValue(value?: string | null, fallbackYear?: number | null) {
  return normalizeLooseDateToIso(value, fallbackYear) || "";
}

function getAvailabilityStatus(row: AvailabilityRow) {
  if (typeof row.available === "boolean") {
    return row.available ? "Available" : "Unavailable";
  }

  return (
    asText(row.availability_status) ||
    asText(row.status) ||
    "Availability noted"
  );
}

function getAvailabilityState(row: AvailabilityRow) {
  if (typeof row.available === "boolean") {
    return row.available ? "available" : "unavailable";
  }
  const status = asText(row.availability_status || row.status).toLowerCase();
  if (!status) return "unknown";
  if (
    ["unavailable", "no", "false", "busy", "blocked"].includes(status) ||
    status.includes("unavailable")
  ) {
    return "unavailable";
  }
  if (["available", "yes", "true", "open"].includes(status)) return "available";
  if (status.includes("available") && !status.includes("unavailable")) return "available";
  return "unknown";
}

function getAvailabilityTime(row: AvailabilityRow) {
  const start = asText(row.start_time);
  const end = asText(row.end_time);
  if (start && end) return `${formatDisplayTime(start)} - ${formatDisplayTime(end)}`;
  return start || end ? formatDisplayTime(start || end) : "";
}

function getAvailabilityForSp(spId: string, availabilityRows: AvailabilityRow[]) {
  return availabilityRows
    .filter((row) => getAvailabilitySpId(row) === spId)
    .sort((a, b) => getAvailabilityDate(a).localeCompare(getAvailabilityDate(b)));
}

function formatAvailabilityRows(rows: AvailabilityRow[]) {
  if (!rows.length) return "No availability rows found.";

  return rows
    .slice(0, 3)
    .map((row) => {
      const time = getAvailabilityTime(row);
      const notes = asText(row.notes);
      return [
        getAvailabilityDate(row),
        getAvailabilityStatus(row),
        time,
        notes,
      ]
        .filter(Boolean)
        .join(" · ");
    })
    .join("\n");
}

function sessionMatchesAvailability(
  session: EventSessionRow,
  row: AvailabilityRow,
  fallbackYear?: number | null
) {
  const sessionDate = normalizeDateValue(session.session_date, fallbackYear);
  const availabilityDate = normalizeDateValue(getAvailabilityDate(row));
  if (!sessionDate || !availabilityDate || sessionDate !== availabilityDate) return false;

  const sessionStart = parseTimeToMinutes(session.start_time);
  const sessionEnd = parseTimeToMinutes(session.end_time);
  const availabilityStart = parseTimeToMinutes(asText(row.start_time));
  const availabilityEnd = parseTimeToMinutes(asText(row.end_time));

  if (
    sessionStart === null ||
    sessionEnd === null ||
    availabilityStart === null ||
    availabilityEnd === null
  ) {
    return true;
  }

  return availabilityStart < sessionEnd && availabilityEnd > sessionStart;
}

function getAvailabilityMatchDetails(
  eventSessions: EventSessionRow[],
  rows: AvailabilityRow[],
  fallbackYear?: number | null
): AvailabilityMatchDetails {
  if (!eventSessions.length || !rows.length) {
    return {
      status: "unknown",
      matchedSessions: 0,
      totalSessions: eventSessions.length,
      reason: "No structured availability match data",
    };
  }

  let matchedSessions = 0;
  let sawRelevantAvailability = false;
  let sawUnavailableConflict = false;

  eventSessions.forEach((session) => {
    const relevantRows = rows.filter((row) => sessionMatchesAvailability(session, row, fallbackYear));
    if (!relevantRows.length) return;

    sawRelevantAvailability = true;
    if (relevantRows.some((row) => getAvailabilityState(row) === "unavailable")) {
      sawUnavailableConflict = true;
    }
    const hasAvailableMatch = relevantRows.some(
      (row) => getAvailabilityState(row) === "available"
    );
    if (hasAvailableMatch) matchedSessions += 1;
  });

  if (matchedSessions === eventSessions.length) {
    return {
      status: "available",
      matchedSessions,
      totalSessions: eventSessions.length,
      reason: "Available for all sessions",
    };
  }

  if (matchedSessions > 0) {
    return {
      status: "partial",
      matchedSessions,
      totalSessions: eventSessions.length,
      reason: `Available for ${matchedSessions} of ${eventSessions.length} sessions`,
    };
  }

  if (sawRelevantAvailability || sawUnavailableConflict) {
    return {
      status: "none",
      matchedSessions,
      totalSessions: eventSessions.length,
      reason: "Conflict with session time",
    };
  }

  return {
    status: "unknown",
    matchedSessions,
    totalSessions: eventSessions.length,
    reason: "No matching availability rows",
  };
}

function getAvailabilityMatchRank(status: AvailabilityMatchStatus) {
  if (status === "available") return 0;
  if (status === "partial") return 1;
  if (status === "unknown") return 2;
  return 3;
}

function getSpTagLabels(sp: SPRow) {
  const tags: string[] = [];
  if (hasTelehealth(sp)) tags.push("Telehealth");
  if (hasPtPreferred(sp)) tags.push("PT preferred");
  if (speaksSpanish(sp)) tags.push("Spanish");
  return tags;
}

function formatAttendanceTimestamp(value?: string | null) {
  if (!value) return "";
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return "";
  return parsed.toLocaleTimeString([], {
    hour: "numeric",
    minute: "2-digit",
  });
}

function formatMinutesAsClockLabel(totalMinutes: number) {
  return formatDisplayTimeFromMinutes(totalMinutes);
}

function formatMinuteRange(startMinutes: number, endMinutes: number) {
  return formatDisplayMinuteRange(startMinutes, endMinutes);
}

function getSpHiringWindowStartTime(startTimeText?: string | null, leadMinutes = HIRING_WORK_WINDOW_DEFAULT_LEAD_MINUTES) {
  const startMinutes = parseTimeToMinutes(startTimeText);
  if (startMinutes === null) return "";

  const effectiveLeadMinutes = Math.max(0, Number.isFinite(leadMinutes) ? leadMinutes : HIRING_WORK_WINDOW_DEFAULT_LEAD_MINUTES);
  const windowStartMinutes = ((startMinutes - effectiveLeadMinutes) % MINUTES_PER_DAY + MINUTES_PER_DAY) % MINUTES_PER_DAY;
  return formatMinutesAsClockLabel(windowStartMinutes);
}

function formatRemainingMinutes(totalMinutes: number) {
  if (totalMinutes <= 0) return "0m";
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  if (hours > 0 && minutes > 0) return `${hours}h ${minutes}m`;
  if (hours > 0) return `${hours}h`;
  return `${minutes}m`;
}

function getLiveFlowDividerLabel(label: string) {
  const normalized = asText(label).toLowerCase();
  if (normalized.includes("lunch")) return "Lunch";
  if (normalized.includes("break")) return "Break";
  if (normalized.includes("debrief")) return "Debrief";
  if (normalized.includes("prebrief")) return "Prebrief";
  return label;
}

function getLiveFlowAnnouncementCopy(block: LiveFlowBlock) {
  if (block.note) return block.note;
  if (block.roundNumber && block.tone === "rotation") {
    return `Round ${block.roundNumber} encounter is live.`;
  }
  return `${getLiveFlowDividerLabel(block.label)} · ${formatMinuteRange(block.startMinutes, block.endMinutes)}`;
}

function isAnnouncementBlockMatch(label: string, matcher: RegExp) {
  return matcher.test(asText(label).toLowerCase());
}

function getAnnouncementCueLabel(
  cueKind: AnnouncementCueTimelineEntry["cueKind"],
  blockLabel?: string
) {
  switch (cueKind) {
    case "prebrief":
      return "Pre-brief Reminder";
    case "encounter_start":
      return "Encounter Start";
    case "checklist_start":
      return "Checklist Start";
    case "feedback_start":
      return "Feedback Start";
    case "transition":
      return "Transition / Move";
    case "lunch":
      return "Lunch / Break";
    case "break":
      return getLiveFlowDividerLabel(blockLabel || "Break");
    case "wrap_up":
      return "Wrap-up";
    default:
      return "Announcement";
  }
}

function getAnnouncementCueAudienceLabel(cueKind: AnnouncementCueTimelineEntry["cueKind"]) {
  switch (cueKind) {
    case "prebrief":
      return "All";
    case "encounter_start":
      return "Learners / SPs";
    case "checklist_start":
      return "Learners / SPs";
    case "feedback_start":
      return "Learners / SPs";
    case "transition":
      return "Learners";
    case "lunch":
    case "break":
    case "wrap_up":
      return "All";
    default:
      return "Operations";
  }
}

function getAnnouncementCueTimingLabel(
  cueKind: AnnouncementCueTimelineEntry["cueKind"],
  roundNumber: number
) {
  switch (cueKind) {
    case "prebrief":
      return `Round ${roundNumber} readiness`;
    case "encounter_start":
      return `Round ${roundNumber} launch`;
    case "checklist_start":
      return `Round ${roundNumber} post-encounter`;
    case "feedback_start":
      return `Round ${roundNumber} feedback`;
    case "transition":
      return `Round ${roundNumber} movement`;
    case "lunch":
    case "break":
      return `Round ${roundNumber} wide block`;
    case "wrap_up":
      return "End-of-day close";
    default:
      return `Round ${roundNumber}`;
  }
}

function buildDefaultAnnouncementText(
  cueKind: AnnouncementCueTimelineEntry["cueKind"],
  roundNumber: number,
  blockLabel?: string
) {
  switch (cueKind) {
    case "prebrief":
      return `Round ${roundNumber} pre-brief begins now. Please gather learners, SPs, faculty, and staff for the readiness briefing.`;
    case "encounter_start":
      return `Round ${roundNumber} encounter begins now. Learners and SPs, please start the case.`;
    case "checklist_start":
      return `Round ${roundNumber} checklist starts now. Please complete the checklist and hold room positions.`;
    case "feedback_start":
      return `Learners, please begin feedback now. You have 5 minutes.`;
    case "transition":
      return `Please transition to the next room assignment now. Staff, reset stations for the next encounter.`;
    case "lunch":
      return `Lunch begins now. Please return on time for the next rotation.`;
    case "break":
      return `${getLiveFlowDividerLabel(blockLabel || "Break")} begins now. Please be ready for the next cue.`;
    case "wrap_up":
      return `That concludes today's simulation event. Please return materials and stand by for wrap-up instructions.`;
    default:
      return "Operational announcement.";
  }
}

function parseDurationMinutes(value?: string | null) {
  const text = asText(value);
  if (!text) return 0;
  const matched = text.match(/(\d+)/);
  return matched ? Number(matched[1]) || 0 : 0;
}

function formatUploadedTimestamp(value?: string | null) {
  if (!value) return "Not uploaded";
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return value;
  return parsed.toLocaleString();
}

function getPollImportSummaryFromResponses(entries: ImportedPollResponseRecord[]): PollImportSummary {
  const matchedCount = entries.filter((entry) => Boolean(entry.matchedSpId)).length;
  return {
    parsedResponses: entries.length,
    matchedCount,
    unmatchedCount: entries.length - matchedCount,
    failedRows: 0,
    availableCount: entries.filter((entry) => entry.responseStatus === "available").length,
    maybeCount: entries.filter((entry) => entry.responseStatus === "maybe").length,
    notAvailableCount: entries.filter((entry) => entry.responseStatus === "not_available").length,
    noResponseCount: entries.filter((entry) => entry.responseStatus === "no_response").length,
    assignmentNotesUpdated: 0,
  };
}

function buildPollImportSuccessMessage(summary: PollImportSummary, uploadedAt: string) {
  const responseLabel = summary.parsedResponses === 1 ? "response" : "responses";
  const candidateLabel = summary.matchedCount === 1 ? "SP candidate" : "SP candidates";
  return `Poll sync complete - ${summary.parsedResponses} ${responseLabel} processed | ${summary.matchedCount} matched ${candidateLabel} | ${summary.availableCount} available | ${summary.notAvailableCount} unavailable/declined | uploaded ${formatUploadedTimestamp(uploadedAt)}`;
}

function formatSessionDate(value?: string | null, fallbackYear?: number | null) {
  return formatHumanDate(value, fallbackYear);
}

function formatEventDateText(value?: string | null, fallbackYear?: number | null) {
  return formatHumanDate(value, fallbackYear);
}

function parseOperationalDate(value?: string | null, fallbackYear?: number | null) {
  const text = asText(value);
  if (!text) return null;

  const numericMatch = text.match(/\b(\d{1,2})[/-](\d{1,2})(?:[/-](\d{2,4}))?\b/);
  if (numericMatch) {
    const month = Number(numericMatch[1]);
    const day = Number(numericMatch[2]);
    const yearText = numericMatch[3];
    const year = yearText
      ? Number(yearText.length === 2 ? `20${yearText}` : yearText)
      : fallbackYear || new Date().getFullYear();

    if (Number.isFinite(month) && Number.isFinite(day) && Number.isFinite(year)) {
      return new Date(year, month - 1, day);
    }
  }

  const hasExplicitYear = /\b\d{4}\b/.test(text);
  const candidates = [
    text,
    !hasExplicitYear && fallbackYear ? `${text} ${fallbackYear}` : "",
  ].filter(Boolean);

  for (const candidate of candidates) {
    const parsed = new Date(candidate);
    if (!Number.isNaN(parsed.getTime())) {
      return new Date(parsed.getFullYear(), parsed.getMonth(), parsed.getDate());
    }
  }

  return null;
}

function isMeaningfulDateText(value: unknown) {
  const normalized = asText(value).toLowerCase();
  if (!normalized) return false;
  if (["tbd", "to be determined", "none", "unknown", "n/a", "na"].includes(normalized)) return false;
  return true;
}

function resolveDateFromRelatedTrainingEvent(node: RelatedOperationalEventNode | null | undefined) {
  if (!node) return "";
  const directDate = asText(
    node.trainingMetadata?.preferred_training_date ||
      node.trainingMetadata?.training_date ||
      node.trainingMetadata?.imported_training_date ||
      node.date_text
  );
  return isMeaningfulDateText(directDate) ? directDate : "";
}

function resolvePrimaryTrainingDateText(metadata: TrainingEventMetadata) {
  const prioritizedDates = [
    asText(metadata.preferred_training_date),
    asText(metadata.training_date),
    asText(metadata.imported_training_date),
  ];
  return prioritizedDates.find((dateText) => isMeaningfulDateText(dateText)) || "";
}

function resolveTrainingDateText(args: {
  primaryTrainingMetadata: TrainingEventMetadata;
  relatedTrainingOperationalEvents: RelatedOperationalEventNode[];
  noteDateText?: string | null | undefined;
  fallbackDateSources?: string[];
}) {
  const exactMatchDateNode = args.relatedTrainingOperationalEvents.find(
    (node) =>
      node.kind === "training" &&
      (node.exact_course_match === true || asText(node.match_confidence).toLowerCase() === "exact_course") &&
      isMeaningfulDateText(resolveDateFromRelatedTrainingEvent(node))
  );

  const exactMatchDateText = resolveDateFromRelatedTrainingEvent(exactMatchDateNode);
  const primaryDateText = resolvePrimaryTrainingDateText(args.primaryTrainingMetadata);
  const noteDateText = asText(args.noteDateText);
  const fallbackDateText =
    args.fallbackDateSources?.find((source) => isMeaningfulDateText(source)) || "";

  return (
    (
      isMeaningfulDateText(primaryDateText)
        ? primaryDateText
        : isMeaningfulDateText(exactMatchDateText)
          ? exactMatchDateText
          : isMeaningfulDateText(noteDateText)
            ? noteDateText
            : isMeaningfulDateText(fallbackDateText)
              ? fallbackDateText
            : ""
    ) || ""
  );
}

function normalizeExternalHref(value?: string | null) {
  const text = asText(value);
  if (!text) return "";
  if (/^(https?:|mailto:|tel:)/i.test(text)) return text;
  if (/^[\w.-]+\.[a-z]{2,}([/:?#].*)?$/i.test(text)) return `https://${text}`;
  return text;
}

function getDateOnly(value: Date) {
  return new Date(value.getFullYear(), value.getMonth(), value.getDate());
}

function getDateDeltaDays(date: Date) {
  const today = getDateOnly(getTodayDate());
  return Math.round((getDateOnly(date).getTime() - today.getTime()) / 86400000);
}

function formatOperationalDate(date: Date | null, fallback?: string | null) {
  if (!date) return asText(fallback) || "Date TBD";
  return date.toLocaleDateString([], {
    month: "long",
    day: "numeric",
    year: "numeric",
  });
}

function getOperationalCountdownLabel(
  date: Date | null,
  labels: {
    today: string;
    tomorrow: string;
    future: (days: number) => string;
    yesterday: string;
    past: string;
    missing: string;
  }
) {
  if (!date) return labels.missing;
  const diffDays = getDateDeltaDays(date);

  if (diffDays < -1) return labels.past;
  if (diffDays === -1) return labels.yesterday;
  if (diffDays === 0) return labels.today;
  if (diffDays === 1) return labels.tomorrow;
  return labels.future(diffDays);
}

function getTimeWindowEndpoint(value?: string | null, endpoint: "start" | "end" = "start") {
  const text = asText(value);
  if (!text) return "";
  const normalized = text.replace(/[–—]/g, "-");
  const parts = normalized
    .split(/\s+(?:to|until)\s+|\s*-\s*/i)
    .map((part) => part.trim())
    .filter(Boolean);

  if (parts.length > 1) return endpoint === "end" ? parts[parts.length - 1] : parts[0];
  return endpoint === "end" ? "" : text;
}

function buildLocalDateTimeFromDateAndTime(
  dateText?: string | null,
  timeText?: string | null,
  fallbackYear?: number | null
) {
  const startMinutes = parseTimeToMinutes(getTimeWindowEndpoint(timeText, "start"));
  if (startMinutes === null) return null;

  const normalizedDate = normalizeLooseDateToIso(dateText, fallbackYear);
  let date = normalizedDate ? new Date(`${normalizedDate}T00:00:00`) : null;
  if (!date || Number.isNaN(date.getTime())) {
    date = parseOperationalDate(dateText, fallbackYear);
  }
  if (!date || Number.isNaN(date.getTime())) return null;

  return new Date(
    date.getFullYear(),
    date.getMonth(),
    date.getDate(),
    Math.floor(startMinutes / 60),
    startMinutes % 60,
    0,
    0
  );
}

function buildOperationalCountdownTarget(args: {
  dateText?: string | null;
  startTimeText?: string | null;
  endTimeText?: string | null;
  fallbackYear?: number | null;
}) {
  const start = buildLocalDateTimeFromDateAndTime(args.dateText, args.startTimeText, args.fallbackYear);
  if (!start) return null;

  const explicitEndText = asText(args.endTimeText) || getTimeWindowEndpoint(args.startTimeText, "end");
  const parsedEndMinutes = parseTimeToMinutes(explicitEndText);
  let end: Date | null = null;
  if (parsedEndMinutes !== null) {
    end = new Date(
      start.getFullYear(),
      start.getMonth(),
      start.getDate(),
      Math.floor(parsedEndMinutes / 60),
      parsedEndMinutes % 60,
      0,
      0
    );
    if (end.getTime() <= start.getTime()) {
      end = new Date(end.getTime() + 24 * 60 * 60 * 1000);
    }
  }

  const targetDateLabel = start.toLocaleDateString([], {
    month: "short",
    day: "numeric",
    year: "numeric",
  });
  const targetTimeLabel = `${targetDateLabel} • ${formatDisplayTime(getTimeWindowEndpoint(args.startTimeText, "start"))}${
    end ? ` - ${formatDisplayTime(args.endTimeText || explicitEndText)}` : ""
  }`;

  return { start, end, targetTimeLabel } satisfies OperationalCountdownTarget;
}

function formatCountdownDistance(milliseconds: number) {
  const totalSeconds = Math.max(0, Math.floor(milliseconds / 1000));
  const totalDays = Math.floor(totalSeconds / 86400);
  const months = Math.floor(totalDays / 30);
  const daysAfterMonths = totalDays % 30;
  const weeks = Math.floor(daysAfterMonths / 7);
  const days = daysAfterMonths % 7;
  const remainingAfterDays = totalSeconds % 86400;
  const hours = Math.floor(remainingAfterDays / 3600);
  const minutes = Math.floor((remainingAfterDays % 3600) / 60);
  const seconds = remainingAfterDays % 60;

  return `${months} month${months === 1 ? "" : "s"} • ${weeks} week${weeks === 1 ? "" : "s"} • ${days} day${days === 1 ? "" : "s"} • ${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
}

function getOperationalCountdownClock(
  target: OperationalCountdownTarget | null,
  nowMs: number | null
): OperationalCountdownClock {
  if (!target) {
    return {
      label: "Countdown unavailable — add event date and start time.",
      tone: "danger",
    };
  }
  if (nowMs === null) {
    return {
      label: "Syncing countdown...",
      tone: "muted",
    };
  }

  const startMs = target.start.getTime();
  const endMs = target.end?.getTime() ?? null;
  if (nowMs < startMs) {
    return {
      label: `Starts in ${formatCountdownDistance(startMs - nowMs)}`,
      tone: "scheduled",
    };
  }
  if (endMs && nowMs < endMs) {
    return {
      label: `Live now • Ends in ${formatCountdownDistance(endMs - nowMs)}`,
      tone: "ready",
    };
  }

  return {
    label: endMs
      ? `Ended ${formatCountdownDistance(nowMs - endMs)} ago`
      : `Started ${formatCountdownDistance(nowMs - startMs)} ago`,
    tone: "muted",
  };
}

function getTrainingCountdownLabel(trainingDate: Date | null, trainingComplete: boolean, hasTrainingInfo: boolean) {
  if (trainingComplete) return "Training completed";
  if (!trainingDate) return hasTrainingInfo ? "Training scheduled" : "Awaiting training";

  const diffDays = getDateDeltaDays(trainingDate);

  if (diffDays < -1) return "Training date passed";
  if (diffDays === -1) return "Training was yesterday";
  if (diffDays === 0) return "Training today";
  if (diffDays === 1) return "Training tomorrow";
  return `Training in ${diffDays} days`;
}

function parseIntegerNoteValue(notes: string | null | undefined, label: string) {
  const text = asText(notes);
  if (!text) return 0;
  const escapedLabel = label.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const match = text.match(new RegExp(`^${escapedLabel}\\s*:\\s*(\\d+)\\b`, "im"));
  if (!match) return 0;
  const parsed = Number(match[1]);
  if (!Number.isFinite(parsed)) return 0;
  return Math.max(0, Math.floor(parsed));
}

function parseNoteValue(notes: string | null | undefined, label: string) {
  const text = asText(notes);
  if (!text) return "";
  const escapedLabel = label.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const match = text.match(new RegExp(`^${escapedLabel}\\s*:\\s*(.+)$`, "im"));
  return match ? match[1].trim() : "";
}

function upsertNoteValue(notes: string | null | undefined, label: string, value: string) {
  const text = asText(notes);
  const escapedLabel = label.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const linePattern = new RegExp(`^${escapedLabel}\\s*:\\s*.*$`, "im");
  const nextLine = `${label}: ${value}`;

  if (linePattern.test(text)) {
    return text.replace(linePattern, nextLine);
  }

  return text ? `${text}\n${nextLine}` : nextLine;
}

function getFirstNoteValue(notes: string | null | undefined, labels: string[]) {
  for (const label of labels) {
    const value = parseNoteValue(notes, label);
    if (value) return value;
  }
  return "";
}

function isBackupRequirementYes(value: unknown) {
  const normalized = asText(value).toLowerCase();
  if (!normalized) return false;
  if (/\b(no|false|0|none|not needed|not required)\b/.test(normalized)) return false;
  return /\b(yes|true|1|required|needed)\b/.test(normalized) || /\d+/.test(normalized);
}

