function normalizeSpPollBuilderGender(value: unknown): SpPollBuilderGenderFilter {
  const text = asText(value).toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
  if (text === "male" || text === "m" || text === "man") return "male";
  if (text === "female" || text === "f" || text === "woman") return "female";
  if (text === "nonbinary" || text === "non_binary" || text === "nb" || text === "other") return "nonbinary_other";
  return "any";
}

function normalizeSpPollBuilderMode(value: unknown): SpPollBuilderMode {
  const text = asText(value).toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
  if (text === "in_person" || text === "inperson") return "in_person";
  if (text === "virtual" || text === "telehealth" || text === "remote") return "virtual";
  return "any";
}

function normalizeSpPollBuilderStatus(value: unknown): SpPollBuilderStatus {
  const text = asText(value).toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
  if (text === "poll_sent" || text === "sent") return "poll_sent";
  if (text === "poll_drafted" || text === "drafted" || text === "draft_ready") return "poll_drafted";
  return "not_started";
}

function normalizeSpPollBuilderLastAction(value: unknown): SpPollBuilderLastAction {
  const text = asText(value).toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
  if (text === "availability_poll_drafted" || text === "poll_drafted") return "availability_poll_drafted";
  if (text === "availability_poll_sent" || text === "poll_sent") return "availability_poll_sent";
  return "";
}

function normalizeMetadataBoolean(value: unknown) {
  if (value === true) return true;
  if (typeof value === "number") return value > 0;
  const text = asText(value).toLowerCase();
  return text === "true" || text === "1" || text === "yes" || text === "y";
}

function normalizeSpPollBuilderSelectedCount(value: unknown, fallback: number) {
  const parsed = Number.parseInt(asText(value), 10);
  if (Number.isFinite(parsed) && parsed >= 0) return parsed;
  return Math.max(0, fallback);
}

function getSpPollBuilderStatusLabel(status: SpPollBuilderStatus, hiringStarted: boolean) {
  if (status === "poll_sent") return "Poll sent - awaiting SP responses";
  if (status === "poll_drafted" || hiringStarted) return "Availability poll drafted";
  return "Not started";
}

function getSpPollBuilderWorkflowDetail(status: SpPollBuilderStatus, hiringStarted: boolean, selectedCount = 0) {
  if (status === "poll_sent") return "POLL SENT · AWAITING SP RESPONSES";
  if (status === "poll_drafted") return "HIRING STARTED · POLL DRAFTED";
  if (hiringStarted && selectedCount > 0) return `HIRING STARTED · ${selectedCount} SELECTED FOR POLL`;
  if (hiringStarted) return "HIRING STARTED · POLL DRAFTED";
  return "";
}

function normalizeSpPollBuilderFilters(value: unknown): SpPollBuilderFilters {
  const fallback = defaultSpPollBuilderFilters();
  if (!value || typeof value !== "object") return fallback;
  const source = value as Partial<Record<keyof SpPollBuilderFilters, unknown>>;
  return {
    activeOnly: source.activeOnly !== false,
    gender: normalizeSpPollBuilderGender(source.gender),
    raceEthnicity: asText(source.raceEthnicity),
    ageMin: asText(source.ageMin),
    ageMax: asText(source.ageMax),
    mode: normalizeSpPollBuilderMode(source.mode),
    preferredOnly: source.preferredOnly === true,
    spanishOnly: source.spanishOnly === true,
    skillsSearch: asText(source.skillsSearch),
    otherRolesSearch: asText(source.otherRolesSearch),
    limit: asText(source.limit),
  };
}

