const FACULTY_EMAIL_PLACEHOLDERS = new Set([
  "name@school.edu",
  "email@example.com",
  "faculty@example.com",
  "name@example.com",
  "user@example.com",
]);

function isValidEmailAddress(value: unknown) {
  const email = normalizeEmail(asText(value));
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function isValidFacultyEmailAddress(value: unknown) {
  const email = normalizeEmail(asText(value));
  if (!email || FACULTY_EMAIL_PLACEHOLDERS.has(email)) return false;
  if ((email.match(/@/g) || []).length !== 1) return false;
  const [, domain = ""] = email.split("@");
  if (!domain || !domain.includes(".") || domain.startsWith(".") || domain.endsWith(".")) return false;
  return isValidEmailAddress(email);
}

function extractValidFacultyEmailAddresses(value: unknown) {
  const matches = asText(value).match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi) || [];
  return Array.from(
    new Set(
      matches
        .map((item) => normalizeEmail(item))
        .filter(isValidFacultyEmailAddress)
    )
  );
}

function getSpPollBuilderMetadataBlock(notes?: string | null) {
  const text = asText(notes);
  if (!text) return "";
  const startIndex = text.indexOf(SP_POLL_BUILDER_METADATA_START);
  const endIndex = text.indexOf(SP_POLL_BUILDER_METADATA_END);
  if (startIndex === -1 || endIndex === -1 || endIndex < startIndex) return "";
  return text.slice(startIndex + SP_POLL_BUILDER_METADATA_START.length, endIndex).trim();
}

function parseSpPollBuilderMetadata(notes?: string | null): SpPollBuilderMetadata {
  const fallback = emptySpPollBuilderMetadata();
  const block = getSpPollBuilderMetadataBlock(notes);
  if (!block) return fallback;

  const rawData = block
    .split(/\r?\n/)
    .map((line) => line.match(/^data\s*:\s*(.*)$/i)?.[1] || "")
    .find(Boolean) || block;

  const candidates = [rawData];
  try {
    candidates.unshift(decodeURIComponent(rawData));
  } catch {
    // Metadata may already be plain JSON.
  }

  for (const candidate of candidates) {
    try {
      const parsed = JSON.parse(candidate) as Partial<SpPollBuilderMetadata> | null;
      if (!parsed || typeof parsed !== "object") continue;
      const selectedSpIds = normalizeStringArray(parsed.selected_sp_ids);
      const selectedEmails = normalizeStringArray(parsed.selected_emails).map((email) => normalizeEmail(email));
      const status = normalizeSpPollBuilderStatus(parsed.status);
      const draftedAt = asText(parsed.drafted_at);
      const sentAt = asText(parsed.sent_at);
      const parsedPollDetails = normalizeSpPollBuilderPollDetails(parsed.poll_details);
      const pollUrl = asText(parsed.poll_url) || parsedPollDetails.poll_url;
      const pollDetails: SpPollBuilderPollDetails = {
        ...parsedPollDetails,
        poll_url: parsedPollDetails.poll_url || pollUrl,
      };
      return {
        method: "microsoft_forms",
        status,
        hiring_process_started:
          normalizeMetadataBoolean(parsed.hiring_process_started) ||
          status === "poll_drafted" ||
          status === "poll_sent" ||
          Boolean(draftedAt || sentAt),
        poll_url: pollUrl,
        selected_sp_ids: selectedSpIds,
        selected_emails: selectedEmails,
        selected_count: normalizeSpPollBuilderSelectedCount(
          parsed.selected_count,
          Math.max(selectedSpIds.length, selectedEmails.length)
        ),
        filters: normalizeSpPollBuilderFilters(parsed.filters),
        poll_details: pollDetails,
        drafted_at: draftedAt,
        sent_at: sentAt,
        last_action_at: asText(parsed.last_action_at),
        last_action: normalizeSpPollBuilderLastAction(parsed.last_action),
        email_subject: asText(parsed.email_subject),
        last_generated_at: asText(parsed.last_generated_at),
        last_generated_by: asText(parsed.last_generated_by),
      };
    } catch {
      // Try the next candidate.
    }
  }

  return fallback;
}

function upsertSpPollBuilderMetadata(
  notes: string | null | undefined,
  partial: Partial<SpPollBuilderMetadata>
) {
  const current = parseSpPollBuilderMetadata(notes);
  const selectedSpIds = normalizeStringArray(partial.selected_sp_ids ?? current.selected_sp_ids);
  const selectedEmails = normalizeStringArray(partial.selected_emails ?? current.selected_emails).map((email) => normalizeEmail(email));
  const status = partial.status !== undefined
    ? normalizeSpPollBuilderStatus(partial.status)
    : current.status;
  const draftedAt = asText(partial.drafted_at ?? current.drafted_at);
  const sentAt = asText(partial.sent_at ?? current.sent_at);
  const hiringProcessStarted = partial.hiring_process_started !== undefined
    ? normalizeMetadataBoolean(partial.hiring_process_started)
    : current.hiring_process_started;
  const pollDetailsFromPartial = partial.poll_details !== undefined
    ? normalizeSpPollBuilderPollDetails(partial.poll_details)
    : current.poll_details;
  const pollUrl = asText(partial.poll_url ?? current.poll_url) || pollDetailsFromPartial.poll_url;
  const pollDetails: SpPollBuilderPollDetails = {
    ...pollDetailsFromPartial,
    poll_url: pollDetailsFromPartial.poll_url || pollUrl,
  };
  const next: SpPollBuilderMetadata = {
    method: "microsoft_forms",
    status,
    hiring_process_started:
      hiringProcessStarted ||
      status === "poll_drafted" ||
      status === "poll_sent" ||
      Boolean(draftedAt || sentAt),
    poll_url: pollUrl,
    selected_sp_ids: selectedSpIds,
    selected_emails: selectedEmails,
    selected_count: normalizeSpPollBuilderSelectedCount(
      partial.selected_count ?? current.selected_count,
      Math.max(selectedSpIds.length, selectedEmails.length)
    ),
    filters: normalizeSpPollBuilderFilters(partial.filters ?? current.filters),
    poll_details: pollDetails,
    drafted_at: draftedAt,
    sent_at: sentAt,
    last_action_at: asText(partial.last_action_at ?? current.last_action_at),
    last_action: partial.last_action !== undefined
      ? normalizeSpPollBuilderLastAction(partial.last_action)
      : current.last_action,
    email_subject: asText(partial.email_subject ?? current.email_subject),
    last_generated_at: asText(partial.last_generated_at ?? current.last_generated_at),
    last_generated_by: asText(partial.last_generated_by ?? current.last_generated_by),
  };

  const text = asText(notes);
  const withoutExisting = text.replace(
    new RegExp(`\\n?${SP_POLL_BUILDER_METADATA_START}[\\s\\S]*?${SP_POLL_BUILDER_METADATA_END}\\n?`, "g"),
    "\n"
  ).trim();
  const encoded = encodeURIComponent(JSON.stringify(next));
  const block = [SP_POLL_BUILDER_METADATA_START, `data: ${encoded}`, SP_POLL_BUILDER_METADATA_END].join("\n");
  return withoutExisting ? `${block}\n${withoutExisting}` : block;
}

function parseSpPollBuilderAgeNumber(value: string) {
  const parsed = Number.parseInt(asText(value), 10);
  return Number.isFinite(parsed) ? parsed : null;
}

function getPortrayalAgeRange(value: unknown) {
  const numbers = (asText(value).match(/\d{1,3}/g) || [])
    .map((item) => Number.parseInt(item, 10))
    .filter((item) => Number.isFinite(item) && item > 0 && item < 130);
  if (!numbers.length) return null;
  return {
    min: Math.min(...numbers),
    max: Math.max(...numbers),
  };
}

function portrayalAgeMatchesFilter(value: unknown, minValue: string, maxValue: string) {
  const requestedMin = parseSpPollBuilderAgeNumber(minValue);
  const requestedMax = parseSpPollBuilderAgeNumber(maxValue);
  if (requestedMin === null && requestedMax === null) return true;
  const range = getPortrayalAgeRange(value);
  if (!range) return false;
  const min = requestedMin ?? 0;
  const max = requestedMax ?? 130;
  return range.max >= min && range.min <= max;
}

function spGenderMatchesFilter(value: unknown, filter: SpPollBuilderGenderFilter) {
  if (filter === "any") return true;
  const text = asText(value).toLowerCase();
  const normalized = normalizeSpPollBuilderGender(value);
  if (filter === "nonbinary_other") {
    return normalized === "nonbinary_other" || (Boolean(text) && normalized === "any" && !/\b(male|female|man|woman)\b/.test(text));
  }
  return normalized === filter;
}

function spModeMatchesFilter(sp: SPRow, mode: SpPollBuilderMode) {
  if (mode === "any") return true;
  const text = [sp.telehealth, sp.notes, sp.other_roles].map(asText).join(" ").toLowerCase();
  if (mode === "virtual") return hasTelehealth(sp) || /\b(virtual|telehealth|remote|zoom)\b/.test(text);
  return !/\b(virtual|telehealth|remote)\s+only\b|\bonly\s+(virtual|telehealth|remote)\b/.test(text);
}

function getSpPollBuilderSearchText(sp: SPRow) {
  return [
    getFullName(sp),
    getEmail(sp),
    sp.status,
    sp.sex,
    sp.race,
    sp.portrayal_age,
    sp.telehealth,
    sp.pt_preferred,
    sp.other_roles,
    sp.notes,
  ].map(asText).join(" ").toLowerCase();
}

function emptyPollResponseMetadata(): PollResponseMetadata {
  return {
    responseStatus: "",
    responseNote: "",
    responseSubmittedAt: "",
  };
}

function parsePollResponseMetadata(notes?: string | null) {
  const metadata = emptyPollResponseMetadata();
  const text = asText(notes);
  const match = text.match(
    new RegExp(`${POLL_RESPONSE_START}\\n?([\\s\\S]*?)\\n?${POLL_RESPONSE_END}`)
  );
  if (!match) return metadata;

  match[1].split(/\r?\n/).forEach((line) => {
    const lineMatch = line.match(/^([A-Za-z]+)\s*:\s*(.*)$/);
    if (!lineMatch) return;
    const key = lineMatch[1] as keyof PollResponseMetadata;
    if (!POLL_RESPONSE_KEYS.includes(key)) return;
    metadata[key] = lineMatch[2].trim();
  });

  return metadata;
}

function getPollResponseStatus(notes?: string | null): PollResponseStatus {
  const status = asText(parsePollResponseMetadata(notes).responseStatus).toLowerCase();
  if (status === "available") return "available";
  if (status === "maybe") return "maybe";
  if (status === "not_available") return "not_available";
  return "no_response";
}

function getPollResponseTimestamp(notes?: string | null) {
  return asText(parsePollResponseMetadata(notes).responseSubmittedAt);
}

function emptyLiveAttendanceMetadata(): LiveAttendanceMetadata {
  return {
    status: "",
    updatedAt: "",
    previousStatus: "",
  };
}

function parseLiveAttendanceMetadata(notes?: string | null) {
  const metadata = emptyLiveAttendanceMetadata();
  const text = asText(notes);
  const match = text.match(
    new RegExp(`${LIVE_ATTENDANCE_START}\\n?([\\s\\S]*?)\\n?${LIVE_ATTENDANCE_END}`)
  );
  if (!match) return metadata;

  match[1].split(/\r?\n/).forEach((line) => {
    const lineMatch = line.match(/^([A-Za-z]+)\s*:\s*(.*)$/);
    if (!lineMatch) return;
    const key = lineMatch[1] as keyof LiveAttendanceMetadata;
    if (!LIVE_ATTENDANCE_KEYS.includes(key)) return;
    metadata[key] = lineMatch[2].trim();
  });

  return metadata;
}

function parseLiveRoomAdjustments(value: string | null | undefined) {
  const text = asText(value);
  if (!text) return {} as LiveRoomAdjustmentsMap;
  try {
    const parsed = JSON.parse(text);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      return {} as LiveRoomAdjustmentsMap;
    }
    return Object.fromEntries(
      Object.entries(parsed).map(([key, adjustment]) => {
        const record = adjustment && typeof adjustment === "object" ? adjustment : {};
        return [
          key,
          {
            standbyAssignmentId: asText((record as LiveRoomAdjustment).standbyAssignmentId),
            restoredAssignmentId: asText((record as LiveRoomAdjustment).restoredAssignmentId),
            expanded: Boolean((record as LiveRoomAdjustment).expanded),
            extraRoomCount: Math.max(
              0,
              Math.floor(Number((record as LiveRoomAdjustment).extraRoomCount) || 0)
            ),
          } satisfies LiveRoomAdjustment,
        ];
      })
    ) as LiveRoomAdjustmentsMap;
  } catch {
    return {} as LiveRoomAdjustmentsMap;
  }
}

function getLearnerAttendanceKey(roundKey: string | null | undefined, roomName: string | null | undefined, learnerName: string) {
  return [
    asText(roundKey) || "round-tbd",
    asText(roomName).toLowerCase() || "room-tbd",
    asText(learnerName).toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "") || "learner",
  ].join(":");
}

function normalizeLearnerAttendanceStatus(value: unknown): LearnerAttendanceStatus {
  const normalized = asText(value).toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
  if (normalized === "arrived") return "arrived";
  if (normalized === "late") return "late";
  if (normalized === "absent" || normalized === "no_show" || normalized === "no_show_absent") return "absent";
  if (normalized === "in_room" || normalized === "roomed") return "in_room";
  if (normalized === "completed" || normalized === "complete") return "completed";
  return "expected";
}

function parseLearnerAttendanceMetadata(value: string | null | undefined) {
  const text = asText(value);
  if (!text) return {} as LearnerAttendanceMap;

  try {
    const parsed = JSON.parse(text);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return {} as LearnerAttendanceMap;
    return Object.fromEntries(
      Object.entries(parsed as Record<string, unknown>).flatMap(([key, rawRecord]) => {
        if (!rawRecord || typeof rawRecord !== "object") return [];
        const record = rawRecord as Record<string, unknown>;
        return [
          [
            key,
            {
              status: normalizeLearnerAttendanceStatus(record.status),
              updatedAt: asText(record.updatedAt),
              roomName: asText(record.roomName),
              roundKey: asText(record.roundKey),
              note: asText(record.note) || undefined,
            } satisfies LearnerAttendanceRecord,
          ],
        ];
      })
    ) as LearnerAttendanceMap;
  } catch {
    return {} as LearnerAttendanceMap;
  }
}

function serializeLearnerAttendanceMetadata(records: LearnerAttendanceMap) {
  const compactRecords = Object.fromEntries(
    Object.entries(records).filter(([, record]) => record.status && record.status !== "expected")
  );
  return Object.keys(compactRecords).length ? JSON.stringify(compactRecords) : "";
}

