function mergeEventFamilyTrainingMetadata(
  primary: TrainingEventMetadata,
  relatedNodes: RelatedOperationalEventNode[]
) {
  const merged = { ...primary };
  const allowedRelatedMetadata = relatedNodes
    .filter((node) => {
      if (node.isConfirmed) return true;
      const confidence = asText(node.match_confidence).toLowerCase();
      return confidence === "exact_course" || confidence === "title_family" || confidence === "source_batch";
    })
    .map((node) => node.trainingMetadata)
    .filter((metadata): metadata is TrainingEventMetadata => Boolean(metadata));

  if (!allowedRelatedMetadata.length) return merged;

  EVENT_FAMILY_TRAINING_MERGE_KEYS.forEach((key) => {
    if (hasMeaningfulTrainingValue(merged[key])) return;
    const source = allowedRelatedMetadata.find((metadata) => hasMeaningfulTrainingValue(metadata[key]));
    if (source) merged[key] = source[key];
  });

  return merged;
}

const UNASSIGNED_LEARNER_ROOM_LABEL = "No student assigned";
const LEGACY_UNASSIGNED_LEARNER_LABEL = "Learner not assigned";

type VirtualAccessMetadata = {
  training_url: string;
  event_url: string;
  training_meeting_id: string;
  training_passcode: string;
  event_meeting_id: string;
  event_passcode: string;
  updated_at: string;
  updated_by: string;
};

const EMPTY_VIRTUAL_ACCESS_METADATA = {
  training_url: "",
  event_url: "",
  training_meeting_id: "",
  training_passcode: "",
  event_meeting_id: "",
  event_passcode: "",
  updated_at: "",
  updated_by: "",
} satisfies VirtualAccessMetadata;

function parseScheduleLearnerRosterMetadata(value: unknown) {
  const text = asText(value);
  if (!text) return [] as string[];

  const candidates = [text];
  try {
    candidates.unshift(decodeURIComponent(text));
  } catch {
    // Legacy metadata may already be plain JSON or plain text.
  }

  for (const candidate of candidates) {
    try {
      const parsed = JSON.parse(candidate);
      const roster = getActualLearnerNames(parsed);
      if (roster.length) return roster;
    } catch {
      // Fall through to line/comma parsing for older hand-authored metadata.
    }
  }

  return text
    .split(/\r?\n|,/)
    .map((item) => normalizeLearnerName(item))
    .filter((item) => Boolean(item) && !isLearnerCountPlaceholderLabel(item));
}

function parseLearnerCountPlaceholder(value: unknown) {
  const text = asText(value).toLowerCase();
  if (!text) return 0;
  const countOnlyMatch = text.match(/^(\d{1,3})$/);
  if (countOnlyMatch) return Number(countOnlyMatch[1]) || 0;
  const countLabelMatch = text.match(/^(\d{1,3})\s+(?:learner|learners|student|students|participant|participants)$/);
  if (countLabelMatch) return Number(countLabelMatch[1]) || 0;
  return 0;
}

function isLearnerCountPlaceholderLabel(value: unknown) {
  return parseLearnerCountPlaceholder(value) > 0;
}

function getActualLearnerNames(values: unknown) {
  return normalizeLearnerNames(values).filter((label) => !isLearnerCountPlaceholderLabel(label));
}

function isGeneratedLearnerName(value: unknown) {
  return /^learner\s+\d+$/i.test(normalizeDisplayText(value));
}

function getImportedLearnerNames(values: unknown) {
  return getActualLearnerNames(values).filter((label) => !isGeneratedLearnerName(label));
}

function getLearnerCountFallbackFromLabels(values: unknown) {
  if (!Array.isArray(values)) return 0;
  return values.reduce((highest, value) => Math.max(highest, parseLearnerCountPlaceholder(value)), 0);
}

function parseVirtualAccessMetadata(raw: unknown) {
  const text = asText(raw);
  if (!text) return { ...EMPTY_VIRTUAL_ACCESS_METADATA };

  try {
    const parsed = JSON.parse(text);
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      const record = parsed as Record<string, unknown>;
      return {
        ...EMPTY_VIRTUAL_ACCESS_METADATA,
        training_url: asText(record.training_url),
        event_url: asText(record.event_url),
        training_meeting_id: asText(record.training_meeting_id),
        training_passcode: asText(record.training_passcode),
        event_meeting_id: asText(record.event_meeting_id),
        event_passcode: asText(record.event_passcode),
        updated_at: asText(record.updated_at),
        updated_by: asText(record.updated_by),
      };
    }
  } catch {
    // Keep legacy string-style virtual access values as an empty object and continue
    // with fallback behavior driven by existing flat metadata keys.
  }

  return { ...EMPTY_VIRTUAL_ACCESS_METADATA };
}

function stringifyVirtualAccessMetadata(value: Partial<VirtualAccessMetadata>) {
  return JSON.stringify({
    ...EMPTY_VIRTUAL_ACCESS_METADATA,
    ...value,
    training_url: asText(value.training_url),
    event_url: asText(value.event_url),
    training_meeting_id: asText(value.training_meeting_id),
    training_passcode: asText(value.training_passcode),
    event_meeting_id: asText(value.event_meeting_id),
    event_passcode: asText(value.event_passcode),
    updated_at: asText(value.updated_at),
    updated_by: asText(value.updated_by),
  });
}

function hasLikelyUrlLikeValue(value: unknown) {
  const text = asText(value).trim();
  if (!text) return false;
  if (/\s/.test(text)) return false;
  if (/^(https?:\/\/|mailto:|tel:)/i.test(text)) return true;
  if (/^[a-z][a-z0-9+.-]*:\/\//i.test(text)) return true;
  return /^[a-zA-Z0-9.-]+\.[a-z]{2,}(?:[/?#:].*)?$/i.test(text);
}

function getLearnerRoomAssignmentLabel(learnerLabels: string[], _learnerCountFallback = 0) {
  void _learnerCountFallback;
  const labels = getActualLearnerNames(learnerLabels);
  if (labels.length) return labels.join(", ");
  return UNASSIGNED_LEARNER_ROOM_LABEL;
}

function getScheduleViewerEmptyLearnerLabel(_snapshotLearnerPlacementLocked = false, _learnerCountFallback = 0) {
  void _snapshotLearnerPlacementLocked;
  void _learnerCountFallback;
  return UNASSIGNED_LEARNER_ROOM_LABEL;
}

function getScheduleSlotPrimarySpName(slotRecord: Record<string, unknown>) {
  return (
    asText(slotRecord.assignedSpName) ||
    asText(slotRecord.primarySpName) ||
    asText(slotRecord.spName)
  );
}

function getScheduleSlotCaseLabel(slotRecord: Record<string, unknown>) {
  return (
    asText(slotRecord.caseLabel) ||
    asText(slotRecord.caseTitle) ||
    asText(slotRecord.caseFile)
  );
}

function getScheduleSlotRoleLabel(slotRecord: Record<string, unknown>) {
  return (
    asText(slotRecord.roleLabel) ||
    asText(slotRecord.role) ||
    asText(slotRecord.portrayal)
  );
}

function parseScheduleRoomAdjustments(value: unknown) {
  const text = asText(value);
  const roundsByNumber: ParsedScheduleRoomAdjustments = new Map();
  if (!text) return roundsByNumber;

  try {
    const parsed = JSON.parse(text) as {
      rounds?: Array<{
        round?: unknown;
        slots?: Array<{
          slotIndex?: unknown;
          learnerLabels?: unknown;
          manualOverride?: unknown;
          source?: unknown;
          stationStatus?: unknown;
          isBackupStation?: unknown;
          roomName?: unknown;
          spName?: unknown;
          backupSpName?: unknown;
          caseLabel?: unknown;
          roleId?: unknown;
          roleLabel?: unknown;
          notes?: unknown;
        }>;
      }>;
    };
    if (!parsed || typeof parsed !== "object") return roundsByNumber;
    (parsed.rounds || []).forEach((roundEntry) => {
      const roundNumber = parsePositiveInteger(roundEntry?.round, 0);
      if (!roundNumber) return;
      const slots = (roundEntry.slots || [])
        .map((slotEntry) => {
          const slotRecord = slotEntry && typeof slotEntry === "object" ? (slotEntry as Record<string, unknown>) : {};
          const slotIndex = Number(slotEntry?.slotIndex);
          if (!Number.isFinite(slotIndex) || slotIndex < 0) return null;
          const learnerLabels = getActualLearnerNames(slotEntry?.learnerLabels || []);
          const manualOverride = parseBooleanValue(slotEntry?.manualOverride, false);
          const source = normalizeDisplayText(slotEntry?.source);
          const stationStatus = normalizeScheduleStationStatus(slotEntry?.stationStatus);
          const isBackupStation = parseBooleanValue(slotEntry?.isBackupStation, false);
          const roomName = normalizeDisplayText(slotEntry?.roomName);
          const spName = normalizeDisplayText(slotEntry?.spName);
          const backupSpName = normalizeDisplayText(slotEntry?.backupSpName);
          const caseLabel = normalizeDisplayText(slotEntry?.caseLabel);
          const roleId = normalizeDisplayText(slotEntry?.roleId);
          const roleLabel = normalizeDisplayText(slotEntry?.roleLabel);
          const notes = normalizeDisplayText(slotEntry?.notes);
          const hasExplicitField = [
            "learnerLabels",
            "source",
            "stationStatus",
            "isBackupStation",
            "roomName",
            "spName",
            "backupSpName",
            "caseLabel",
            "roleId",
            "roleLabel",
            "notes",
          ].some((field) => Object.prototype.hasOwnProperty.call(slotRecord, field));
          if (!learnerLabels.length && !manualOverride && !hasExplicitField) return null;
          return {
            slotIndex,
            learnerLabels,
            ...(manualOverride ? { manualOverride: true } : {}),
            ...(Object.prototype.hasOwnProperty.call(slotRecord, "source") ? { source } : {}),
            ...(Object.prototype.hasOwnProperty.call(slotRecord, "stationStatus") ? { stationStatus: stationStatus || undefined } : {}),
            ...(Object.prototype.hasOwnProperty.call(slotRecord, "isBackupStation") ? { isBackupStation } : {}),
            ...(Object.prototype.hasOwnProperty.call(slotRecord, "roomName") ? { roomName } : {}),
            ...(Object.prototype.hasOwnProperty.call(slotRecord, "spName") ? { spName } : {}),
            ...(Object.prototype.hasOwnProperty.call(slotRecord, "backupSpName") ? { backupSpName } : {}),
            ...(Object.prototype.hasOwnProperty.call(slotRecord, "caseLabel") ? { caseLabel } : {}),
            ...(Object.prototype.hasOwnProperty.call(slotRecord, "roleId") ? { roleId } : {}),
            ...(Object.prototype.hasOwnProperty.call(slotRecord, "roleLabel") ? { roleLabel } : {}),
            ...(Object.prototype.hasOwnProperty.call(slotRecord, "notes") ? { notes } : {}),
          } satisfies ScheduleRoomAdjustmentSlot;
        })
        .filter(Boolean) as ScheduleRoomAdjustmentSlot[];
      if (slots.length) roundsByNumber.set(roundNumber, slots);
    });
  } catch {
    return new Map();
  }

  return roundsByNumber;
}

function serializeScheduleRoomAdjustments(value: ParsedScheduleRoomAdjustments) {
  return JSON.stringify({
    v: 1,
    rounds: Array.from(value.entries())
      .sort((a, b) => a[0] - b[0])
      .map(([round, slots]) => ({
        round,
        slots: slots
          .slice()
          .sort((a, b) => a.slotIndex - b.slotIndex)
          .map((slot) => ({
            slotIndex: slot.slotIndex,
            learnerLabels: getActualLearnerNames(slot.learnerLabels || []),
            ...(slot.manualOverride ? { manualOverride: true } : {}),
            ...(hasScheduleRoomAdjustmentField(slot, "source") ? { source: normalizeDisplayText(slot.source) } : {}),
            ...(hasScheduleRoomAdjustmentField(slot, "stationStatus") ? { stationStatus: normalizeScheduleStationStatus(slot.stationStatus) || undefined } : {}),
            ...(hasScheduleRoomAdjustmentField(slot, "isBackupStation") ? { isBackupStation: Boolean(slot.isBackupStation) } : {}),
            ...(hasScheduleRoomAdjustmentField(slot, "roomName") ? { roomName: normalizeDisplayText(slot.roomName) } : {}),
            ...(hasScheduleRoomAdjustmentField(slot, "spName") ? { spName: normalizeDisplayText(slot.spName) } : {}),
            ...(hasScheduleRoomAdjustmentField(slot, "backupSpName") ? { backupSpName: normalizeDisplayText(slot.backupSpName) } : {}),
            ...(hasScheduleRoomAdjustmentField(slot, "caseLabel") ? { caseLabel: normalizeDisplayText(slot.caseLabel) } : {}),
            ...(hasScheduleRoomAdjustmentField(slot, "roleId") ? { roleId: normalizeDisplayText(slot.roleId) } : {}),
            ...(hasScheduleRoomAdjustmentField(slot, "roleLabel") ? { roleLabel: normalizeDisplayText(slot.roleLabel) } : {}),
            ...(hasScheduleRoomAdjustmentField(slot, "notes") ? { notes: normalizeDisplayText(slot.notes) } : {}),
          })),
      }))
      .filter((entry) =>
        entry.slots.some((slot) =>
          slot.learnerLabels.length ||
          slot.manualOverride ||
          hasScheduleRoomAdjustmentField(slot, "source") ||
          hasScheduleRoomAdjustmentField(slot, "stationStatus") ||
          hasScheduleRoomAdjustmentField(slot, "isBackupStation") ||
          hasScheduleRoomAdjustmentField(slot, "roomName") ||
          hasScheduleRoomAdjustmentField(slot, "spName") ||
          hasScheduleRoomAdjustmentField(slot, "backupSpName") ||
          hasScheduleRoomAdjustmentField(slot, "caseLabel") ||
          hasScheduleRoomAdjustmentField(slot, "roleId") ||
          hasScheduleRoomAdjustmentField(slot, "roleLabel") ||
          hasScheduleRoomAdjustmentField(slot, "notes")
        )
      ),
  });
}

function normalizeScheduleStationStatus(value: unknown): ScheduleStationStatus | "" {
  const normalized = normalizeDisplayText(value).toLowerCase();
  if (normalized === "active") return "active";
  if (normalized === "backup" || normalized === "standby") return "backup";
  if (normalized === "inactive" || normalized === "empty") return "inactive";
  return "";
}

function hasScheduleRoomAdjustmentField(
  slot: Partial<ScheduleRoomAdjustmentSlot> | null | undefined,
  field: keyof ScheduleRoomAdjustmentSlot
) {
  return Boolean(slot) && Object.prototype.hasOwnProperty.call(slot, field);
}

function isConfirmedScheduleRoomAdjustment(slot: Partial<ScheduleRoomAdjustmentSlot> | null | undefined) {
  return normalizeDisplayText(slot?.source).toLowerCase() === CONFIRMED_SCHEDULE_OVERRIDE_SOURCE;
}

function normalizeScheduleCaseIdentity(value: unknown) {
  return normalizeDisplayText(value).toLowerCase();
}

function buildActiveScheduleCaseIdentitySet(caseLabels: string[]) {
  return new Set(
    caseLabels
      .map((label) => normalizeScheduleCaseIdentity(label))
      .filter(Boolean)
  );
}

function isGeneratedCasePlaceholderLabel(value: unknown) {
  return /^case\s+\d+$/i.test(normalizeDisplayText(value));
}

function shouldStripSavedSlotCaseLabel(value: unknown, activeCaseIdentities: Set<string>) {
  const normalized = normalizeScheduleCaseIdentity(value);
  if (!normalized || !activeCaseIdentities.size) return false;
  return isGeneratedCasePlaceholderLabel(value) && !activeCaseIdentities.has(normalized);
}

function sanitizeSavedScheduleRoomSlotForRender(
  slot: ScheduleBuilderPreviewResolvedRoomSlot,
  adjustment: ScheduleRoomAdjustmentSlot | null | undefined,
  activeCaseIdentities: Set<string>
) {
  // IMPORTANT REGRESSION GUARD:
  // Schedule room cards must render from authoritative saved room slot objects. Do not stitch together
  // room, learner, SP, case, and role data from separate arrays by index. Saved builder/completed
  // schedule slots are the unit of truth. Room Operations must not erase saved SP/case/status fields
  // just because stale, unconfirmed room adjustment metadata happens to contain the same values.
  const next = { ...slot };
  void adjustment;
  if (shouldStripSavedSlotCaseLabel(next.caseLabel, activeCaseIdentities)) {
    next.caseLabel = "";
  }
  return next;
}

function sanitizeSavedScheduleRoomSlotsForRender(
  slots: ScheduleBuilderPreviewResolvedRoomSlot[],
  roundAdjustments: ScheduleRoomAdjustmentSlot[],
  activeCaseLabels: string[]
) {
  const activeCaseIdentities = buildActiveScheduleCaseIdentitySet(activeCaseLabels);
  return slots.map((slot, slotIndex) => {
    const adjustment = roundAdjustments.find((entry) => entry.slotIndex === slotIndex) || null;
    return sanitizeSavedScheduleRoomSlotForRender(slot, adjustment, activeCaseIdentities);
  });
}

function sanitizeScheduleBuilderPreviewResolvedRounds(
  rounds: ScheduleBuilderPreviewResolvedRound[],
  adjustments: ParsedScheduleRoomAdjustments,
  activeCaseLabels: string[]
) {
  return rounds.map((round, roundIndex) => {
    const roundNumber = Number(round.round) || roundIndex + 1;
    const roundAdjustments = adjustments.get(roundNumber) || [];
    if (!round.roomSlots.length && !roundAdjustments.length) return round;
    return {
      ...round,
      roomSlots: sanitizeSavedScheduleRoomSlotsForRender(round.roomSlots, roundAdjustments, activeCaseLabels),
    };
  });
}

function sanitizeScheduleBuilderPreviewDraftSlots(
  snapshot: ScheduleBuilderPreviewDraft,
  adjustments: ParsedScheduleRoomAdjustments,
  activeCaseLabels: string[]
) {
  return {
    ...snapshot,
    resolvedRounds: sanitizeScheduleBuilderPreviewResolvedRounds(
      snapshot.resolvedRounds || [],
      adjustments,
      activeCaseLabels
    ),
  } satisfies ScheduleBuilderPreviewDraft;
}

function sanitizeCompletedScheduleRepairAdjustments(
  adjustments: ParsedScheduleRoomAdjustments,
  options?: { maxRounds?: number; maxSlotsPerRound?: number }
) {
  const maxRounds = Math.max(1, options?.maxRounds || KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROUND_COUNT);
  const maxSlotsPerRound = Math.max(1, options?.maxSlotsPerRound || KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_COUNT);
  const next = new Map<number, ScheduleRoomAdjustmentSlot[]>();

  adjustments.forEach((slots, rawRoundNumber) => {
    const roundNumber = Math.max(1, Number(rawRoundNumber) || 0);
    if (!roundNumber || roundNumber > maxRounds) return;

    const sanitizedSlots = slots
      .filter((slot) => Number.isFinite(slot.slotIndex) && slot.slotIndex >= 0 && slot.slotIndex < maxSlotsPerRound)
      .map((slot) => {
        const sanitized: ScheduleRoomAdjustmentSlot = {
          slotIndex: slot.slotIndex,
          learnerLabels: [],
        };

        if (slot.manualOverride) sanitized.manualOverride = true;
        if (hasScheduleRoomAdjustmentField(slot, "source")) sanitized.source = normalizeDisplayText(slot.source);
        if (hasScheduleRoomAdjustmentField(slot, "stationStatus")) {
          sanitized.stationStatus = normalizeScheduleStationStatus(slot.stationStatus) || undefined;
        }
        if (hasScheduleRoomAdjustmentField(slot, "isBackupStation")) {
          sanitized.isBackupStation = Boolean(slot.isBackupStation);
        }
        if (hasScheduleRoomAdjustmentField(slot, "notes")) {
          sanitized.notes = normalizeDisplayText(slot.notes);
        }

        if (isConfirmedScheduleRoomAdjustment(slot)) {
          if (hasScheduleRoomAdjustmentField(slot, "roomName")) sanitized.roomName = normalizeDisplayText(slot.roomName);
          if (hasScheduleRoomAdjustmentField(slot, "spName")) sanitized.spName = normalizeDisplayText(slot.spName);
          if (hasScheduleRoomAdjustmentField(slot, "backupSpName")) sanitized.backupSpName = normalizeDisplayText(slot.backupSpName);
          if (hasScheduleRoomAdjustmentField(slot, "caseLabel")) sanitized.caseLabel = normalizeDisplayText(slot.caseLabel);
          if (hasScheduleRoomAdjustmentField(slot, "roleId")) sanitized.roleId = normalizeDisplayText(slot.roleId);
          if (hasScheduleRoomAdjustmentField(slot, "roleLabel")) sanitized.roleLabel = normalizeDisplayText(slot.roleLabel);
        }

        return sanitized;
      })
      .filter((slot) =>
        slot.manualOverride ||
        hasScheduleRoomAdjustmentField(slot, "source") ||
        hasScheduleRoomAdjustmentField(slot, "stationStatus") ||
        hasScheduleRoomAdjustmentField(slot, "isBackupStation") ||
        hasScheduleRoomAdjustmentField(slot, "roomName") ||
        hasScheduleRoomAdjustmentField(slot, "spName") ||
        hasScheduleRoomAdjustmentField(slot, "backupSpName") ||
        hasScheduleRoomAdjustmentField(slot, "caseLabel") ||
        hasScheduleRoomAdjustmentField(slot, "roleId") ||
        hasScheduleRoomAdjustmentField(slot, "roleLabel") ||
        hasScheduleRoomAdjustmentField(slot, "notes")
      );

    if (sanitizedSlots.length) next.set(roundNumber, sanitizedSlots);
  });

  return next;
}

function upsertScheduleRoomAdjustmentSlot(
  adjustments: ParsedScheduleRoomAdjustments,
  roundNumber: number,
  slotIndex: number,
  partial: Partial<ScheduleRoomAdjustmentSlot>
) {
  const next = new Map(adjustments);
  const currentSlots = next.get(roundNumber)?.slice() || [];
  const existing = currentSlots.find((slot) => slot.slotIndex === slotIndex) || {
    slotIndex,
    learnerLabels: [],
  };
  const hasAnyExplicitField = [
    "learnerLabels",
    "source",
    "stationStatus",
    "isBackupStation",
    "roomName",
    "spName",
    "backupSpName",
    "caseLabel",
    "roleId",
    "roleLabel",
    "notes",
  ].some((field) => hasScheduleRoomAdjustmentField(partial, field as keyof ScheduleRoomAdjustmentSlot));
  const merged: ScheduleRoomAdjustmentSlot = {
    ...existing,
    ...partial,
    slotIndex,
    manualOverride:
      partial.manualOverride !== undefined
        ? Boolean(partial.manualOverride)
        : hasAnyExplicitField
        ? true
        : Boolean(existing.manualOverride),
    learnerLabels:
      partial.learnerLabels !== undefined
        ? getActualLearnerNames(partial.learnerLabels)
        : getActualLearnerNames(existing.learnerLabels || []),
  };
  const filtered = currentSlots.filter((slot) => slot.slotIndex !== slotIndex);
  if (
    merged.learnerLabels.length ||
    merged.manualOverride ||
    asText(merged.roomName) ||
    asText(merged.source) ||
    asText(merged.stationStatus) ||
    Boolean(merged.isBackupStation) ||
    asText(merged.spName) ||
    asText(merged.backupSpName) ||
    asText(merged.caseLabel) ||
    asText(merged.roleId) ||
    asText(merged.roleLabel) ||
    asText(merged.notes)
  ) {
    filtered.push(merged);
  }
  if (filtered.length) next.set(roundNumber, filtered);
  else next.delete(roundNumber);
  return next;
}

function isAssignedLearnerRoomLabel(label: unknown) {
  const text = asText(label);
  if (!text) return false;
  const normalized = text.toLowerCase();
  return (
    !isLearnerCountPlaceholderLabel(text) &&
    normalized !== LEGACY_UNASSIGNED_LEARNER_LABEL.toLowerCase() &&
    normalized !== UNASSIGNED_LEARNER_ROOM_LABEL.toLowerCase() &&
    normalized !== "overflow / standby"
  );
}

function getResolvedRoundLearnerLabels(args: {
  learnerRoster: string[];
  roomCapacity: number;
  roundIndex: number;
  slotIndex: number;
  roomSlotCount: number;
  activeCaseCount: number;
  isMultiCaseMode: boolean;
  isVirtualEvent: boolean;
}) {
  const roster = normalizeLearnerNames(args.learnerRoster);
  const safeRoomCapacity = Math.max(args.roomCapacity, 1);
  const safeRoomSlotCount = Math.max(args.roomSlotCount, 1);

  if (!roster.length) return [] as string[];

  if (args.isMultiCaseMode && args.activeCaseCount > 1) {
    const learnerGroups: Array<{ labels: string[] }> = [];
    for (let index = 0; index < roster.length; index += safeRoomCapacity) {
      learnerGroups.push({ labels: roster.slice(index, index + safeRoomCapacity) });
    }

    const activeRoomCount = safeRoomSlotCount;
    const groupCount = learnerGroups.length;
    if (!activeRoomCount || !groupCount || args.slotIndex >= activeRoomCount) return [];

    const rotationIndex = args.roundIndex % Math.max(args.activeCaseCount, groupCount, 1);
    const effectiveSlotIndex = args.isVirtualEvent ? args.slotIndex : args.slotIndex;
    let groupIndex: number | null = null;
    if (groupCount >= activeRoomCount) {
      groupIndex = (rotationIndex + effectiveSlotIndex) % groupCount;
    } else {
      const candidateGroup = args.isVirtualEvent
        ? (rotationIndex + effectiveSlotIndex) % activeRoomCount
        : ((effectiveSlotIndex - rotationIndex) % activeRoomCount + activeRoomCount) % activeRoomCount;
      groupIndex = candidateGroup < groupCount ? candidateGroup : null;
    }

    return groupIndex === null ? [] : learnerGroups[groupIndex]?.labels || [];
  }

  const firstLearnerIndex = args.roundIndex * safeRoomSlotCount * safeRoomCapacity + args.slotIndex * safeRoomCapacity;
  return Array.from({ length: safeRoomCapacity }, (_, learnerOffset) => roster[firstLearnerIndex + learnerOffset] || "")
    .filter(Boolean);
}

function buildSelectedRoundOperationalRooms(args: {
  selectedRotationRound: RotationRound | null;
  selectedResolvedRound: ScheduleBuilderPreviewResolvedRound | null;
  selectedResolvedRoundNumber: number;
  selectedRoundRoomSlotEntries: RoomDisplayEntry[];
  selectedRoundSessions: EventSessionRow[];
  activeScheduleRoomAdjustments: ParsedScheduleRoomAdjustments;
  selectedRoundCaseLabel: string;
  selectedRoundStationLabel: string;
  backupAssignmentNameSet: Set<string>;
  roomNamingContext: RoomNamingContext;
  eventLocation?: string | null;
  scheduleBuilderLearnerNames: string[];
  scheduleBuilderRoomCapacity: number;
  resolvedScheduleMatrixCaseCount: number;
  isScheduleMatrixVirtual: boolean;
  activeScheduleCaseLabels: string[];
  assignedSpNames: string[];
}) {
  const {
    selectedRotationRound,
    selectedResolvedRound,
    selectedResolvedRoundNumber,
    selectedRoundRoomSlotEntries,
    selectedRoundSessions,
    activeScheduleRoomAdjustments,
    selectedRoundCaseLabel,
    selectedRoundStationLabel,
    backupAssignmentNameSet,
    roomNamingContext,
    eventLocation,
    scheduleBuilderLearnerNames,
    scheduleBuilderRoomCapacity,
    resolvedScheduleMatrixCaseCount,
    isScheduleMatrixVirtual,
    activeScheduleCaseLabels,
    assignedSpNames,
  } = args;

  if (!selectedRotationRound) {
    return null as ResolvedScheduleTruthStation[] | null;
  }

  const roundAdjustments = activeScheduleRoomAdjustments.get(selectedResolvedRoundNumber) || [];
  const savedRoomSlots = Array.isArray(selectedResolvedRound?.roomSlots)
    ? sanitizeSavedScheduleRoomSlotsForRender(selectedResolvedRound.roomSlots, roundAdjustments, activeScheduleCaseLabels)
    : [];
  const usingSavedRoomSlots = savedRoomSlots.length > 0;
  const roundKey = asText(selectedRotationRound.key);
  const roundNumber = selectedResolvedRoundNumber;
  const start = asText(selectedResolvedRound?.startTime) || asText(selectedRotationRound.start_time);
  const end = asText(selectedResolvedRound?.endTime) || asText(selectedRotationRound.end_time);

  const sessionByRoomNumber = new Map<number, EventSessionRow>();
  const sessionByRoomName = new Map<string, EventSessionRow>();
  selectedRoundSessions.forEach((session) => {
    const roomName = asText(session.room);
    const roomNumber = getRoomDisplayNumber(roomName);
    if (roomNumber !== null && !sessionByRoomNumber.has(roomNumber)) {
      sessionByRoomNumber.set(roomNumber, session);
    }
    if (roomName) sessionByRoomName.set(roomName.toLowerCase(), session);
  });

  const fallbackEntries = selectedRoundRoomSlotEntries.length
    ? selectedRoundRoomSlotEntries
    : [{ roomName: getFallbackRoomLabel(0, roomNamingContext), sourceIndex: 0 }];
  const slotCount = Math.max(savedRoomSlots.length, fallbackEntries.length, 1);
  const sourceSlots: Array<{
    slot: ScheduleBuilderPreviewResolvedRoomSlot;
    sourceIndex: number;
    location: string;
  }> = usingSavedRoomSlots
    ? savedRoomSlots.map((slot, slotIndex) => {
        const sourceEntry = fallbackEntries[slotIndex] || null;
        const roomName = asText(slot.roomName) || asText(sourceEntry?.roomName) || getFallbackRoomLabel(slotIndex, roomNamingContext);
        const roomNumber = getRoomDisplayNumber(roomName);
        const matchedSession =
          (roomNumber !== null ? sessionByRoomNumber.get(roomNumber) : null) ||
          sessionByRoomName.get(roomName.toLowerCase()) ||
          sessionByRoomName.get(asText(sourceEntry?.roomName).toLowerCase()) ||
          null;
        return {
          slot,
          sourceIndex: sourceEntry?.sourceIndex ?? slotIndex,
          location: asText(matchedSession?.location) || asText(eventLocation),
        };
      })
    : fallbackEntries.map((entry, slotIndex) => {
        const roomNumber = getRoomDisplayNumber(entry.roomName);
        const matchedSession =
          (roomNumber !== null ? sessionByRoomNumber.get(roomNumber) : null) ||
          sessionByRoomName.get(asText(entry.roomName).toLowerCase()) ||
          null;
        return {
          slot: {
            roomName: asText(matchedSession?.room) || asText(entry.roomName) || getFallbackRoomLabel(slotIndex, roomNamingContext),
            learnerLabels: getResolvedRoundLearnerLabels({
              learnerRoster: scheduleBuilderLearnerNames,
              roomCapacity: scheduleBuilderRoomCapacity,
              roundIndex: Math.max(roundNumber - 1, 0),
              slotIndex,
              roomSlotCount: slotCount,
              activeCaseCount: resolvedScheduleMatrixCaseCount,
              isMultiCaseMode: resolvedScheduleMatrixCaseCount > 1,
              isVirtualEvent: isScheduleMatrixVirtual,
            }),
            assignedSpName: "",
            backupSpName: "",
            caseLabel: "",
            roleId: "",
            roleLabel: "",
            notes: "",
          } satisfies ScheduleBuilderPreviewResolvedRoomSlot,
          sourceIndex: entry.sourceIndex,
          location: asText(matchedSession?.location) || asText(eventLocation),
        };
      });

  // IMPORTANT REGRESSION GUARD:
  // Schedule room cards must render from authoritative saved room slot objects. Do not stitch together
  // room, learner, SP, case, and role data from separate arrays by index. Saved builder/completed
  // schedule slots are the unit of truth.
  return sourceSlots.map(({ slot, sourceIndex, location }, slotIndex) => {
    const slotOverride =
      roundAdjustments.find((adjustment: ScheduleRoomAdjustmentSlot) => adjustment.slotIndex === slotIndex) || null;
    const canApplyAssignmentOverride =
      !usingSavedRoomSlots || isConfirmedScheduleRoomAdjustment(slotOverride);
    const snapshotLearnerPlacementLocked = usingSavedRoomSlots;
    const hasLearnerLabelsOverride = canApplyAssignmentOverride && hasScheduleRoomAdjustmentField(slotOverride, "learnerLabels");
    const hasRoomNameOverride = canApplyAssignmentOverride && hasScheduleRoomAdjustmentField(slotOverride, "roomName");
    const hasSpNameOverride = canApplyAssignmentOverride && hasScheduleRoomAdjustmentField(slotOverride, "spName");
    const hasBackupSpOverride = canApplyAssignmentOverride && hasScheduleRoomAdjustmentField(slotOverride, "backupSpName");
    const hasCaseLabelOverride = canApplyAssignmentOverride && hasScheduleRoomAdjustmentField(slotOverride, "caseLabel");
    const hasRoleIdOverride = canApplyAssignmentOverride && hasScheduleRoomAdjustmentField(slotOverride, "roleId");
    const hasRoleLabelOverride = canApplyAssignmentOverride && hasScheduleRoomAdjustmentField(slotOverride, "roleLabel");
    const hasNotesOverride = canApplyAssignmentOverride && hasScheduleRoomAdjustmentField(slotOverride, "notes");
    const hasStationStatusOverride = canApplyAssignmentOverride && hasScheduleRoomAdjustmentField(slotOverride, "stationStatus");
    const hasBackupStationOverride = canApplyAssignmentOverride && hasScheduleRoomAdjustmentField(slotOverride, "isBackupStation");

    const generatedLearnerLabels = usingSavedRoomSlots
      ? []
      : getResolvedRoundLearnerLabels({
          learnerRoster: scheduleBuilderLearnerNames,
          roomCapacity: scheduleBuilderRoomCapacity,
          roundIndex: Math.max(roundNumber - 1, 0),
          slotIndex,
          roomSlotCount: slotCount,
          activeCaseCount: resolvedScheduleMatrixCaseCount,
          isMultiCaseMode: resolvedScheduleMatrixCaseCount > 1,
          isVirtualEvent: isScheduleMatrixVirtual,
        });
    const savedLearnerLabels = getActualLearnerNames(Array.isArray(slot?.learnerLabels) ? slot.learnerLabels : []);
    const overrideLearnerLabels = getActualLearnerNames(slotOverride?.learnerLabels || []);
    const savedLearnerCountFallback = getLearnerCountFallbackFromLabels(Array.isArray(slot?.learnerLabels) ? slot.learnerLabels : []);
    const overrideLearnerCountFallback = getLearnerCountFallbackFromLabels(slotOverride?.learnerLabels || []);
    // IMPORTANT REGRESSION GUARD:
    // Saved schedule viewer cells must render learner/student labels from the slot object.
    // Do not substitute seat counts, learner counts, generated fallback labels, or Room
    // Operations metadata for saved schedule learner placement.
    const shouldUseSavedSnapshotLearners = usingSavedRoomSlots && !hasLearnerLabelsOverride;
    const learnerLabels = hasLearnerLabelsOverride
      ? overrideLearnerLabels
      : shouldUseSavedSnapshotLearners
        ? savedLearnerLabels
      : savedLearnerLabels.length
        ? savedLearnerLabels
        : generatedLearnerLabels;
    const learnerCountFallback = usingSavedRoomSlots
      ? 0
      : learnerLabels.length
      ? 0
      : hasLearnerLabelsOverride
        ? (snapshotLearnerPlacementLocked ? 0 : overrideLearnerCountFallback)
        : shouldUseSavedSnapshotLearners
          ? 0
          : savedLearnerCountFallback;
    const roomName =
      (hasRoomNameOverride ? asText(slotOverride?.roomName) : asText(slot?.roomName)) ||
      getFallbackRoomLabel(slotIndex, roomNamingContext);
    const primarySpName = hasSpNameOverride
      ? asText(slotOverride?.spName)
      : asText(slot?.assignedSpName) || asText(assignedSpNames[slotIndex]);
    const backupSpName = hasBackupSpOverride
      ? asText(slotOverride?.backupSpName)
      : asText(slot?.backupSpName);
    const caseLabel =
      (hasCaseLabelOverride ? asText(slotOverride?.caseLabel) : asText(slot?.caseLabel)) ||
      (!usingSavedRoomSlots && activeScheduleCaseLabels.length
        ? activeScheduleCaseLabels[(slotIndex + Math.max(roundNumber - 1, 0)) % activeScheduleCaseLabels.length]
        : "") ||
      (usingSavedRoomSlots ? "" : asText(selectedRoundCaseLabel));
    const roleId = hasRoleIdOverride
      ? asText(slotOverride?.roleId)
      : asText(slot?.roleId);
    const roleLabel = hasRoleLabelOverride
      ? asText(slotOverride?.roleLabel)
      : asText(slot?.roleLabel);
    const notes = hasNotesOverride ? asText(slotOverride?.notes) : asText(slot?.notes);
    const stationLabel = usingSavedRoomSlots ? "" : asText(selectedRoundStationLabel);
    const encounterLabel = [stationLabel, caseLabel].filter(Boolean).join(" · ") || "Case pending";
    const savedStationStatus = normalizeScheduleStationStatus(slot?.stationStatus);
    const hasSavedScheduleSignals = Boolean(
      getActualLearnerNames(Array.isArray(slot?.learnerLabels) ? slot.learnerLabels : []).length ||
      asText(slot?.assignedSpName) ||
      asText(slot?.backupSpName) ||
      asText(slot?.caseLabel) ||
      asText(slot?.roleLabel) ||
      asText(slot?.roomName)
    );
    const savedSlotIsFlexOrEmpty = Boolean(
      slot?.roomType === "flex" ||
      (!hasSavedScheduleSignals && typeof slot?.capacity === "number" && slot.capacity <= 0)
    );
    const manualStationStatus = hasStationStatusOverride
      ? normalizeScheduleStationStatus(slotOverride?.stationStatus)
      : savedStationStatus;
    const primarySpIsBackup = Boolean(primarySpName && backupAssignmentNameSet.has(normalizeDisplayText(primarySpName).toLowerCase()));
    const explicitBackupStation = hasBackupStationOverride
      ? Boolean(slotOverride?.isBackupStation)
      : Boolean(slot?.isBackupStation || savedStationStatus === "backup");
    const inferredBackupStation = usingSavedRoomSlots
      ? explicitBackupStation
      : Boolean(backupSpName || explicitBackupStation || primarySpIsBackup);
    const stationStatus: ScheduleStationStatus =
      manualStationStatus === "inactive"
        ? "inactive"
        : manualStationStatus === "backup"
          ? "backup"
          : manualStationStatus === "active"
            ? "active"
            : savedSlotIsFlexOrEmpty
              ? "inactive"
            : inferredBackupStation
              ? "backup"
              : "active";

    return {
      key: `${roundKey}-selected-room-truth-${slotIndex}`,
      roundKey,
      roundNumber,
      start,
      end,
      roomSlotIndex: slotIndex,
      sourceIndex,
      roomName,
      roomLabel: roomName,
      location,
      learnerLabels,
      learnerCountFallback,
      snapshotLearnerPlacementLocked,
      primarySpName,
      backupSpName,
      caseLabel,
      roleId,
      roleLabel,
      notes,
      stationLabel,
      encounterLabel,
      stationStatus,
      isActiveStation: stationStatus === "active",
      isBackupStation: stationStatus === "backup",
    } satisfies ResolvedScheduleTruthStation;
  });
}

function normalizeScheduleBuilderDayBlocks(value: unknown) {
  if (!Array.isArray(value)) return [] as ScheduleBuilderPreviewDayBlock[];

  return value
    .map((item, index) => {
      const record = item && typeof item === "object" ? (item as Record<string, unknown>) : {};
      const label = asText(record.label) || asText(record.type) || "Schedule Block";
      return {
        id: asText(record.id) || `schedule-block-${index}`,
        type: asText(record.type),
        label,
        durationMinutes: asText(record.durationMinutes),
        placement: asText(record.placement) || "after_each_rotation",
        placementInterval: asText(record.placementInterval) || "2",
        specificTime: asText(record.specificTime),
        visibleTo: asText(record.visibleTo) || "both",
      };
    })
    .filter((block) => Boolean(block.label));
}

function parseBooleanValue(value: unknown, fallback = false) {
  if (typeof value === "boolean") return value;
  const text = asText(value).toLowerCase();
  if (text === "true" || text === "1" || text === "yes") return true;
  if (text === "false" || text === "0" || text === "no") return false;
  return fallback;
}

function normalizeScheduleBuilderCaseDefinitions(value: unknown) {
  if (!Array.isArray(value)) return [] as ScheduleBuilderPreviewCaseDefinition[];
  return value
    .map((entry, index) => {
      const record = entry && typeof entry === "object" ? (entry as Record<string, unknown>) : {};
      const name = asText(record.name) || asText(record.title) || `Case ${index + 1}`;
      return {
        id: asText(record.id) || `snapshot-case-${index + 1}`,
        name,
        roomAssignment: asText(record.roomAssignment || record.room_assignment),
        active: asText(record.status).toLowerCase() !== "inactive" && record.active !== false,
        documentName:
          asText(record.documentName) ||
          asText(record.document_name) ||
          asText(record.fileName) ||
          asText(record.file_name),
        documentUrl:
          asText(record.documentUrl) ||
          asText(record.document_url) ||
          asText(record.url),
        fileUrl:
          asText(record.fileUrl) ||
          asText(record.file_url),
        storagePath:
          asText(record.storagePath) ||
          asText(record.storage_path),
        hasDocument: parseBooleanValue(record.hasDocument ?? record.has_document),
      } satisfies ScheduleBuilderPreviewCaseDefinition;
    })
    .filter((entry) => Boolean(entry.name));
}

function parseScheduleBuilderPreviewDraft(value: string | null) {
  if (!value) return null;

  try {
    const parsed = JSON.parse(value) as Record<string, unknown>;
    if (!parsed || typeof parsed !== "object") return null;
    const scheduleCaseDefinitions = normalizeScheduleBuilderCaseDefinitions(parsed.scheduleCaseDefinitions);
    const activeCaseCount = scheduleCaseDefinitions.filter((caseDef) => caseDef.active).length;
    const resolvedRounds = Array.isArray(parsed.resolvedRounds)
      ? parsed.resolvedRounds
          .map((round, index) => {
            const record = round && typeof round === "object" ? (round as Record<string, unknown>) : {};
            const roomSlots = Array.isArray(record.roomSlots)
              ? record.roomSlots
                  .map((slot) => {
                    const slotRecord = slot && typeof slot === "object" ? (slot as Record<string, unknown>) : {};
	                    return {
	                      roomName: asText(slotRecord.roomName),
	                      learnerLabels: getActualLearnerNames(slotRecord.learnerLabels),
	                      assignedSpName: getScheduleSlotPrimarySpName(slotRecord),
	                      backupSpName: asText(slotRecord.backupSpName),
	                      caseLabel: getScheduleSlotCaseLabel(slotRecord),
	                      roleId: asText(slotRecord.roleId),
	                      roleLabel: getScheduleSlotRoleLabel(slotRecord),
	                      notes: asText(slotRecord.notes),
                      stationStatus: normalizeScheduleStationStatus(slotRecord.stationStatus) || undefined,
                      isBackupStation: parseBooleanValue(slotRecord.isBackupStation, false),
                      roomType: slotRecord.roomType === "flex" ? "flex" : "exam",
                      capacity: Math.max(0, parsePositiveInteger(slotRecord.capacity, 0)),
                    } satisfies ScheduleBuilderPreviewResolvedRoomSlot;
                  })
                  .filter(
                    (slot) =>
                      Boolean(
                        slot.roomName ||
                          slot.learnerLabels.length ||
                          slot.assignedSpName ||
                          slot.backupSpName ||
                          slot.caseLabel ||
                          slot.roleLabel ||
                          slot.notes ||
                          slot.stationStatus ||
                          slot.isBackupStation
                      )
                  )
              : [];
            return {
              round: Math.max(1, parsePositiveInteger(record.round, index + 1)),
              sessionDate: asText(record.sessionDate) || asText(parsed.eventDate),
              startTime: asText(record.startTime),
              endTime: asText(record.endTime),
              roomSlots,
            } satisfies ScheduleBuilderPreviewResolvedRound;
          })
          .filter((round) => round.roomSlots.length > 0 || Boolean(round.startTime || round.endTime))
      : [];
    const derivedRoundCount = resolvedRounds.length;
    const derivedRoomCount = resolvedRounds.reduce((maxCount, round) => Math.max(maxCount, round.roomSlots.length), 0);

    return {
      learnerFileName: asText(parsed.learnerFileName),
      uploadedLearners: normalizeTextArray(parsed.uploadedLearners),
      originalUploadedLearners: normalizeTextArray(parsed.originalUploadedLearners),
      roundCount: asText(parsed.roundCount),
      examRoomCount: asText(parsed.examRoomCount),
      flexRoomCount: asText(parsed.flexRoomCount),
      maxPairsPerFlexRoom: asText(parsed.maxPairsPerFlexRoom),
      startTime: asText(parsed.startTime),
      staffArrivalTime: asText(parsed.staffArrivalTime),
      spArrivalTime: asText(parsed.spArrivalTime),
      facultyArrivalTime: asText(parsed.facultyArrivalTime),
      roomSetupMinutes: asText(parsed.roomSetupMinutes),
      studentPrebriefMinutes: asText(parsed.studentPrebriefMinutes),
      spPrebriefMinutes: asText(parsed.spPrebriefMinutes),
      facultyPrebriefMinutes: asText(parsed.facultyPrebriefMinutes),
      encounterMinutes: asText(parsed.encounterMinutes),
      roomCapacity: asText(parsed.roomCapacity),
      manualRoundOverride: parseBooleanValue(parsed.manualRoundOverride, false),
      dayBlocks: normalizeScheduleBuilderDayBlocks(parsed.dayBlocks),
      snapshotVersion: parsePositiveInteger(parsed.snapshotVersion, 0) || undefined,
      scheduleStatus: asText(parsed.scheduleStatus),
      scheduleRoundCount: Math.max(derivedRoundCount, parsePositiveInteger(parsed.scheduleRoundCount, 0)),
      scheduleRoomCount: Math.max(derivedRoomCount, parsePositiveInteger(parsed.scheduleRoomCount, 0)),
      scheduleRoomCapacity: Math.max(0, parsePositiveInteger(parsed.scheduleRoomCapacity, 0)),
      scheduleLearnerRoster: normalizeTextArray(parsed.scheduleLearnerRoster),
      multipleCasesEnabled: parseBooleanValue(
        parsed.multipleCasesEnabled,
        parseBooleanValue(parsed.caseRotationRequired, false)
      ),
      scheduleCaseDefinitions,
      scheduleActiveCaseCount: Math.max(activeCaseCount, parsePositiveInteger(parsed.scheduleActiveCaseCount, 0)),
      scheduleFlexRoomCount: parsePositiveInteger(parsed.scheduleFlexRoomCount, 0),
      caseRotationRequired: parseBooleanValue(
        parsed.caseRotationRequired,
        parseBooleanValue(parsed.multipleCasesEnabled, false)
      ),
      eventDate: asText(parsed.eventDate),
      resolvedRounds,
      savedAt: asText(parsed.savedAt),
    } satisfies ScheduleBuilderPreviewDraft;
  } catch {
    return null;
  }
}

function parseCompletedScheduleBuilderSnapshot(value: unknown) {
  const text = asText(value);
  if (!text) return null;

  const candidates = [text];
  try {
    candidates.unshift(decodeURIComponent(text));
  } catch {
    // Completed snapshots are stored URL-encoded; keep plain JSON as a legacy fallback.
  }

  for (const candidate of candidates) {
    const parsed = parseScheduleBuilderPreviewDraft(candidate);
    if (parsed?.startTime) return parsed;
  }

  return null;
}

function parseCompletedScheduleBuilderDraftFromObject(value: unknown) {
  if (!value || typeof value !== "object") return null;
  return parseCompletedScheduleBuilderSnapshot(JSON.stringify(value));
}

function getCompletedScheduleCalculatedRoundCount(
  payload: Pick<CompletedScheduleMetadataPayload, "learner_count" | "room_count" | "students_per_room"> | null | undefined
) {
  const learnerCount = parsePositiveInteger(payload?.learner_count, 0);
  const roomCount = parsePositiveInteger(payload?.room_count, 0);
  const studentsPerRoom = parsePositiveInteger(payload?.students_per_room, 0);
  const learnersPerRound = roomCount * studentsPerRoom;
  if (learnerCount <= 0 || learnersPerRound <= 0) return 0;
  return Math.max(1, Math.ceil(learnerCount / learnersPerRound));
}

function getCompletedScheduleRawRoundsLength(parsed: Record<string, unknown>) {
  const directRounds = Array.isArray(parsed.rounds) ? parsed.rounds.length : 0;
  const rotationRounds = Array.isArray(parsed.rotation_rounds) ? parsed.rotation_rounds.length : 0;
  const rotationSlots = Array.isArray(parsed.rotation_slots) ? parsed.rotation_slots.length : 0;
  return Math.max(directRounds, rotationRounds, rotationSlots);
}

function normalizeCompletedScheduleSnapshotRoundCount(
  snapshot: ScheduleBuilderPreviewDraft,
  payload: Pick<CompletedScheduleMetadataPayload, "learner_count" | "room_count" | "students_per_room">
) {
  const calculatedRoundCount = getCompletedScheduleCalculatedRoundCount(payload);
  const resolvedRounds = snapshot.resolvedRounds || [];
  if (calculatedRoundCount <= 0 || resolvedRounds.length <= calculatedRoundCount) {
    return {
      snapshot,
      calculatedRoundCount,
      wasNormalized: false,
    };
  }

  return {
    snapshot: {
      ...snapshot,
      roundCount: String(calculatedRoundCount),
      scheduleRoundCount: calculatedRoundCount,
      resolvedRounds: resolvedRounds.slice(0, calculatedRoundCount),
    },
    calculatedRoundCount,
    wasNormalized: true,
  };
}

function parseCompletedScheduleMetadataPayload(raw: unknown): CompletedScheduleMetadataParseResult | null {
  const text = asText(raw);
  if (!text) return null;

  const candidates = [text];
  try {
    candidates.unshift(decodeURIComponent(text));
  } catch {
    // Completed schedule payload is usually URL-encoded.
  }

  for (const candidate of candidates) {
    try {
      const parsed = JSON.parse(candidate) as Record<string, unknown>;
      if (!parsed || typeof parsed !== "object") continue;

      const status = asText(parsed.status).toLowerCase();
      if (status !== "complete" && status !== "in_progress") continue;
      const normalizedStatus: CompletedScheduleMetadataPayload["status"] =
        status === "complete" ? "complete" : "in_progress";
      const rawRoundsLength = getCompletedScheduleRawRoundsLength(parsed);

      const snapshot =
        parsed.snapshot && typeof parsed.snapshot === "object"
          ? parseCompletedScheduleBuilderDraftFromObject(parsed.snapshot)
          : typeof parsed.snapshot === "string"
            ? parseCompletedScheduleBuilderSnapshot(parsed.snapshot)
            : null;

      if (!snapshot) {
        const legacySnapshot =
          typeof parsed.snapshot === "string" ? parseCompletedScheduleBuilderSnapshot(parsed.snapshot) : null;
        if (!legacySnapshot) continue;

        const fallbackRoomCount = parsePositiveInteger(parsed.room_count, 0);
        const fallbackLearnerCount = parsePositiveInteger(parsed.learner_count, 0);
        const fallbackRoomCapacity = parsePositiveInteger(parsed.students_per_room, 0);
        const fallbackRoundCount = parsePositiveInteger(parsed.rounds_count, 0);
        const fallbackTiming =
          parseCompletedScheduleMetadataTiming(legacySnapshot, parsed.timing);
        const basePayload = {
          status: normalizedStatus,
          source: asText(parsed.source) === "schedule_builder" ? "schedule_builder" : "schedule_builder",
          completed_at: asText(parsed.completed_at) || new Date().toISOString(),
          completed_by: asText(parsed.completed_by),
          learner_count: fallbackLearnerCount,
          room_count: fallbackRoomCount,
          students_per_room: fallbackRoomCapacity,
          rounds_count: fallbackRoundCount,
          room_names: normalizeTextArray(parsed.room_names),
          timing: fallbackTiming,
          snapshot: legacySnapshot,
        } satisfies CompletedScheduleMetadataPayload;
        const normalizedSnapshot = normalizeCompletedScheduleSnapshotRoundCount(legacySnapshot, basePayload);
        return {
          payload: {
            ...basePayload,
            rounds_count: normalizedSnapshot.calculatedRoundCount || basePayload.rounds_count,
            snapshot: normalizedSnapshot.snapshot,
          },
          snapshot: normalizedSnapshot.snapshot,
          rawSnapshot: legacySnapshot,
          rawRoundsLength,
          rawResolvedRoundsLength: legacySnapshot.resolvedRounds.length,
          calculatedRoundCount: normalizedSnapshot.calculatedRoundCount,
          wasNormalized: normalizedSnapshot.wasNormalized,
        };
      }
      const basePayload = {
        status: normalizedStatus,
        source: asText(parsed.source) === "schedule_builder" ? "schedule_builder" : "schedule_builder",
        completed_at: asText(parsed.completed_at) || new Date().toISOString(),
        completed_by: asText(parsed.completed_by),
        learner_count: parsePositiveInteger(parsed.learner_count, 0),
        room_count: parsePositiveInteger(parsed.room_count, 0),
        students_per_room: parsePositiveInteger(parsed.students_per_room, 0),
        rounds_count: parsePositiveInteger(parsed.rounds_count, 0),
        room_names: normalizeTextArray(parsed.room_names),
        timing: parseCompletedScheduleMetadataTiming(snapshot, parsed.timing),
        snapshot,
      } satisfies CompletedScheduleMetadataPayload;
      const normalizedSnapshot = normalizeCompletedScheduleSnapshotRoundCount(snapshot, basePayload);
      return {
        payload: {
          ...basePayload,
          rounds_count: normalizedSnapshot.calculatedRoundCount || basePayload.rounds_count,
          snapshot: normalizedSnapshot.snapshot,
        },
        snapshot: normalizedSnapshot.snapshot,
        rawSnapshot: snapshot,
        rawRoundsLength,
        rawResolvedRoundsLength: snapshot.resolvedRounds.length,
        calculatedRoundCount: normalizedSnapshot.calculatedRoundCount,
        wasNormalized: normalizedSnapshot.wasNormalized,
      };
    } catch {
      continue;
    }
  }

  return null;
}

function parseCompletedScheduleMetadataTiming(
  snapshot: ScheduleBuilderPreviewDraft,
  rawTiming: unknown
) {
  const snapshotWithLegacyTargetMinutes = snapshot as {
    sessionLengthMinutes?: unknown;
    scheduleLengthMinutes?: unknown;
    roundTargetMinutes?: unknown;
  };
  const timing =
    rawTiming && typeof rawTiming === "object"
      ? rawTiming as Record<string, unknown>
      : {};

  return {
    start_time: asText(timing.start_time) || asText(snapshot.startTime),
    end_time: asText(timing.end_time),
    encounter_minutes: parsePositiveInteger(timing.encounter_minutes, parsePositiveInteger(snapshot.encounterMinutes, 0)),
    feedback_minutes: parsePositiveInteger(timing.feedback_minutes, parsePositiveInteger(snapshot.feedbackMinutes, 0)),
    transition_minutes: parsePositiveInteger(timing.transition_minutes, parsePositiveInteger(snapshot.transitionMinutes, 0)),
    checklist_minutes: parsePositiveInteger(timing.checklist_minutes, parsePositiveInteger(snapshot.checklistMinutes, 0)),
    prebrief_minutes: parsePositiveInteger(timing.prebrief_minutes, parsePositiveInteger(snapshot.facultyPrebriefMinutes, 0)),
    round_target_minutes: parsePositiveInteger(
      timing.round_target_minutes,
      parsePositiveInteger(
        snapshotWithLegacyTargetMinutes.sessionLengthMinutes,
        parsePositiveInteger(
          snapshotWithLegacyTargetMinutes.scheduleLengthMinutes,
          parsePositiveInteger(snapshotWithLegacyTargetMinutes.roundTargetMinutes, 0)
        )
      )
    ),
  };
}

function parseScheduleBuilderPreviewDays(raw: string | null | undefined) {
  const text = asText(raw);
  if (!text) return new Map<number, ScheduleBuilderPreviewDraft>();

  try {
    const parsed = JSON.parse(text) as Record<string, string>;
    if (!parsed || typeof parsed !== "object") return new Map<number, ScheduleBuilderPreviewDraft>();

    const output = new Map<number, ScheduleBuilderPreviewDraft>();
    Object.entries(parsed).forEach(([rawKey, encodedSnapshot]) => {
      const day = Number.parseInt(rawKey, 10);
      if (!Number.isFinite(day) || day <= 0 || typeof encodedSnapshot !== "string") return;
      const snapshot = parseCompletedScheduleBuilderSnapshot(encodedSnapshot);
      if (snapshot) output.set(day, snapshot);
    });

    return output;
  } catch {
    return new Map<number, ScheduleBuilderPreviewDraft>();
  }
}

function serializeScheduleBuilderPreviewDays(days: Map<number, ScheduleBuilderPreviewDraft>) {
  if (!days.size) return "";
  return JSON.stringify(
    Object.fromEntries(
      Array.from(days.entries())
        .sort((a, b) => a[0] - b[0])
        .map(([day, snapshot]) => [String(day), encodeURIComponent(JSON.stringify(snapshot))])
    )
  );
}

function getScheduleBuilderPreviewMaxRoomCount(snapshot: ScheduleBuilderPreviewDraft | null | undefined) {
  if (!snapshot) return 0;
  return Math.max(
    snapshot.scheduleRoomCount || 0,
    parsePositiveInteger(snapshot.examRoomCount, 0),
    (snapshot.resolvedRounds || []).reduce((maxCount, round) => Math.max(maxCount, round.roomSlots.length), 0)
  );
}

function hasCorruptedCompletedSchedulePlaceholderText(value: string | null | undefined) {
  const text = asText(value);
  if (!text) return false;
  return (
    /"learnerLabels"\s*:\s*\[[^\]]*"\d+\s+(?:learner|learners|student|students|participant|participants)"/i.test(text) ||
    /"learnerLabels"\s*:\s*\[\s*"\d+"\s*(?:,\s*"\d+")*\s*\]/i.test(text)
  );
}

function getLearnerAttendanceSlug(name: string) {
  return asText(name).toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
}

function resolveScheduleBuilderPreviewSnapshot(
  metadata: Partial<TrainingEventMetadata> | null | undefined,
  options?: { scheduleDay?: number | null; localStorageSnapshot?: string | null }
): ScheduleBuilderSnapshotResolution {
  // IMPORTANT REGRESSION GUARD:
  // Saved builder draft and completed schedule snapshot are authoritative. Do not rebuild
  // schedule structure from fallback room/learner math when saved schedule metadata exists.
  // Failed saves must not mutate the local saved state.
  const effectiveDay = options?.scheduleDay && options.scheduleDay > 0 ? options.scheduleDay : 1;
  const serverDaySnapshots = parseScheduleBuilderPreviewDays(asText(metadata?.schedule_builder_days));
  const serverSnapshotFromDay = serverDaySnapshots.get(effectiveDay) || null;
  const inheritedDaySnapshot =
    effectiveDay > 1 && serverDaySnapshots.has(effectiveDay - 1)
      ? serverDaySnapshots.get(effectiveDay - 1) || null
      : null;
  const fallbackLegacySnapshot = parseCompletedScheduleBuilderSnapshot(metadata?.schedule_builder_snapshot);
  const completedMetadataResult = parseCompletedScheduleMetadataPayload(metadata?.completed_schedule);
  const localSnapshot = options?.localStorageSnapshot
    ? parseScheduleBuilderPreviewDraft(options.localStorageSnapshot)
    : null;
  const completedPayloadStatus = asText(completedMetadataResult?.payload?.status).toLowerCase();
  const completedPayloadSnapshot = completedMetadataResult?.snapshot || null;

  const getSnapshotRoundCount = (snapshot: ScheduleBuilderPreviewDraft | null) =>
    Math.max(
      snapshot?.resolvedRounds?.length || 0,
      snapshot?.scheduleRoundCount || 0,
      parsePositiveInteger(snapshot?.roundCount, 0)
    );

  const orderedServerSnapshots = [
    completedPayloadSnapshot,
    serverSnapshotFromDay,
    inheritedDaySnapshot,
    fallbackLegacySnapshot,
  ].filter(Boolean) as ScheduleBuilderPreviewDraft[];

  const bestCompletedServerSnapshot =
    orderedServerSnapshots.length > 0
      ? [...orderedServerSnapshots].sort(
          (a, b) => getSnapshotRoundCount(b) - getSnapshotRoundCount(a)
        )[0]
      : null;

  const serverSnapshot = serverSnapshotFromDay || inheritedDaySnapshot || fallbackLegacySnapshot;
  const completedSnapshot =
    completedPayloadStatus === "complete"
      ? completedPayloadSnapshot || bestCompletedServerSnapshot || serverSnapshot
      : asText(metadata?.schedule_status).toLowerCase() === "complete"
        ? bestCompletedServerSnapshot || serverSnapshot
        : null;

  const draft =
    completedPayloadStatus === "complete"
      ? completedPayloadSnapshot || completedSnapshot || serverSnapshot || localSnapshot
      : completedSnapshot || serverSnapshot || localSnapshot;

  return {
    effectiveDay,
    serverDaySnapshots,
    serverSnapshotFromDay,
    inheritedDaySnapshot,
    fallbackLegacySnapshot,
    serverSnapshot,
    completedSnapshot,
    completedMetadataResult,
    draft,
  };
}

function getScheduleBuilderBlockAudience(block: ScheduleBuilderPreviewDayBlock): RotationCompanionView[] {
  const visibleTo = asText(block.visibleTo).toLowerCase();
  const labelAudience = getRoundCompanionAudience(block.label);
  const audiences = new Set<RotationCompanionView>();

  if (visibleTo === "operations") {
    audiences.add("operations");
  } else if (visibleTo === "student") {
    audiences.add("student");
  } else {
    audiences.add("student");
    audiences.add("operations");
  }

  if (visibleTo !== "student" && labelAudience.includes("sp")) {
    audiences.add("sp");
  }
  if (labelAudience.includes("operations")) {
    audiences.add("operations");
  }

  return Array.from(audiences);
}

function shouldShowScheduleBuilderBlockForRound(
  block: ScheduleBuilderPreviewDayBlock,
  roundIndex: number,
  totalRounds: number,
  selectedRound: RotationRound
) {
  const placement = asText(block.placement).toLowerCase();
  if (placement === "after_each_rotation") return true;
  if (placement === "after_every_x_rotations") {
    const interval = Math.max(1, parsePositiveInteger(block.placementInterval, 2));
    return (roundIndex + 1) % interval === 0;
  }
  if (placement === "before_rotations") return roundIndex === 0;
  if (placement === "after_rotations") return roundIndex === totalRounds - 1;
  if (placement === "specific_time") {
    const specificMinutes = parseTimeToMinutes(block.specificTime);
    const startMinutes = parseTimeToMinutes(selectedRound.start_time);
    const endMinutes = parseTimeToMinutes(selectedRound.end_time);
    if (specificMinutes === null || startMinutes === null || endMinutes === null) return false;
    return specificMinutes >= startMinutes && specificMinutes <= endMinutes;
  }
  return true;
}

function formatScheduleBuilderBlockDetail(block: ScheduleBuilderPreviewDayBlock) {
  const duration = parsePositiveInteger(block.durationMinutes, 0);
  const placement = asText(block.placement).replace(/_/g, " ");
  const durationLabel = duration ? `${duration} minute${duration === 1 ? "" : "s"}` : "";
  if (block.specificTime) {
    return [formatDisplayTime(block.specificTime) || block.specificTime, durationLabel].filter(Boolean).join(" · ");
  }
  return [durationLabel, placement].filter(Boolean).join(" · ") || "Schedule block";
}

function formatLiveFlowDurationLabel(durationMinutes: number) {
  const minutes = Math.max(0, Math.round(durationMinutes));
  return `${minutes} minute${minutes === 1 ? "" : "s"}`;
}

function normalizeLiveFlowBlockLabel(label: string, type?: string) {
  const rawLabel = asText(label);
  const normalized = `${asText(type)} ${rawLabel}`.toLowerCase();

  if (/soap/.test(normalized)) return "SOAP Notes";
  if (/checklist/.test(normalized)) return "Checklist";
  if (/feedback/.test(normalized)) return "Feedback";
  if (/debrief/.test(normalized)) return "Debrief";
  if (/pre[\s-]?brief|orientation|briefing/.test(normalized)) return "Prebrief";
  if (/lunch/.test(normalized)) return "Lunch";
  if (/break/.test(normalized)) return "Break";
  if (/transition|turnover|reset/.test(normalized)) return "Transition";
  if (/encounter|rotation|case/.test(normalized)) return "Encounter";
  if (/setup/.test(normalized)) return "Setup";

  return rawLabel.replace(/\s+/g, " ") || "Event Block";
}

function getLiveFlowTone(label: string, type?: string): LiveFlowTone {
  const normalized = `${asText(type)} ${asText(label)}`.toLowerCase();
  if (/encounter|rotation|case/.test(normalized)) return "rotation";
  if (/transition|turnover|reset/.test(normalized)) return "transition";
  if (/break|lunch/.test(normalized)) return "break";
  return "support";
}

function getLiveFlowPlacementNote(block: ScheduleBuilderPreviewDayBlock) {
  const placement = asText(block.placement).toLowerCase();
  if (placement === "before_rotations") return "Before encounters";
  if (placement === "after_rotations") return "After final encounter";
  if (placement === "specific_time") return "Scheduled time";
  if (placement === "after_every_x_rotations") {
    const interval = Math.max(1, parsePositiveInteger(block.placementInterval, 2));
    return `Every ${interval} encounters`;
  }
  if (placement === "after_each_rotation") return "Between encounters";
  return "";
}

function getFallbackLiveFlowLabel(gapMinutes: number, notesText: string) {
  if (gapMinutes >= 40) return "Lunch";
  if (/soap/i.test(notesText) && gapMinutes >= 10) return "SOAP Notes";
  if (/checklist/i.test(notesText) && gapMinutes >= 5) return "Checklist";
  if (gapMinutes >= 15) return "Break";
  return "Transition";
}
function toTimeInputValue(value?: string | null) {
  const trimmed = asText(value);
  if (!trimmed) return "";
  const minutes = parseTimeToMinutes(trimmed);
  if (minutes === null) return trimmed.slice(0, 5);
  const hours = Math.floor(minutes / 60);
  const mins = minutes % 60;
  return `${String(hours).padStart(2, "0")}:${String(mins).padStart(2, "0")}`;
}

function getSessionEditorStateFromStructuredSessions(
  sessions: EventSessionRow[],
  eventDateText?: string | null
): SessionEditorState {
  const primarySession = sessions[0];
  return {
    session_date:
      asText(primarySession?.session_date) ||
      normalizeLooseDateToIso(eventDateText) ||
      "",
    start_time: toTimeInputValue(primarySession?.start_time),
    end_time: toTimeInputValue(primarySession?.end_time),
  };
}

function getEventDetailsSessionEditorState(
  sessions: EventSessionRow[],
  eventDateText: string | null | undefined,
  metadata: TrainingEventMetadata
): SessionEditorState {
  const structuredSessionFallback = getSessionEditorStateFromStructuredSessions(sessions, eventDateText);

  return {
    session_date:
      normalizeLooseDateToIso(metadata.event_session_date) ||
      structuredSessionFallback.session_date,
    start_time: toTimeInputValue(metadata.event_start_time || structuredSessionFallback.start_time),
    // Event Details owns this value. Do not derive it from selected rotation rounds,
    // imported schedule blocks, or preferred training windows after it has been saved.
    end_time: toTimeInputValue(metadata.event_end_time || structuredSessionFallback.end_time),
  };
}

