  useEffect(() => {
    if (!id || !isTrainingOnlyEvent) return;
    const primaryMatch = relatedOperationalEvents.find((node) => ["simulation", "skills", "virtual"].includes(node.kind));
    if (primaryMatch?.id && primaryMatch.id !== id) {
      router.replace(`/events/${encodeURIComponent(primaryMatch.id)}?trainingSource=${encodeURIComponent(id)}`);
      return;
    }
    router.replace(`/events?search=${encodeURIComponent(trainingOnlyRedirectSearch || asText(event?.name) || "training")}&trainingSource=${encodeURIComponent(id)}`);
  }, [event?.name, id, isTrainingOnlyEvent, relatedOperationalEvents, router, trainingOnlyRedirectSearch]);
  const hasFaculty = hasNotesLine(event?.notes, /^(Course Faculty|Faculty)\s*:/im);
  const hasTrainingScheduled = hasNotesLine(event?.notes, /^Training Date\s*:/im);
  const hasRoomsBuilt =
    sessions.some((session) => Boolean(asText(session.room) || asText(session.location))) ||
    scheduleBuilderDraftRoomCount > 0 ||
    Boolean(scheduleBuilderPreviewDraft?.resolvedRounds?.some((round) => round.roomSlots.length > 0));
  const scheduleWorkflowStatus = asText(trainingMetadata.schedule_status).toLowerCase();
  const rotationScheduleBuilt = ["built", "saved", "complete"].includes(
    asText(trainingMetadata.rotation_schedule_status).toLowerCase()
  );
  const hasCompletedScheduleSnapshot = Boolean(
    completedScheduleMetadataStatus === "complete" &&
      completedScheduleSnapshotFromMetadata
  );
  const hasSavedScheduleDraft = Boolean(
    scheduleBuilderPreviewDraft?.startTime ||
      scheduleBuilderPreviewDraft?.roundCount ||
      scheduleBuilderPreviewDraft?.resolvedRounds?.length ||
      scheduleBuilderPreviewDraft?.uploadedLearners?.length ||
      scheduleBuilderPreviewDraft?.originalUploadedLearners?.length ||
      authoritativeEventScheduleTruth.hasSavedScheduleData ||
      trainingMetadata.rotation_schedule_status
  );
  const scheduleCompleted =
    scheduleWorkflowStatus === "complete" ||
    asText(trainingMetadata.rotation_schedule_status).toLowerCase() === "complete" ||
    hasCompletedScheduleSnapshot;
  const roomOperationsScheduleOutputProtected =
    scheduleCompleted || rotationScheduleBuilt || ["built", "saved"].includes(scheduleWorkflowStatus);
  const scheduleInProgress =
    !scheduleCompleted && (scheduleWorkflowStatus === "in_progress" || hasSavedScheduleDraft || hasRoomsBuilt);
  const canRepairCompletedScheduleSnapshot =
    viewerRole === "admin" || viewerRole === "super_admin";
  const completedScheduleRepairStatus = useMemo(() => {
    const isKnownRepairEvent = id === KNOWN_COMPLETED_SCHEDULE_REPAIR_EVENT_ID;
    const snapshot = scheduleBuilderPreviewDraft;
    const caseEntries = parseCaseFileEntries(
      trainingMetadata.case_manager_cases || trainingMetadata.case_files
    ).filter((entry) => entry.status !== "inactive");
    const activeCaseStationCount = Math.max(
      KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_COUNT,
      parsePositiveInteger(trainingMetadata.case_count, 0),
      caseEntries.length
    );
    const snapshotMaxRoomCount = getScheduleBuilderPreviewMaxRoomCount(snapshot);
    const storedRoomCount = parsePositiveInteger(trainingMetadata.schedule_room_count, 0);
    const reasons: string[] = [];

    if (!snapshot?.resolvedRounds?.length) {
      reasons.push("Completed snapshot is missing resolved rounds.");
    }
    if (
      hasCorruptedCompletedSchedulePlaceholderText(trainingMetadata.schedule_builder_snapshot) ||
      hasCorruptedCompletedSchedulePlaceholderText(trainingMetadata.schedule_builder_days) ||
      hasCorruptedCompletedSchedulePlaceholderText(trainingMetadata.schedule_room_adjustments)
    ) {
      reasons.push("Saved metadata still contains numeric learner placeholder labels.");
    }
    if (snapshotMaxRoomCount > activeCaseStationCount) {
      reasons.push(
        `Completed snapshot expands to ${snapshotMaxRoomCount} rooms instead of ${activeCaseStationCount} active case stations.`
      );
    }
    if (storedRoomCount > activeCaseStationCount) {
      reasons.push(
        `Saved room count is ${storedRoomCount} instead of ${activeCaseStationCount} active case stations.`
      );
    }
    if (
      snapshot?.resolvedRounds?.[0]?.roomSlots?.length &&
      snapshot.resolvedRounds[0].roomSlots.length > KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_COUNT
    ) {
      reasons.push(
        `Round 1 snapshot saved ${snapshot.resolvedRounds[0].roomSlots.length} rooms instead of ${KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_COUNT}.`
      );
    }

    return {
      isKnownRepairEvent,
      activeCaseStationCount,
      snapshotMaxRoomCount,
      isCorrupted:
        isKnownRepairEvent &&
        scheduleCompleted &&
        reasons.length > 0,
      reasons,
      hasBackup:
        Boolean(trainingMetadata.schedule_repair_backup_snapshot) ||
        Boolean(trainingMetadata.schedule_repair_applied_at),
    };
  }, [
    id,
    scheduleBuilderPreviewDraft,
    scheduleCompleted,
    trainingMetadata.case_count,
    trainingMetadata.case_files,
    trainingMetadata.case_manager_cases,
    trainingMetadata.schedule_builder_days,
    trainingMetadata.schedule_builder_snapshot,
    trainingMetadata.schedule_repair_applied_at,
    trainingMetadata.schedule_repair_backup_snapshot,
    trainingMetadata.schedule_room_adjustments,
    trainingMetadata.schedule_room_count,
  ]);
  const buildKnownCompletedScheduleRepairSnapshot = useCallback(() => {
    const baseSnapshot = scheduleBuilderPreviewDraft;
    if (!baseSnapshot) return null;

    const overlaySlotByIndex = new Map<number, ScheduleBuilderPreviewResolvedRoomSlot>();
    (baseSnapshot.resolvedRounds || []).forEach((round) => {
      (round.roomSlots || []).forEach((slot, slotIndex) => {
        if (slotIndex >= KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_COUNT) return;
        if (!overlaySlotByIndex.has(slotIndex)) {
          overlaySlotByIndex.set(slotIndex, slot);
          return;
        }
        const existing = overlaySlotByIndex.get(slotIndex);
        const existingWeight = [
          existing?.assignedSpName,
          existing?.backupSpName,
          existing?.caseLabel,
          existing?.roleLabel,
          existing?.notes,
        ].filter(Boolean).length;
        const candidateWeight = [
          slot.assignedSpName,
          slot.backupSpName,
          slot.caseLabel,
          slot.roleLabel,
          slot.notes,
        ].filter(Boolean).length;
        if (candidateWeight > existingWeight) {
          overlaySlotByIndex.set(slotIndex, slot);
        }
      });
    });

    const now = new Date().toISOString();
    const repairedRounds = KNOWN_COMPLETED_SCHEDULE_REPAIR_LAYOUT.map((roundLearnerGroups, roundIndex) => {
      const baseRound = baseSnapshot.resolvedRounds?.[roundIndex] || null;
      return {
        round: roundIndex + 1,
        sessionDate:
          asText(baseRound?.sessionDate) ||
          asText(baseSnapshot.eventDate) ||
          sessionEditor.session_date ||
          asText(event?.date_text),
        startTime: asText(baseRound?.startTime),
        endTime: asText(baseRound?.endTime),
        roomSlots: roundLearnerGroups.map((learnerGroup, slotIndex) => {
          const baseSlot = baseRound?.roomSlots?.[slotIndex] || overlaySlotByIndex.get(slotIndex) || null;
          return {
            roomName: asText(baseSlot?.roomName) || getFallbackRoomLabel(slotIndex, roomNamingContext),
            learnerLabels: [...learnerGroup],
            assignedSpName: asText(baseSlot?.assignedSpName),
            backupSpName: asText(baseSlot?.backupSpName),
            caseLabel: asText(baseSlot?.caseLabel),
            roleId: asText(baseSlot?.roleId),
            roleLabel: asText(baseSlot?.roleLabel),
            notes: asText(baseSlot?.notes),
            stationStatus: normalizeScheduleStationStatus(baseSlot?.stationStatus) || undefined,
            isBackupStation: Boolean(baseSlot?.isBackupStation),
          } satisfies ScheduleBuilderPreviewResolvedRoomSlot;
        }),
      } satisfies ScheduleBuilderPreviewResolvedRound;
    });

    return {
      ...baseSnapshot,
      uploadedLearners: [...KNOWN_COMPLETED_SCHEDULE_REPAIR_LEARNER_ROSTER],
      originalUploadedLearners: [...KNOWN_COMPLETED_SCHEDULE_REPAIR_LEARNER_ROSTER],
      roundCount: String(KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROUND_COUNT),
      examRoomCount: String(KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_COUNT),
      flexRoomCount: "0",
      roomCapacity: String(KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_CAPACITY),
      scheduleStatus: "complete",
      scheduleRoundCount: KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROUND_COUNT,
      scheduleRoomCount: KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_COUNT,
      scheduleRoomCapacity: KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_CAPACITY,
      scheduleLearnerRoster: [...KNOWN_COMPLETED_SCHEDULE_REPAIR_LEARNER_ROSTER],
      eventDate:
        asText(baseSnapshot.eventDate) ||
        sessionEditor.session_date ||
        asText(event?.date_text),
      resolvedRounds: repairedRounds,
      savedAt: now,
    } satisfies ScheduleBuilderPreviewDraft;
  }, [event?.date_text, roomNamingContext, scheduleBuilderPreviewDraft, sessionEditor.session_date]);
  async function handleRepairCompletedScheduleSnapshot() {
    if (!id || !completedScheduleRepairStatus.isCorrupted) return;

    const confirmed = window.confirm(
      "Repair completed schedule snapshot?\n\nThis will replace corrupted saved schedule metadata for this event with the corrected completed schedule structure. This should only be used when the completed snapshot is known to be corrupted."
    );
    if (!confirmed) return;

    const repairedSnapshot = buildKnownCompletedScheduleRepairSnapshot();
    if (!repairedSnapshot) {
      setEventSaveError("Could not repair this completed schedule because the saved snapshot is missing.");
      setEventSaveMessage("");
      return;
    }

    const currentDay = scheduleBuilderDay || 1;
    const daySnapshots = parseScheduleBuilderPreviewDays(trainingMetadata.schedule_builder_days);
    daySnapshots.set(currentDay, repairedSnapshot);
    const currentAdjustments = parseScheduleRoomAdjustments(trainingMetadata.schedule_room_adjustments);
    const sanitizedAdjustments = sanitizeCompletedScheduleRepairAdjustments(currentAdjustments, {
      maxRounds: KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROUND_COUNT,
      maxSlotsPerRound: KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_COUNT,
    });
    const parsedAttendance = parseLearnerAttendanceMetadata(trainingMetadata.live_learner_attendance);
    const learnerNameBySlug = new Map(
      KNOWN_COMPLETED_SCHEDULE_REPAIR_LEARNER_ROSTER.map((name) => [getLearnerAttendanceSlug(name), name])
    );
    const repairedAttendanceRecords = Object.fromEntries(
      Object.entries(parsedAttendance).flatMap(([key, record]) => {
        const slug = asText(key).split(":").pop() || "";
        const learnerName = learnerNameBySlug.get(slug);
        if (!learnerName) {
          return /^\d+$/.test(slug) ? [] : [[key, record]];
        }
        if (isLearnerCountPlaceholderLabel(learnerName)) return [];

        const roundNumber = getRoundNumberFromRotationKey(record.roundKey || key);
        if (
          roundNumber < 1 ||
          roundNumber > KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROUND_COUNT
        ) {
          return [[key, record]];
        }

        const repairedRound = repairedSnapshot.resolvedRounds[roundNumber - 1];
        if (!repairedRound) {
          return [[key, record]];
        }

        const repairedSlotIndex = repairedRound.roomSlots.findIndex((slot) =>
          slot.learnerLabels.some((label) => normalizeLearnerName(label) === normalizeLearnerName(learnerName))
        );
        if (repairedSlotIndex < 0) {
          return [];
        }

        const repairedRoomName =
          asText(repairedRound.roomSlots[repairedSlotIndex]?.roomName) ||
          getFallbackRoomLabel(repairedSlotIndex, roomNamingContext);
        const repairedRoundKey = getSnapshotRoundKey(roundNumber);
        const repairedKey = getLearnerAttendanceKey(repairedRoundKey, repairedRoomName, learnerName);
        return [[
          repairedKey,
          {
            ...record,
            roomName: repairedRoomName,
            roundKey: repairedRoundKey,
          } satisfies LearnerAttendanceRecord,
        ]];
      })
    ) as LearnerAttendanceMap;
    const now = new Date().toISOString();

    setSaving(true);
    setEventSaveMessage("Repairing completed schedule snapshot...");
    setEventSaveError("");

    try {
      await persistTrainingMetadataFields(
        {
          schedule_builder_snapshot: encodeURIComponent(JSON.stringify(repairedSnapshot)),
          schedule_builder_days: serializeScheduleBuilderPreviewDays(daySnapshots),
          schedule_room_adjustments: serializeScheduleRoomAdjustments(sanitizedAdjustments),
          schedule_room_count: String(KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_COUNT),
          schedule_round_count: String(KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROUND_COUNT),
          schedule_room_capacity: String(KNOWN_COMPLETED_SCHEDULE_REPAIR_EXPECTED_ROOM_CAPACITY),
          schedule_learner_count: String(KNOWN_COMPLETED_SCHEDULE_REPAIR_LEARNER_ROSTER.length),
          schedule_learner_roster: encodeURIComponent(
            JSON.stringify([...KNOWN_COMPLETED_SCHEDULE_REPAIR_LEARNER_ROSTER])
          ),
          schedule_status: "complete",
          rotation_schedule_status:
            asText(trainingMetadata.rotation_schedule_status).toLowerCase() === "complete"
              ? trainingMetadata.rotation_schedule_status
              : "complete",
          live_learner_attendance: serializeLearnerAttendanceMetadata(repairedAttendanceRecords),
          schedule_last_saved_at: now,
          schedule_updated_at: now,
          schedule_repair_backup_snapshot: asText(trainingMetadata.schedule_builder_snapshot),
          schedule_repair_backup_days: asText(trainingMetadata.schedule_builder_days),
          schedule_repair_backup_adjustments: asText(trainingMetadata.schedule_room_adjustments),
          schedule_repair_backup_attendance: asText(trainingMetadata.live_learner_attendance),
          schedule_repair_applied_at: now,
          schedule_repair_applied_by: viewerRole,
          schedule_repair_note:
            "Known NUPR 706 VIR completed snapshot repair applied. Replaced corrupted learner placement metadata with the verified 4-round, 4-station rotation snapshot.",
        },
        "Completed schedule snapshot repaired."
      );

      setScheduleBuilderPreviewDraft(repairedSnapshot);
      setPersistedLearnerAttendanceRecords(repairedAttendanceRecords);
      await refreshData({
        preserveLocalEdits: true,
        preserveSelectedSp: true,
        source: "manual",
      });
    } catch (error) {
      setEventSaveError(
        error instanceof Error ? error.message : "Could not repair the completed schedule snapshot."
      );
      setEventSaveMessage("");
    } finally {
      setSaving(false);
    }
  }

  // CFSP schedule file inside cabinet v13
  useEffect(() => {
    if (typeof document === "undefined") return;

    const findCabinet = () => {
      const direct = document.getElementById("simulation-command-file-cabinet");
      if (direct instanceof HTMLElement) return direct;

      const candidates = Array.from(document.querySelectorAll("section, article, div"))
        .filter((node): node is HTMLElement => node instanceof HTMLElement)
        .filter((node) => {
          const text = (node.textContent || "").toLowerCase();
          return (
            text.includes("simulation command file cabinet") &&
            (text.includes("doorsign") || text.includes("case") || text.includes("recording"))
          );
        })
        .sort((a, b) => (a.textContent || "").length - (b.textContent || "").length);

      return candidates[0] || null;
    };

    const upsertScheduleFile = () => {
      const cabinet = findCabinet();
      if (!cabinet) return false;

      cabinet
        .querySelectorAll("[data-cfsp-schedule-file-card='true']")
        .forEach((node) => node.remove());

      const card = document.createElement("div");
      card.setAttribute("data-cfsp-schedule-file-card", "true");
      card.style.cssText = [
        "display:flex",
        "align-items:center",
        "justify-content:space-between",
        "gap:14px",
        "margin:14px 0",
        "padding:14px 16px",
        "border-radius:18px",
        "border:1px solid rgba(20,184,166,0.30)",
        "background:linear-gradient(135deg, rgba(255,255,255,0.98), rgba(240,253,250,0.92))",
        "box-shadow:0 12px 26px rgba(20,91,150,0.10)",
        "color:#12324a",
        "position:relative",
        "z-index:20",
      ].join(";");

      const label = document.createElement("div");
      label.style.cssText = [
        "display:grid",
        "gap:3px",
        "min-width:0",
        "color:#12324a",
      ].join(";");

      const eyebrow = document.createElement("div");
      eyebrow.textContent = scheduleCompleted ? "COMPLETED SCHEDULE FILE" : "SCHEDULE FILE";
      eyebrow.style.cssText = [
        "font-size:11px",
        "font-weight:950",
        "letter-spacing:.09em",
        "text-transform:uppercase",
        "color:#0f766e",
      ].join(";");

      const title = document.createElement("div");
      title.textContent = scheduleCompleted
        ? "Schedule is complete and lives in this file cabinet."
        : "Schedule is not complete yet. Finish it in the builder.";
      title.style.cssText = [
        "font-size:14px",
        "font-weight:900",
        "color:#12324a",
        "line-height:1.35",
      ].join(";");

      label.appendChild(eyebrow);
      label.appendChild(title);

      const button = document.createElement("button");
      button.type = "button";
      button.setAttribute("data-cfsp-schedule-file-link", "true");
      button.textContent = scheduleCompleted ? "Open Completed Schedule" : "Open Schedule Builder";
      button.style.cssText = [
        "appearance:none",
        "cursor:pointer",
        "white-space:nowrap",
        "border-radius:12px",
        "border:1px solid rgba(20,184,166,0.32)",
        "background:linear-gradient(135deg,#0f9488,#145b96)",
        "color:#ffffff",
        "font-weight:950",
        "padding:10px 14px",
        "box-shadow:0 8px 18px rgba(20,91,150,0.12)",
      ].join(";");

      const handleClick = () => {
        if (scheduleCompleted) {
          const existingOpenScheduleAction = Array.from(
            document.querySelectorAll("a, button")
          ).find((node) => {
            if (!(node instanceof HTMLElement)) return false;
            if (node.closest("[data-cfsp-schedule-file-card='true']")) return false;

            const label = (node.textContent || "")
              .toLowerCase()
              .replace(/\s+/g, " ")
              .trim();

            return label === "open schedule" || label.includes("open schedule");
          });

          if (existingOpenScheduleAction instanceof HTMLElement) {
            existingOpenScheduleAction.click();
            return;
          }

          window.location.assign(`/events/${encodeURIComponent(id)}#completed-schedule`);
          return;
        }

        const params = new URLSearchParams();
        params.set("source", "file-cabinet");
        params.set("view", "builder");

        window.location.assign(
          `/events/${encodeURIComponent(id)}/schedule-builder?${params.toString()}`
        );
      };

      button.addEventListener("click", handleClick);

      card.appendChild(label);
      card.appendChild(button);

      const titleNode = Array.from(cabinet.querySelectorAll("h1, h2, h3, strong, div"))
        .find((node) => (node.textContent || "").toLowerCase().includes("simulation command file cabinet"));

      const titleContainer = titleNode instanceof HTMLElement ? titleNode.closest("div") : null;

      if (titleContainer && titleContainer.parentElement === cabinet) {
        cabinet.insertBefore(card, titleContainer.nextSibling);
      } else {
        cabinet.insertBefore(card, cabinet.firstElementChild);
      }

      return true;
    };

    upsertScheduleFile();

    const interval = window.setInterval(() => {
      if (upsertScheduleFile()) {
        window.clearInterval(interval);
      }
    }, 400);

    const timeout = window.setTimeout(() => {
      window.clearInterval(interval);
    }, 6000);

    return () => {
      window.clearInterval(interval);
      window.clearTimeout(timeout);
      document
        .querySelectorAll("[data-cfsp-schedule-file-card='true']")
        .forEach((node) => node.remove());
    };
  }, [id, scheduleCompleted]);

  const trainingFacultyText = trainingMetadata.faculty_names || fallbackFacultyText;
  const facultyEmailText = trainingMetadata.faculty_email;
  const facultyPhoneText = trainingMetadata.faculty_phone;
  const validFacultyEmails = useMemo(
    () => extractValidFacultyEmailAddresses(facultyEmailText),
    [facultyEmailText]
  );
  const facultyHasValidEmail = validFacultyEmails.length > 0;
  const facultyContactInfoAvailable = Boolean(
    trainingFacultyText || facultyPhoneText || trainingMetadata.sim_contact || hasFaculty
  );
  const facultyEmailReadinessLabel = facultyHasValidEmail
    ? "FACULTY EMAIL READY"
    : facultyContactInfoAvailable
      ? "FACULTY EMAIL MISSING"
      : "FACULTY INFO NEEDED";
  const trainingSimContact =
    trainingMetadata.sim_contact || simStaffNames.join(", ") || "Sim Team Assigned";
  const eventMaterialUrl = asText(trainingMetadata.staffing_doc_url);
  const eventMaterialName =
    asText(trainingMetadata.staffing_doc_name) ||
    getFilenameFromUrl(eventMaterialUrl) ||
    "Event Material";
  const eventMaterialStoragePath = asText(trainingMetadata.staffing_doc_storage_path);
  const caseFileUrl = asText(trainingMetadata.case_file_url);
  const caseFileStoragePath = asText(trainingMetadata.case_file_storage_path);
  const caseFileDisplayName =
    asText(trainingMetadata.case_name) ||
    asText(trainingMetadata.case_file_name) ||
    getFilenameFromUrl(caseFileUrl) ||
    "";
  const legacyCaseFileEntry = useMemo(
    () =>
      normalizeCaseFileEntry(
        {
          id: "primary-case-file",
          name: caseFileDisplayName,
          url: caseFileUrl,
          storagePath: caseFileStoragePath,
          uploadedAt: trainingMetadata.case_file_uploaded_at,
          uploadedBy: trainingMetadata.case_file_uploaded_by,
        },
        0
      ),
    [
      caseFileDisplayName,
      caseFileStoragePath,
      caseFileUrl,
      trainingMetadata.case_file_uploaded_at,
      trainingMetadata.case_file_uploaded_by,
    ]
  );
  const structuredCaseFileEntries = useMemo(
    () => parseCaseFileEntries(trainingMetadata.case_manager_cases || trainingMetadata.case_files),
    [trainingMetadata.case_files, trainingMetadata.case_manager_cases]
  );
  const caseFileEntries = useMemo(
    () =>
      structuredCaseFileEntries.length
        ? structuredCaseFileEntries
        : mergeLegacyCaseFileEntry([], legacyCaseFileEntry),
    [legacyCaseFileEntry, structuredCaseFileEntries]
  );
  const primaryCaseFileEntry = caseFileEntries[0] || legacyCaseFileEntry;
  const caseFileCount = caseFileEntries.length;
  const uploadedCaseFileCount = caseFileEntries.filter((entry) => Boolean(entry.url || entry.storagePath)).length;
  const caseDocumentReadinessEntries = useMemo(() => {
    const seen = new Set<string>();
    const entries: Array<{
      key: string;
      name: string;
      previewReady: boolean;
      attachedByNameOnly: boolean;
    }> = [];
    const pushEntry = (args: {
      key: string;
      name: string;
      previewReady: boolean;
      attachedByNameOnly: boolean;
    }) => {
      const normalizedName = normalizeDisplayText(args.name).toLowerCase();
      const dedupeKey = normalizedName || args.key;
      if (!dedupeKey || seen.has(dedupeKey)) return;
      seen.add(dedupeKey);
      entries.push(args);
    };

    caseFileEntries.forEach((entry, index) => {
      if (!hasCaseFileDocumentEvidence(entry)) return;
      const previewReady = Boolean(entry.url || entry.storagePath);
      pushEntry({
        key: entry.id || `case-file-entry-${index + 1}`,
        name: entry.name || `Case ${index + 1}`,
        previewReady,
        attachedByNameOnly: !previewReady,
      });
    });

    (scheduleBuilderPreviewDraft?.scheduleCaseDefinitions || [])
      .filter((caseDef) => caseDef.active !== false && hasCaseFileDocumentEvidence(caseDef))
      .forEach((caseDef, index) => {
        const previewReady = Boolean(caseDef.documentUrl || caseDef.fileUrl || caseDef.storagePath);
        pushEntry({
          key: caseDef.id || `schedule-case-definition-${index + 1}`,
          name: caseDef.documentName || caseDef.name || `Case ${index + 1}`,
          previewReady,
          attachedByNameOnly: !previewReady,
        });
      });

    return entries;
  }, [caseFileEntries, scheduleBuilderPreviewDraft?.scheduleCaseDefinitions]);
  const caseDocumentReadyCount = caseDocumentReadinessEntries.length;
  const caseDocumentPreviewReadyCount = caseDocumentReadinessEntries.filter((entry) => entry.previewReady).length;
  const caseDocumentNameOnlyCount = caseDocumentReadinessEntries.filter((entry) => entry.attachedByNameOnly).length;
  const caseDocumentSummaryLabel = caseDocumentReadyCount
    ? caseDocumentPreviewReadyCount === caseDocumentReadyCount
      ? `${caseDocumentReadyCount} case file${caseDocumentReadyCount === 1 ? "" : "s"} ready`
      : `${caseDocumentReadyCount} case file${caseDocumentReadyCount === 1 ? "" : "s"}`
    : "No case file";
  const caseDocumentDetailLabel = caseDocumentReadyCount
    ? caseDocumentPreviewReadyCount === caseDocumentReadyCount
      ? `${caseDocumentReadyCount} case file${caseDocumentReadyCount === 1 ? "" : "s"} ready`
      : `${caseDocumentReadyCount} case file${caseDocumentReadyCount === 1 ? "" : "s"} attached`
    : "";
  const eventMaterialBusy = trainingMaterialSaving.staffing_doc;
  const materialsReadinessRaw = getFirstNoteValue(eventEditor.notes || event?.notes, [
    "Materials Readiness",
    "Materials Status",
  ]) || trainingMetadata.event_material_status;
  const savedMaterialsReadinessValue = normalizeMaterialsReadinessValue(materialsReadinessRaw);
  const materialsReadinessOption =
    getMaterialsReadinessOption(savedMaterialsReadinessValue || "materials_not_reviewed") ||
    materialsReadinessOptions[0];
  const hasUploadedEventMaterial = Boolean(eventMaterialUrl);
  const hasAnyMaterialEvidence = hasUploadedEventMaterial || hasMaterialEvidence(trainingMetadata);
  const materialsReadinessNeedsAttention =
    savedMaterialsReadinessValue === "materials_needed" ||
    savedMaterialsReadinessValue === "awaiting_faculty_materials";
