  const resolvedScheduleMatrixCaseCount = useMemo(() => {
    if (scheduleBuilderDraftActiveCaseCount > 0) {
      return scheduleBuilderDraftActiveCaseCount;
    }
    const explicitCaseCount = parsePositiveInteger(trainingMetadata.case_count, 0);
    const parsedCaseCount = parseCaseFileEntries(trainingMetadata.case_manager_cases || trainingMetadata.case_files).filter((entry) => entry.status !== "inactive").length;
    return Math.max(explicitCaseCount, parsedCaseCount);
  }, [
    scheduleBuilderDraftActiveCaseCount,
    trainingMetadata.case_count,
    trainingMetadata.case_files,
    trainingMetadata.case_manager_cases,
  ]);
  const isScheduleMatrixVirtual = selectedModalityLabel === "Virtual";
  const currentLiveReferenceRoundIndex = useMemo(
    () =>
      currentLiveReferenceRound
        ? rotationRounds.findIndex((round) => round.key === currentLiveReferenceRound.key)
        : -1,
    [currentLiveReferenceRound, rotationRounds]
  );
  const currentLiveReferenceSessions = useMemo(() => {
    if (!currentLiveReferenceRound) return [] as EventSessionRow[];
    return sessions.filter((session) => getRotationRoundKeyFromSession(session) === currentLiveReferenceRound.key);
  }, [currentLiveReferenceRound, sessions]);
  const currentLiveReferenceRoomSlotEntries = useMemo(() => {
    if (!currentLiveReferenceRound) return [] as RoomDisplayEntry[];
    return (
      roomSlotEntriesByRoundKey.get(currentLiveReferenceRound.key) ||
      buildFullRoomSlotsForRound(currentLiveReferenceRound, {
        metadataRoomCount: effectiveRoomCount,
        roomContext: roomNamingContext,
      })
    );
  }, [currentLiveReferenceRound, effectiveRoomCount, roomNamingContext, roomSlotEntriesByRoundKey]);
  const currentLiveReferenceScheduleRows = useMemo(() => {
    if (!currentLiveReferenceRound) return [] as Array<{ roomName: string; learnerLabels: string[] }>;

    const completedReferenceRound = resolveSelectedScheduleRound({
      selectedRotationRound: currentLiveReferenceRound,
      resolvedRounds: authoritativeScheduleResolvedRounds,
      persistedResolvedRoundsByKey,
      selectedRoundIndex: Math.max(currentLiveReferenceRoundIndex, 0),
      selectedRoundGlobalIndex: Math.max(currentLiveReferenceRoundIndex, 0),
    });
    if (completedReferenceRound?.roomSlots?.length) {
      const activeCaseLabelsForReference = (scheduleBuilderPreviewDraft?.scheduleCaseDefinitions || [])
        .filter((caseDef) => caseDef.active !== false)
        .map((caseDef) => asText(caseDef.name))
        .filter(Boolean);
      const fallbackCaseLabelsForReference = parseCaseFileEntries(
        trainingMetadata.case_manager_cases || trainingMetadata.case_files
      )
        .filter((caseEntry) => caseEntry.status !== "inactive")
        .map((caseEntry) => asText(caseEntry.name))
        .filter(Boolean);
      const referenceRoundNumber = Number(completedReferenceRound.round) || Math.max(currentLiveReferenceRoundIndex, 0) + 1;
      const sanitizedSlots = sanitizeSavedScheduleRoomSlotsForRender(
        completedReferenceRound.roomSlots,
        activeScheduleRoomAdjustments.get(referenceRoundNumber) || [],
        activeCaseLabelsForReference.length ? activeCaseLabelsForReference : fallbackCaseLabelsForReference
      );
      return sanitizedSlots.map((slot, slotIndex) => ({
        roomName: asText(slot.roomName) || getFallbackRoomLabel(slotIndex, roomNamingContext),
        learnerLabels: getActualLearnerNames(slot.learnerLabels),
      }));
    }

    const sessionByRoomNumber = new Map<number, EventSessionRow>();
    const sessionByRoomName = new Map<string, EventSessionRow>();
    currentLiveReferenceSessions.forEach((session) => {
      const roomName = asText(session.room);
      const roomNumber = getRoomDisplayNumber(roomName);
      if (roomNumber !== null && !sessionByRoomNumber.has(roomNumber)) {
        sessionByRoomNumber.set(roomNumber, session);
      }
      if (roomName) sessionByRoomName.set(roomName.toLowerCase(), session);
    });

    const displayRows = currentLiveReferenceRoomSlotEntries.length
      ? currentLiveReferenceRoomSlotEntries.map((entry, slotIndex) => {
          const roomNumber = getRoomDisplayNumber(entry.roomName);
          const matchedSession =
            (roomNumber !== null ? sessionByRoomNumber.get(roomNumber) : null) ||
            sessionByRoomName.get(asText(entry.roomName).toLowerCase()) ||
            null;
          return {
            roomName:
              asText(matchedSession?.room) ||
              asText(entry.roomName) ||
              getFallbackRoomLabel(slotIndex, roomNamingContext),
            slotIndex,
          };
        })
      : [];

    return displayRows.map(({ roomName, slotIndex }) => {
      const learnerLabels = getResolvedRoundLearnerLabels({
        learnerRoster: scheduleBuilderLearnerNames,
        roomCapacity: scheduleBuilderRoomCapacity,
        roundIndex: Math.max(currentLiveReferenceRoundIndex, 0),
        slotIndex,
        roomSlotCount: Math.max(displayRows.length, 1),
        activeCaseCount: resolvedScheduleMatrixCaseCount,
        isMultiCaseMode: resolvedScheduleMatrixCaseCount > 1,
        isVirtualEvent: isScheduleMatrixVirtual,
      });
      return { roomName, learnerLabels };
    });
  }, [
    currentLiveReferenceRound,
    currentLiveReferenceRoundIndex,
    currentLiveReferenceRoomSlotEntries,
    currentLiveReferenceSessions,
    isScheduleMatrixVirtual,
    activeScheduleRoomAdjustments,
    authoritativeScheduleResolvedRounds,
    persistedResolvedRoundsByKey,
    resolvedScheduleMatrixCaseCount,
    roomNamingContext,
    scheduleBuilderPreviewDraft?.scheduleCaseDefinitions,
    scheduleBuilderLearnerNames,
    scheduleBuilderRoomCapacity,
    trainingMetadata.case_files,
    trainingMetadata.case_manager_cases,
  ]);
  const selectedRoundSessions = useMemo(() => {
    if (!selectedRotationRound) return [] as EventSessionRow[];
    return sessions.filter((session) => getRotationRoundKeyFromSession(session) === selectedRotationRound.key);
  }, [selectedRotationRound, sessions]);
  const selectedResolvedRoundResolution = useMemo(
    () =>
      resolveSelectedScheduleRoundWithTrace({
        selectedRotationRound,
        resolvedRounds: authoritativeScheduleResolvedRounds,
        persistedResolvedRoundsByKey,
        selectedRoundIndex: activeSelectedRotationRoundIndex,
        selectedRoundGlobalIndex: activeSelectedRotationRoundGlobalIndex,
      }),
    [
      activeSelectedRotationRoundGlobalIndex,
      activeSelectedRotationRoundIndex,
      authoritativeScheduleResolvedRounds,
      persistedResolvedRoundsByKey,
      selectedRotationRound,
    ]
  );
  const selectedResolvedRound = selectedResolvedRoundResolution.round;
  const selectedResolvedRoundNumber =
    (selectedResolvedRound && Number.isFinite(selectedResolvedRound.round) ? selectedResolvedRound.round : 0) ||
    getRoundNumberFromRotationKey(selectedRotationRound?.key) ||
    (activeSelectedRotationRoundGlobalIndex >= 0 ? activeSelectedRotationRoundGlobalIndex + 1 : activeSelectedRotationRoundIndex + 1);
  const selectedResolvedRoomSlots = useMemo(
    () => selectedResolvedRound?.roomSlots || [],
    [selectedResolvedRound]
  );
  const selectedRoundRoomSlotEntries = useMemo(() => {
    if (!selectedRotationRound) return [] as RoomDisplayEntry[];
    if (selectedResolvedRoomSlots.length) {
      return selectedResolvedRoomSlots.map((slot, slotIndex) => ({
        roomName: asText(slot.roomName) || getFallbackRoomLabel(slotIndex, roomNamingContext),
        sourceIndex: slotIndex,
      }));
    }

    const mappedSlots = roomSlotEntriesByRoundKey.get(selectedRotationRound.key) || [];
    const persistedRoundSlotCount = selectedResolvedRoomSlots.length || 0;
    const operationalRoomCount = Math.max(
      mappedSlots.length,
      persistedRoundSlotCount ? 0 : effectiveRoomCount
    );

    const expandedSlots = buildFullRoomSlotsForRound(selectedRotationRound, {
      metadataRoomCount: operationalRoomCount,
      roomContext: roomNamingContext,
    });

    // Operations must follow actual room/SP coverage, not learner-capacity compression.
    if (mappedSlots.length >= operationalRoomCount) return mappedSlots;

    return expandedSlots.map((slot, index) => ({
      ...slot,
      ...(mappedSlots[index] || {}),
      roomName: mappedSlots[index]?.roomName || slot.roomName,
    }));
  }, [
    effectiveRoomCount,
    roomNamingContext,
    roomSlotEntriesByRoundKey,
    selectedResolvedRoomSlots,
    selectedRotationRound,
  ]);
  const selectedRoundRoomCount = selectedResolvedRoomSlots.length || selectedRoundRoomSlotEntries.length;
  useEffect(() => {
    const isAdminViewer = viewerRole === "admin" || viewerRole === "super_admin";
    if (!isAdminViewer || !authoritativeEventScheduleTruth.hasSavedScheduleData) return;

    const selectedRoundHasSlots = selectedResolvedRoomSlots.length > 0;
    if (selectedRoundHasSlots) return;

    const availableRoundSlotCounts = authoritativeScheduleResolvedRounds.map((round, roundIndex) => ({
      round: parsePositiveInteger(round.round, roundIndex + 1),
      dayKey: normalizeScheduleDayKey(round.sessionDate),
      slotCount: round.roomSlots.length,
      startTime: asText(round.startTime),
      endTime: asText(round.endTime),
    }));

    window.console.warn("Schedule truth diagnostic: selected round unresolved slots", {
      scheduleSource: authoritativeEventScheduleTruth.scheduleSource,
      selectedRoundLabel: selectedRotationRound ? `Round ${activeSelectedRotationRoundIndex + 1}` : "Round not selected",
      selectedRoundIndex: activeSelectedRotationRoundIndex,
      selectedRoundGlobalIndex: activeSelectedRotationRoundGlobalIndex,
      selectedDayKey:
        normalizeScheduleDayKey(selectedEventDateContext) || normalizeScheduleDayKey(selectedRotationRound?.session_date),
      savedRoundCount: authoritativeScheduleResolvedRounds.length,
      selectedRoundHasSlots,
      selectedRoundSlotCount: selectedResolvedRoomSlots.length,
      availableRoundSlotCounts,
      sourcePathUsed: selectedResolvedRoundResolution.sourcePath,
    });
  }, [
    activeSelectedRotationRoundGlobalIndex,
    activeSelectedRotationRoundIndex,
    authoritativeEventScheduleTruth.hasSavedScheduleData,
    authoritativeEventScheduleTruth.scheduleSource,
    authoritativeScheduleResolvedRounds,
    selectedEventDateContext,
    selectedResolvedRoomSlots.length,
    selectedResolvedRoundResolution.sourcePath,
    selectedRotationRound,
    viewerRole,
  ]);
  const selectedRoundCaseLabel = useMemo(
    () =>
      getFirstNoteValue(eventEditor.notes || event?.notes, ["Case", "Case Name", "Station Case"]) ||
      asText(trainingMetadata.case_name) ||
      parseCaseFileEntries(trainingMetadata.case_files)[0]?.name ||
      getDisplayFileStem(trainingMetadata.case_file_url) ||
      getDisplayFileStem(eventMaterialUrl) ||
      "",
    [event?.notes, eventEditor.notes, eventMaterialUrl, trainingMetadata.case_files, trainingMetadata.case_file_url, trainingMetadata.case_name]
  );
  const selectedRoundStationLabel = useMemo(
    () => getFirstNoteValue(eventEditor.notes || event?.notes, ["Station", "Station Label", "Station Labels"]),
    [event?.notes, eventEditor.notes]
  );
  const backupAssignmentNameSet = useMemo(() => {
    const names = new Set<string>();
    backupAssignments.forEach((assignment) => {
      const sp = assignment.sp_id ? spsById.get(assignment.sp_id) || null : null;
      const spName = normalizeDisplayText(getFullName(sp || emptySpRow)).toLowerCase();
      if (spName) names.add(spName);
    });
    return names;
  }, [backupAssignments, spsById]);
  const activeScheduleCaseLabels = useMemo(() => {
    const snapshotCaseLabels = (scheduleBuilderPreviewDraft?.scheduleCaseDefinitions || [])
      .filter((caseDef) => caseDef.active !== false)
      .map((caseDef) => asText(caseDef.name))
      .filter(Boolean);
    if (snapshotCaseLabels.length) return snapshotCaseLabels;
    return caseFileEntries
      .filter((caseEntry) => asText(caseEntry.status).toLowerCase() !== "inactive")
      .map((caseEntry) => asText(caseEntry.name))
      .filter(Boolean);
  }, [caseFileEntries, scheduleBuilderPreviewDraft?.scheduleCaseDefinitions]);
  const selectedRoundResolvedScheduleTruth = useMemo(
    () =>
      buildSelectedRoundOperationalRooms({
        selectedRotationRound,
        selectedResolvedRound,
        selectedResolvedRoundNumber,
        selectedRoundRoomSlotEntries,
        selectedRoundSessions,
        activeScheduleRoomAdjustments,
        selectedRoundCaseLabel,
        selectedRoundStationLabel,
        backupAssignmentNameSet,
        roomNamingContext,
        eventLocation: event?.location,
        scheduleBuilderLearnerNames,
        scheduleBuilderRoomCapacity,
	        resolvedScheduleMatrixCaseCount,
        isScheduleMatrixVirtual,
        activeScheduleCaseLabels,
        assignedSpNames: confirmedAssignmentNames,
	      }),
    [
      activeScheduleRoomAdjustments,
      activeScheduleCaseLabels,
      backupAssignmentNameSet,
      confirmedAssignmentNames,
      event?.location,
      isScheduleMatrixVirtual,
      resolvedScheduleMatrixCaseCount,
      roomNamingContext,
      scheduleBuilderLearnerNames,
      scheduleBuilderRoomCapacity,
      selectedResolvedRound,
      selectedResolvedRoundNumber,
      selectedRotationRound,
		      selectedRoundCaseLabel,
		      selectedRoundRoomSlotEntries,
      selectedRoundSessions,
      selectedRoundStationLabel,
    ]
  );
  const selectedRoundActiveScheduleTruth = useMemo(
    () => selectedRoundResolvedScheduleTruth?.filter((station) => station.stationStatus === "active") || null,
    [selectedRoundResolvedScheduleTruth]
  );
  const selectedRoundBackupScheduleTruth = useMemo(
    () => selectedRoundResolvedScheduleTruth?.filter((station) => station.stationStatus === "backup") || null,
    [selectedRoundResolvedScheduleTruth]
  );
  const selectedRoundActiveStationCount =
    selectedRoundActiveScheduleTruth !== null ? selectedRoundActiveScheduleTruth.length : selectedRoundRoomCount;
  const selectedRoundBackupStationCount = selectedRoundBackupScheduleTruth?.length || 0;
  const selectedRoundScheduleRows = useMemo(() => {
    if (!selectedRoundResolvedScheduleTruth?.length) {
      return [] as Array<RoundRoomRow>;
    }
    return selectedRoundResolvedScheduleTruth
      .filter((station) => station.stationStatus !== "inactive")
      .map((station) => {
	      const assignment = station.primarySpName
	        ? findAssignmentBySpDisplayName(confirmedAssignments, spsById, station.primarySpName)
	        : null;
	      const sp = assignment?.sp_id ? spsById.get(assignment.sp_id) || null : null;
	      const learnerLabels = getActualLearnerNames(station.learnerLabels);
	      const hasPrimarySpName = Boolean(asText(station.primarySpName));
	      const flags = [
	        station.roomName ? "" : "Missing room",
	        assignment && !sp ? "Missing SP profile" : "",
	        staffingRelevant && !hasPrimarySpName && station.stationStatus === "active" ? "Missing SP" : "",
	        effectiveLearnerCount > 0 && !learnerLabels.length && station.stationStatus === "active" ? "No student assigned" : "",
	      ].filter(Boolean);

      return {
        key: `${station.key}-schedule`,
        slotIndex: station.roomSlotIndex,
        roomName: station.roomName,
        location: station.location || asText(event?.location),
        learnerLabels,
	        learnerCountFallback: station.learnerCountFallback,
	        snapshotLearnerPlacementLocked: station.snapshotLearnerPlacementLocked,
	        assignment,
	        sp,
	        primarySpName: station.primarySpName,
	        backupSpName: station.backupSpName,
	        caseLabel: station.caseLabel,
        roleId: station.roleId,
        roleLabel: station.roleLabel,
        notes: station.notes,
        stationLabel: station.stationLabel,
        flags,
      } satisfies RoundRoomRow;
    });
  }, [
    event?.location,
    effectiveLearnerCount,
    selectedRoundResolvedScheduleTruth,
    confirmedAssignments,
    spsById,
    staffingRelevant,
  ]);
  const selectedRoundOperationsRows = useMemo(() => {
    if (!selectedRoundResolvedScheduleTruth?.length) {
      return [] as OperationsRoomCardRow[];
    }

    const scheduleRowsBySlotIndex = new Map(selectedRoundScheduleRows.map((row) => [row.slotIndex, row]));

    return selectedRoundResolvedScheduleTruth.map((station) => {
      const existingRow = scheduleRowsBySlotIndex.get(station.roomSlotIndex) || null;
      const primarySpName = asText(station.primarySpName);
      const learnerLabels = getActualLearnerNames(station.learnerLabels);
      const roomName = station.roomName;
      const caseLabel = asText(station.caseLabel);
      const effectiveCaseEntry = findCaseFileEntryForLabel(caseFileEntries, caseLabel);
      const roleId = asText(station.roleId);
      const roleLabel = resolveCaseRoleLabel(
        effectiveCaseEntry,
        roleId,
        asText(station.roleLabel)
      );
      const assignment = primarySpName
        ? findAssignmentBySpDisplayName(confirmedAssignments, spsById, primarySpName)
        : null;
      const sp = assignment?.sp_id ? spsById.get(assignment.sp_id) || null : null;

      return {
        key: `${station.key}-ops`,
        slotIndex: station.roomSlotIndex,
        roomName,
        location: station.location || existingRow?.location || asText(event?.location),
        learnerLabels,
        learnerCountFallback: station.learnerCountFallback || existingRow?.learnerCountFallback || 0,
        snapshotLearnerPlacementLocked: station.snapshotLearnerPlacementLocked || Boolean(existingRow?.snapshotLearnerPlacementLocked),
        assignment,
        sp,
        primarySpName,
        backupSpName: asText(station.backupSpName),
        caseLabel,
        roleId,
        roleLabel,
        notes: asText(station.notes),
        stationLabel: asText(station.stationLabel),
        stationStatus: station.stationStatus,
        isActiveStation: station.stationStatus === "active",
        isBackupStation: station.stationStatus === "backup",
        flags: station.stationStatus !== "active"
          ? (existingRow?.flags || []).filter((flag) => !["Missing SP", "No learner assigned", "No student assigned"].includes(asText(flag)))
          : existingRow?.flags || [],
      } satisfies OperationsRoomCardRow;
    });
  }, [
    caseFileEntries,
    confirmedAssignments,
    event?.location,
    selectedRoundResolvedScheduleTruth,
    selectedRoundScheduleRows,
    spsById,
  ]);
  const getOperationsRoomPrimarySpName = (row: OperationsRoomCardRow | RoundRoomRow) =>
    row.sp ? getFullName(row.sp) : ("primarySpName" in row ? asText(row.primarySpName) : "");
  const selectedRoundLearnerFlowRows = useMemo(() => {
    if (selectedRoundResolvedScheduleTruth?.length) {
      return selectedRoundResolvedScheduleTruth
        .filter((station) => station.stationStatus !== "inactive")
        .map((station) => ({
          key: `${station.key}-learner-flow`,
          roomName: station.roomName,
          learnerLabels: getActualLearnerNames(station.learnerLabels),
          learnerCountFallback: station.learnerCountFallback,
          snapshotLearnerPlacementLocked: station.snapshotLearnerPlacementLocked,
          stationLabel: station.stationLabel,
          caseLabel: station.caseLabel,
          roleLabel: station.roleLabel,
          encounterLabel: station.encounterLabel,
          roundNumber: station.roundNumber,
          start: station.start,
          end: station.end,
          stationStatus: station.stationStatus,
          isBackupStation: station.isBackupStation,
        }));
    }

    return selectedRoundScheduleRows.map((row, index) => ({
      key: `${row.key}-learner-flow`,
      roomName: row.roomName || getFallbackRoomLabel(index, roomNamingContext),
      learnerLabels: getActualLearnerNames(row.learnerLabels),
      learnerCountFallback: row.learnerCountFallback || 0,
      snapshotLearnerPlacementLocked: row.snapshotLearnerPlacementLocked,
      stationLabel: row.stationLabel,
      caseLabel: row.caseLabel,
      roleLabel: row.roleLabel,
      encounterLabel: [row.stationLabel, row.caseLabel].filter(Boolean).join(" · ") || "Case pending",
      roundNumber: selectedResolvedRoundNumber,
      start: asText(selectedRotationRound?.start_time),
      end: asText(selectedRotationRound?.end_time),
      stationStatus: "active" as ScheduleStationStatus,
      isBackupStation: false,
    }));
  }, [
    roomNamingContext,
    selectedResolvedRoundNumber,
    selectedRotationRound?.end_time,
    selectedRotationRound?.start_time,
    selectedRoundResolvedScheduleTruth,
    selectedRoundScheduleRows,
  ]);
	  const selectedRoundLearnerCount = useMemo(() => {
	    if (!selectedRotationRound) return null;
	    const resolvedLearnerCount = selectedRoundLearnerFlowRows.reduce((total, row) => total + row.learnerLabels.length, 0);
	    const hasAuthoritativeSavedSlots = selectedRoundLearnerFlowRows.some((row) => row.snapshotLearnerPlacementLocked);
	    if (hasAuthoritativeSavedSlots) return resolvedLearnerCount;
	    if (resolvedLearnerCount > 0) return resolvedLearnerCount;
    if (effectiveLearnerCount <= 0) return null;
    const roomCapacity = selectedRoundRoomCount || 0;
    if (roomCapacity <= 0) return null;
    const remaining = effectiveLearnerCount - Math.max(selectedResolvedRoundNumber - 1, 0) * roomCapacity;
    if (remaining <= 0) return 0;
    return Math.min(roomCapacity, remaining);
  }, [effectiveLearnerCount, selectedResolvedRoundNumber, selectedRotationRound, selectedRoundLearnerFlowRows, selectedRoundRoomCount]);
  const operationalRoundCount = rotationRounds.length || activeRotationCount || scheduleBuilderDraftRoundCount || 0;
  const operationalRoomCount = selectedRoundActiveStationCount || selectedRoundRoomCount || effectiveRoomCount || scheduleBuilderDraftRoomCount || 0;
  const completedScheduleCalculatedRoundCount =
    completedScheduleMetadataResult?.calculatedRoundCount ||
    getCompletedScheduleCalculatedRoundCount(completedScheduleMetadataPayload);
  const completedScheduleDisplayMismatchWarning =
    completedScheduleMetadataStatus === "complete" &&
    completedScheduleCalculatedRoundCount > 0 &&
    operationalRoundCount > 0 &&
    operationalRoundCount !== completedScheduleCalculatedRoundCount
      ? `Schedule display mismatch: completed schedule calculates ${completedScheduleCalculatedRoundCount} rounds but UI is showing ${operationalRoundCount}.`
      : "";
  const completedScheduleNormalizedRoundWarning =
    !completedScheduleDisplayMismatchWarning &&
    completedScheduleMetadataResult?.wasNormalized
      ? "Completed schedule round count differs from legacy setup count. Showing completed schedule."
      : "";
  const operationalLearnerCountLabel =
    selectedRoundLearnerCount !== null
      ? String(selectedRoundLearnerCount)
      : effectiveLearnerCount > 0
        ? String(effectiveLearnerCount)
        : "TBD";
  const selectedRoundEmptySlots = useMemo(() => {
    if (!selectedRotationRound) return null;
    if (selectedRoundLearnerCount === null) return null;
    const roomSlots = selectedRoundActiveStationCount || selectedRoundRoomCount || 0;
    if (roomSlots <= 0) return null;
    return Math.max(roomSlots - selectedRoundLearnerCount, 0);
  }, [selectedRoundActiveStationCount, selectedRoundLearnerCount, selectedRotationRound, selectedRoundRoomCount]);
  const learnerPlannerCapacity = useMemo(() => {
    if (effectiveRoomCount <= 0 || activeRotationCount <= 0) return 0;
    return effectiveRoomCount * Math.max(scheduleBuilderRoomCapacity, 1) * activeRotationCount;
  }, [activeRotationCount, effectiveRoomCount, scheduleBuilderRoomCapacity]);
  const learnerFlowSelectedRoundCoverageShortage = Math.max(Math.max(selectedRoundActiveStationCount || selectedRoundRoomCount, needed) - confirmedAssignments.length, 0);
  const learnerPlannerRosterCount = scheduleBuilderLearnerNames.length;
  const learnerPlannerExpectedCount = Math.max(effectiveLearnerCount, learnerPlannerRosterCount);
  const learnerPlannerAssignedCount =
    learnerPlannerRosterCount > 0 && learnerPlannerCapacity > 0
      ? Math.min(learnerPlannerRosterCount, learnerPlannerCapacity)
      : 0;
  const learnerPlannerUnassignedCount = Math.max(learnerPlannerRosterCount - learnerPlannerAssignedCount, 0);
  const learnerPlannerMissingSignals = [
    learnerPlannerExpectedCount > 0 && learnerPlannerRosterCount === 0
      ? `${learnerPlannerExpectedCount} expected learner${learnerPlannerExpectedCount === 1 ? "" : "s"} counted, but roster names are not available`
      : "",
    learnerPlannerRosterCount > 0 && effectiveRoomCount <= 0 ? "Room count is missing" : "",
    learnerPlannerRosterCount > 0 && activeRotationCount <= 0 ? "Rotation rounds are missing" : "",
    learnerPlannerUnassignedCount > 0
      ? `${learnerPlannerUnassignedCount} learner${learnerPlannerUnassignedCount === 1 ? "" : "s"} beyond current room/round capacity`
      : "",
  ].filter(Boolean);
  const selectedRoundAssignedLearnerCount = selectedRoundLearnerFlowRows.reduce((total, row) => total + row.learnerLabels.length, 0);
  const selectedRoundExpectedLearnerCount = selectedRoundLearnerCount ?? 0;
  const selectedRoundPrimaryCoveredCount = selectedRoundOperationsRows.filter(
    (row) => row.isActiveStation && row.assignment && getAssignmentStatus(row.assignment) === "confirmed"
  ).length;
  const selectedRoundConfiguredRoomCount = Math.max(selectedRoundScheduleRows.length, selectedRoundRoomCount, 0);
  const selectedRoundRoomNameCounts = selectedRoundScheduleRows.reduce<Map<string, number>>((map, row) => {
    const roomName = asText(row.roomName).trim().toLowerCase();
    if (!roomName || isRoomPlaceholderLabel(row.roomName)) {
      return map;
    }
    map.set(roomName, (map.get(roomName) || 0) + 1);
    return map;
  }, new Map<string, number>());
  const duplicateAssignedRoomLabels = Array.from(selectedRoundRoomNameCounts.entries())
    .filter(([, count]) => count > 1)
    .map(([roomName, count]) => `${roomName.toUpperCase()} assigned in ${count} rows`)
    .map((item) => `Duplicate room mapping: ${item}`);
  const sameDateRoundTimings = useMemo(() => {
    const roundsByDate = rotationRounds.reduce<Record<string, RotationRound[]>>((acc, round) => {
      const dateKey = asText(round.session_date) || "date-tbd";
      if (!acc[dateKey]) acc[dateKey] = [];
      acc[dateKey].push(round);
      return acc;
    }, {} as Record<string, RotationRound[]>);

    return Object.entries(roundsByDate).flatMap(([dateKey, roundsForDate]) =>
      roundsForDate
        .map((round) => {
          const timing = getNormalizedRotationRoundTiming(round, roundsForDate);
          if (!timing) return null;
          return { dateKey, round, ...timing };
        })
        .filter((row): row is { dateKey: string; round: RotationRound; startMinutes: number; endMinutes: number } => Boolean(row))
        .sort((a, b) => {
          if (a.startMinutes !== b.startMinutes) return a.startMinutes - b.startMinutes;
          return a.endMinutes - b.endMinutes;
        })
        .map((entry, index, list) => {
          const previous = index > 0 ? list[index - 1] : null;
          if (!previous) return null;
          if (entry.startMinutes >= previous.endMinutes) return null;
          return {
            dateKey: entry.dateKey,
            current: entry.round,
            previous: previous.round,
            previousStart: previous.startMinutes,
            previousEnd: previous.endMinutes,
            currentStart: entry.startMinutes,
          };
        })
        .filter((issue): issue is NonNullable<typeof issue> => Boolean(issue))
    );
  }, [rotationRounds]);
  const learnerFlowTimingCollisionSignals = sameDateRoundTimings.map(
    ({ current, previous }) => `${current.key} starts before ${previous.key} completed`
  );
  const learnerFlowRoundCapacitySignals =
    selectedRoundExpectedLearnerCount > 0 && selectedRoundAssignedLearnerCount < selectedRoundExpectedLearnerCount
      ? [
          `${
            selectedRoundExpectedLearnerCount - selectedRoundAssignedLearnerCount
          } learner${selectedRoundExpectedLearnerCount - selectedRoundAssignedLearnerCount === 1 ? "" : "s"} unassigned in active round`,
        ]
      : [];
  const learnerFlowMissingSignals = [
    ...learnerPlannerMissingSignals,
    ...duplicateAssignedRoomLabels,
    ...learnerFlowRoundCapacitySignals,
    ...learnerFlowTimingCollisionSignals,
    staffingRelevant && learnerFlowSelectedRoundCoverageShortage > 0
      ? `${learnerFlowSelectedRoundCoverageShortage} room slot${learnerFlowSelectedRoundCoverageShortage === 1 ? "" : "s"} without SP assignment in active round`
      : "",
  ].filter(Boolean);
  const learnerAssignmentsIncomplete = learnerFlowMissingSignals.length > 0;
  const learnerFlowIssues: LearnerFlowIssue[] = useMemo(
    () =>
      learnerFlowMissingSignals.map((signal) => {
        if (signal.includes("not available")) {
          return {
            what: signal,
            why: "The learner roster is required to build reliable round capacity and to avoid seat assignment drift.",
            fix: "Upload or repair learner names in Student Roster files, then refresh the schedule builder surface.",
            actionLabel: "Open Schedule",
          };
        }
        if (signal.includes("No learner assigned") || signal.includes("No student assigned") || signal.includes("unassigned")) {
          return {
            what: signal,
            why: "Capacity and learner counts are out of sync for this active round.",
            fix: "Re-open Schedule and continue auto-fill, then move learners manually only if needed.",
            actionLabel: "Open Schedule",
          };
        }
        if (signal.includes("Duplicate room mapping")) {
          return {
            what: signal,
            why: "Two schedule entries are targeting the same room, so learner/SP rotation visibility can become ambiguous.",
            fix: "Open Schedule and resolve room names so each room has one active slot per round.",
            actionLabel: "Edit Schedule",
          };
        }
        if (signal.includes("starts before") && signal.includes("completed")) {
          return {
            what: signal,
            why: "Encounter rounds are overlapping in the schedule timeline.",
            fix: "Update event session start/end inputs so rounds keep clean chronological order.",
            actionLabel: "Open Schedule",
          };
        }
        if (signal.includes("room plan needs review") || signal.includes("Room count is missing") || signal.includes("rotation rounds are missing")) {
          return {
            what: signal,
            why: "Room count and rotation inputs are foundational to learner and SP assignment integrity.",
            fix: "Complete the schedule builder setup fields and regenerate rounds as needed.",
            actionLabel: "Edit Schedule",
          };
        }
        if (signal.includes("without SP assignment") || signal.includes("room slot")) {
          return {
            what: signal,
            why: "This room slot cannot be staffed and should be resolved before live operations.",
            fix: "Staffing must cover every required slot or reduce active room count for that round.",
            actionLabel: "Open SP Staffing Center",
          };
        }

        return {
          what: signal,
          why: "This condition is blocking learner flow confidence for final schedule output.",
          fix: "Open schedule planning controls and confirm missing learner/room/round inputs before run-through.",
        };
      }),
    [learnerFlowMissingSignals]
  );
  const learnerFlowStatusReason = learnerAssignmentsIncomplete ? "Status reason: review each flagged issue" : "Status reason: no issues detected";
  const selectedRoundDayBlocks = useMemo(() => {
    if (!selectedRotationRound) return [] as RoundCompanionBlock[];
    const dayBlocks: RoundCompanionBlock[] = liveFlowBlocks
      .filter(
        (block) =>
          block.key.startsWith(`${selectedRotationRound.key}-`) &&
          block.tone !== "rotation" &&
          block.source !== "schedule_builder"
      )
      .map((block) => ({
        label: block.label,
        detail: block.detail,
        audience: getRoundCompanionAudience(block.label),
        durationMinutes: parseDurationMinutes(block.detail),
      }));

    scheduleBuilderPreviewDraft?.dayBlocks.forEach((block) => {
      const durationMinutes = parsePositiveInteger(block.durationMinutes, 0);
      if (
        !shouldShowScheduleBuilderBlockForRound(
          block,
          activeSelectedRotationRoundIndex,
          rotationRounds.length,
          selectedRotationRound
        )
      ) {
        return;
      }

      dayBlocks.push({
        label: block.label,
        detail: formatScheduleBuilderBlockDetail(block),
        audience: getScheduleBuilderBlockAudience(block),
        durationMinutes,
      });
    });

    const seen = new Set<string>();
    return dayBlocks.filter((block) => {
      const key = `${block.label}|${block.detail}|${block.audience.join(",")}`;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  }, [
    activeSelectedRotationRoundIndex,
    liveFlowBlocks,
    rotationRounds.length,
    scheduleBuilderPreviewDraft?.dayBlocks,
    selectedRotationRound,
  ]);
  const visibleSelectedRoundDayBlocks = useMemo(
    () =>
      selectedRoundDayBlocks.filter(
        (block) =>
          roundCompanionView === "operations" ||
          roundCompanionView === "announcements" ||
          block.audience.includes(roundCompanionView)
      ),
    [roundCompanionView, selectedRoundDayBlocks]
  );
  const visibleSelectedRoundScheduleBlocks = useMemo(() => {
    if (!selectedRotationRound) {
      return [] as Array<RoundCompanionBlock & { timeLabel: string }>;
    }

    const selectedRoundTiming = getNormalizedRotationRoundTiming(
      selectedRotationRound,
      getSameDateRotationRounds(selectedRotationRound, rotationRounds)
    );
    let cursorMinutes = selectedRoundTiming?.endMinutes ?? null;

    return visibleSelectedRoundDayBlocks.map((block) => {
      const durationMinutes = block.durationMinutes ?? parseDurationMinutes(block.detail);
      const timeLabel =
        cursorMinutes !== null && durationMinutes > 0
          ? formatMinuteRange(cursorMinutes, cursorMinutes + durationMinutes)
          : block.detail;
      if (cursorMinutes !== null && durationMinutes > 0) {
        cursorMinutes += durationMinutes;
      }
      return { ...block, timeLabel };
    });
  }, [rotationRounds, selectedRotationRound, visibleSelectedRoundDayBlocks]);
  const selectedRoundLearnerScheduleReady =
    selectedRoundScheduleRows.some(
      (row) =>
        !isRoomPlaceholderLabel(row.roomName) ||
        row.learnerLabels.length > 0 ||
        Boolean(row.caseLabel || row.stationLabel)
    ) || visibleSelectedRoundScheduleBlocks.length > 0;
	  const selectedRoundSpScheduleReady =
	    selectedRoundScheduleRows.some(
	      (row) => !isRoomPlaceholderLabel(row.roomName) || Boolean(row.sp || row.primarySpName || row.caseLabel || row.stationLabel)
	    ) || visibleSelectedRoundScheduleBlocks.length > 0;
  const selectedRoundOperationsScheduleReady =
    selectedRoundOperationsRows.length > 0 ||
    visibleSelectedRoundScheduleBlocks.length > 0;
  const selectedRoundPlanRoomEntries = useMemo(
    () =>
      selectedRoundScheduleRows.length
        ? selectedRoundScheduleRows.map((row) => ({
            roomName: row.roomName,
            sourceIndex: row.slotIndex,
          }))
        : selectedRoundRoomSlotEntries,
    [selectedRoundRoomSlotEntries, selectedRoundScheduleRows]
  );
  const selectedRoundExplicitSlotAssignments = useMemo(() => {
    if (!selectedRoundPlanRoomEntries.length || !selectedRotationRound) {
      return [] as Array<AssignmentRow | null>;
    }

    return selectedRoundPlanRoomEntries.map((_entry, index) => {
      const scheduledRow = selectedRoundScheduleRows[index];
      return scheduledRow?.assignment || null;
    });
  }, [selectedRoundPlanRoomEntries, selectedRoundScheduleRows, selectedRotationRound]);
  const selectedRoundRoomAssignmentPlan = useMemo(
    () =>
      buildRoomSlotAssignmentPlan(
        selectedRoundPlanRoomEntries,
        selectedRoundExplicitSlotAssignments,
        confirmedAssignments,
        roomNamingContext
      ),
    [confirmedAssignments, roomNamingContext, selectedRoundExplicitSlotAssignments, selectedRoundPlanRoomEntries]
  );
  const selectedRoundCoverageTarget = Math.max(selectedRoundActiveStationCount || selectedRoundRoomCount, needed);
  const selectedRoundCoverageShortage = Math.max(selectedRoundCoverageTarget - confirmedAssignments.length, 0);
	  const selectedRoundTacticalBoardRows = useMemo(
	    () => {
	      if (!selectedRotationRound) return [] as Array<RoundRoomBoardRow>;
	      if (selectedRoundOperationsRows.length) {
	        return selectedRoundOperationsRows.map((row) => ({
	          ...row,
	          key: `${row.key}-board`,
	          isAutoMapped: false,
	          isExplicitMapped: Boolean(row.primarySpName),
	          mappingState: row.stationStatus === "inactive" ? "Inactive" : "",
	          flags: row.stationStatus !== "active"
	            ? row.flags.filter((flag) => !["Missing SP", "No learner assigned", "No student assigned"].includes(asText(flag)))
	            : row.flags,
	        })) satisfies Array<RoundRoomBoardRow>;
	      }

	      const roomSlotEntries = selectedRoundRoomSlotEntries.length
	        ? selectedRoundRoomSlotEntries
        : selectedRoundScheduleRows.map((row, sourceIndex) => ({
            roomName: row.roomName,
            sourceIndex,
          }));
      const rowsByRoomNumber = new Map<number, RoundRoomRow>();
      const rowsByRoomName = new Map<string, RoundRoomRow>();

      selectedRoundScheduleRows.forEach((row) => {
        const roomNumber = getRoomDisplayNumber(row.roomName);
        if (roomNumber !== null && !rowsByRoomNumber.has(roomNumber)) {
          rowsByRoomNumber.set(roomNumber, row);
        }
        rowsByRoomName.set(asText(row.roomName).toLowerCase(), row);
      });

      return roomSlotEntries.map((entry, index) => {
        const roomNumber = getRoomDisplayNumber(entry.roomName);
        const existingRow =
          (roomNumber !== null ? rowsByRoomNumber.get(roomNumber) : null) ||
          rowsByRoomName.get(asText(entry.roomName).toLowerCase()) ||
          null;
        const assignment =
          selectedRoundRoomAssignmentPlan.assignments[index]?.assignment || null;
        const isAutoMapped = Boolean(selectedRoundRoomAssignmentPlan.assignments[index]?.isAutoMapped);
        const isExplicitMapped = Boolean(selectedRoundRoomAssignmentPlan.assignments[index]?.isExplicit);
        const sp = assignment?.sp_id ? spsById.get(assignment.sp_id) || null : null;
        const learnerLabels = existingRow?.learnerLabels.length
          ? existingRow.learnerLabels
          : getResolvedRoundLearnerLabels({
              learnerRoster: scheduleBuilderLearnerNames,
              roomCapacity: scheduleBuilderRoomCapacity,
              roundIndex: Math.max(selectedResolvedRoundNumber - 1, 0),
              slotIndex: index,
              roomSlotCount: Math.max(roomSlotEntries.length, 1),
              activeCaseCount: resolvedScheduleMatrixCaseCount,
              isMultiCaseMode: resolvedScheduleMatrixCaseCount > 1,
              isVirtualEvent: isScheduleMatrixVirtual,
            });
        const hasRoomIdentity = roomNumber !== null || Boolean(entry.roomName);
        const rowTimingExists = Boolean(
          asText(selectedRotationRound.start_time) ||
            asText(selectedRotationRound.end_time)
        );
        const isDisplayMapped =
          hasRoomIdentity && (Boolean(assignment) || learnerLabels.length > 0 || rowTimingExists);
        const flags = Array.from(
          new Set(
            [
              ...(existingRow?.flags || []).filter((flag) => flag !== "Missing SP" && flag !== "Unassigned"),
              assignment && !sp ? "Missing SP profile" : "",
              staffingRelevant && !assignment
                ? selectedRoundCoverageShortage > 0
                  ? "Missing SP"
                  : !isDisplayMapped
                    ? "Needs room mapping"
                    : "Auto-mapped"
                : null,
              staffingRelevant && assignment && !isDisplayMapped ? "Needs room mapping" : "",
            ].filter((flag): flag is string => Boolean(flag))
          )
        );

        return {
          key: `${selectedRotationRound.key}-room-slot-${entry.sourceIndex}-${index}`,
          slotIndex: existingRow?.slotIndex ?? index,
          roomName: entry.roomName,
          location: existingRow?.location || asText(event?.location),
          learnerLabels,
          learnerCountFallback: existingRow?.learnerCountFallback || 0,
          snapshotLearnerPlacementLocked: Boolean(existingRow?.snapshotLearnerPlacementLocked),
	          assignment,
	          sp,
	          primarySpName: existingRow?.primarySpName || (sp ? getFullName(sp) : ""),
	          backupSpName: existingRow?.backupSpName || "",
          caseLabel: existingRow?.caseLabel || selectedRoundCaseLabel,
          roleId: existingRow?.roleId || "",
          roleLabel: existingRow?.roleLabel || "",
          notes: existingRow?.notes || "",
          stationLabel: existingRow?.stationLabel || selectedRoundStationLabel,
          isAutoMapped,
          isExplicitMapped,
          mappingState: isDisplayMapped ? "" : "Needs room mapping",
          flags,
        } satisfies RoundRoomBoardRow;
      });
    },
    [
      event?.location,
      isScheduleMatrixVirtual,
      resolvedScheduleMatrixCaseCount,
      selectedResolvedRoundNumber,
      selectedRoundCoverageShortage,
      scheduleBuilderLearnerNames,
      scheduleBuilderRoomCapacity,
      selectedRotationRound,
      selectedRoundRoomAssignmentPlan.assignments,
	      selectedRoundCaseLabel,
	      selectedRoundOperationsRows,
	      selectedRoundRoomSlotEntries,
      selectedRoundScheduleRows,
      selectedRoundStationLabel,
      spsById,
      staffingRelevant,
    ]
  );
  const selectedRoundMappedRoomCount = useMemo(
    () => {
      const backupSlotIndexes = new Set((selectedRoundBackupScheduleTruth || []).map((station) => station.roomSlotIndex));
      return selectedRoundTacticalBoardRows.filter((row) => {
        if (backupSlotIndexes.has(row.slotIndex)) return false;
        const rowTimingExists = Boolean(
          asText(selectedRotationRound?.start_time) ||
            asText(selectedRotationRound?.end_time)
        );
        const rowHasLearners = Boolean(row.learnerLabels.length);
        const rowHasRoomNumber = getRoomDisplayNumber(row.roomName) !== null || Boolean(row.roomName);
        const rowHasSp = Boolean(row.assignment);
        return rowHasRoomNumber && (rowHasSp || rowHasLearners || rowTimingExists) && row.mappingState !== "Needs room mapping";
      }).length;
    },
    [selectedRoundTacticalBoardRows, selectedRotationRound, selectedRoundBackupScheduleTruth]
  );
  const selectedRoundRoomMappingGap = Math.max((selectedRoundActiveStationCount || selectedRoundRoomCount) - selectedRoundMappedRoomCount, 0);
  const selectedRoundRoomsMapped = Math.max((selectedRoundActiveStationCount || selectedRoundRoomCount) - selectedRoundRoomMappingGap, 0);
  const selectedRoundOperationsFlags = useMemo(() => {
    const flags = new Set<string>();
    const backupSlotIndexes = new Set((selectedRoundBackupScheduleTruth || []).map((station) => station.roomSlotIndex));

    if (!selectedRoundScheduleRows.length) flags.add("No room schedule");
    selectedRoundTacticalBoardRows.forEach((row) => {
      if (backupSlotIndexes.has(row.slotIndex)) return;
      row.flags.forEach((flag) => {
        const normalizedFlag = asText(flag);
        if (!normalizedFlag) return;
        if (normalizedFlag === "Missing SP" && selectedRoundCoverageShortage <= 0) return;
        flags.add(normalizedFlag);
      });
    });
    if (selectedRoundCoverageShortage > 0) {
      flags.add(`${selectedRoundCoverageShortage} room${selectedRoundCoverageShortage === 1 ? "" : "s"} still needs SP`);
    } else if (selectedRoundRoomMappingGap > 0) {
      flags.add(`Needs room mapping for ${selectedRoundRoomMappingGap} room${selectedRoundRoomMappingGap === 1 ? "" : "s"}`);
    }
    if (selectedRoundEmptySlots !== null && selectedRoundEmptySlots > 0) {
      flags.add(`${selectedRoundEmptySlots} empty learner slot${selectedRoundEmptySlots === 1 ? "" : "s"}`);
    }
    return Array.from(flags);
  }, [
    selectedRoundCoverageShortage,
    selectedRoundEmptySlots,
    selectedRoundRoomMappingGap,
    selectedRoundScheduleRows,
    selectedRoundTacticalBoardRows,
    selectedRoundBackupScheduleTruth,
  ]);
  const announcementCueTextOverrides = useMemo(() => {
    const cueTextById = new Map<string, string>();
    announcementScheduleConfig.cues.forEach((cue) => {
      const cueText = asText(cue.announcementText);
      if (cueText) {
        cueTextById.set(cue.id, cueText);
      }
    });
    return cueTextById;
  }, [announcementScheduleConfig]);
  const buildAnnouncementTimelineForRound = useCallback(
    (round: RotationRound | null | undefined, roundIndex: number) => {
      if (!round) return [] as AnnouncementCueTimelineEntry[];

      const selectedRoundTiming = getNormalizedRotationRoundTiming(
        round,
        getSameDateRotationRounds(round, rotationRounds)
      );
      const startMinutes = selectedRoundTiming?.startMinutes ?? null;
      const endMinutes = selectedRoundTiming?.endMinutes ?? null;
      if (startMinutes === null || endMinutes === null || endMinutes <= startMinutes) {
        return [] as AnnouncementCueTimelineEntry[];
      }

      const roundNumber = roundIndex + 1;
      const nextRound = activeDateRotationRounds[roundIndex + 1] || null;
      const nextRoundTiming = nextRound
        ? getNormalizedRotationRoundTiming(nextRound, getSameDateRotationRounds(nextRound, rotationRounds))
        : null;
      const nextRoundStartMinutes =
        nextRoundTiming?.startMinutes !== null && nextRoundTiming?.startMinutes !== undefined
          ? nextRoundTiming.startMinutes
          : null;
      const roundWindowEndMinutes =
        typeof nextRoundStartMinutes === "number" && nextRoundStartMinutes > startMinutes
          ? nextRoundStartMinutes
          : endMinutes;
      const selectedRoundKeyPrefix = `${asText(round.key)}-`;
      const roundFlowBlocks = (Array.isArray(liveFlowBlocks) ? liveFlowBlocks : [])
        .filter((block) => asText(block?.key).startsWith(selectedRoundKeyPrefix))
        .sort((a, b) => a.startMinutes - b.startMinutes || a.endMinutes - b.endMinutes || a.label.localeCompare(b.label));
      const supportingWindowBlocks = (Array.isArray(liveFlowBlocks) ? liveFlowBlocks : [])
        .filter((block) => {
          if (asText(block?.key).startsWith(selectedRoundKeyPrefix)) return false;
          if (block.startMinutes < startMinutes || block.startMinutes >= roundWindowEndMinutes) return false;
          return isAnnouncementBlockMatch(block.label, /lunch|break|debrief|wrap|close|end of event/);
        })
        .sort((a, b) => a.startMinutes - b.startMinutes || a.endMinutes - b.endMinutes || a.label.localeCompare(b.label));
      const configuredEncounterMinutes = Math.max(parsePositiveInteger(scheduleBuilderPreviewDraft?.encounterMinutes, 0), 20);
      const configuredChecklistMinutes = Math.max(parsePositiveInteger(scheduleBuilderPreviewDraft?.checklistMinutes, 0), 10);
      const configuredFeedbackMinutes = Math.max(parsePositiveInteger(scheduleBuilderPreviewDraft?.feedbackMinutes, 0), 5);
      const configuredTransitionMinutes = Math.max(parsePositiveInteger(scheduleBuilderPreviewDraft?.transitionMinutes, 0), 5);
      const configuredPrebriefMinutes = Math.max(
        parsePositiveInteger(scheduleBuilderPreviewDraft?.studentPrebriefMinutes, 0),
        parsePositiveInteger(scheduleBuilderPreviewDraft?.spPrebriefMinutes, 0),
        parsePositiveInteger(scheduleBuilderPreviewDraft?.facultyPrebriefMinutes, 0),
        15
      );
      const encounterBlock = roundFlowBlocks.find((block) =>
        isAnnouncementBlockMatch(block.label, /encounter|rotation|case/)
      );
      const checklistBlock = roundFlowBlocks.find((block) =>
        isAnnouncementBlockMatch(block.label, /checklist|soap/)
      );
      const feedbackBlock = roundFlowBlocks.find((block) =>
        isAnnouncementBlockMatch(block.label, /feedback/)
      );
      const transitionBlock = roundFlowBlocks.find((block) =>
        isAnnouncementBlockMatch(block.label, /transition|turnaround|turnover|reset/)
      );
      const prebriefBlock =
        roundIndex === 0
          ? (Array.isArray(liveFlowBlocks) ? liveFlowBlocks : [])
              .filter((block) => {
                if (!isAnnouncementBlockMatch(block.label, /pre[\s-]?brief|orientation|briefing/)) return false;
                return block.endMinutes <= startMinutes;
              })
              .sort((a, b) => b.startMinutes - a.startMinutes)[0] || null
          : null;
      const encounterStartMinutes = encounterBlock?.startMinutes ?? startMinutes;
      const checklistStartMinutes = checklistBlock?.startMinutes ?? Math.min(roundWindowEndMinutes, encounterStartMinutes + configuredEncounterMinutes);
      const feedbackStartMinutes = feedbackBlock?.startMinutes ?? Math.min(roundWindowEndMinutes, checklistStartMinutes + configuredChecklistMinutes);
      const transitionStartMinutes = transitionBlock?.startMinutes ?? Math.min(roundWindowEndMinutes, feedbackStartMinutes + configuredFeedbackMinutes);
      const cueEntries: AnnouncementCueTimelineEntry[] = [];
      const overrideAnnouncementText = (
        cueKind: AnnouncementCueTimelineEntry["cueKind"],
        fallbackText: string
      ) => {
        const overrideIdsByKind: Record<AnnouncementCueTimelineEntry["cueKind"], string[]> = {
          prebrief: ["prebrief-reminder", "sp-prepare"],
          encounter_start: ["encounter-start", "begin-encounter"],
          checklist_start: ["checklist-start"],
          feedback_start: ["feedback-start", "encounter-over-feedback"],
          transition: ["transition-start", "leave-meeting"],
          lunch: ["lunch-break", "break-start"],
          break: ["break-start"],
          wrap_up: ["wrap-up", "event-close"],
        };
        for (const overrideId of overrideIdsByKind[cueKind]) {
          const overrideText = announcementCueTextOverrides.get(overrideId);
          if (overrideText) return overrideText;
        }
        return fallbackText;
      };
      const pushCue = (
        cueKind: AnnouncementCueTimelineEntry["cueKind"],
        timeMinutes: number | null | undefined,
        blockLabel?: string,
        detail?: string
      ) => {
        if (typeof timeMinutes !== "number" || !Number.isFinite(timeMinutes)) return;
        const cueLabel = getAnnouncementCueLabel(cueKind, blockLabel);
        const audienceLabel = getAnnouncementCueAudienceLabel(cueKind);
        const announcementText = overrideAnnouncementText(
          cueKind,
          buildDefaultAnnouncementText(cueKind, roundNumber, blockLabel)
        );
        cueEntries.push({
          key: `${asText(round.key)}:${cueKind}:${Math.round(timeMinutes)}`,
          cueId: cueKind,
          cueKind,
          roundKey: asText(round.key),
          roundNumber,
          timeMinutes,
          timeLabel: formatMinutesAsClockLabel(timeMinutes),
          phaseLabel: cueLabel,
          audienceLabel,
          blockLabel: blockLabel || cueLabel,
          cueTimingLabel: getAnnouncementCueTimingLabel(cueKind, roundNumber),
          announcement: announcementText,
          detail,
        });
      };

      if (roundIndex === 0 && configuredPrebriefMinutes > 0) {
        const prebriefStartMinutes = prebriefBlock?.startMinutes ?? encounterStartMinutes - configuredPrebriefMinutes;
        pushCue(
          "prebrief",
          prebriefStartMinutes,
          prebriefBlock?.label || "Prebrief",
          `${getAnnouncementCueAudienceLabel("prebrief")} · ${formatLiveFlowDurationLabel(
            Math.max(prebriefBlock ? prebriefBlock.endMinutes - prebriefBlock.startMinutes : configuredPrebriefMinutes, 1)
          )}`
        );
      }

      pushCue(
        "encounter_start",
        encounterStartMinutes,
        encounterBlock?.label || "Encounter",
        `${getAnnouncementCueAudienceLabel("encounter_start")} · ${formatLiveFlowDurationLabel(configuredEncounterMinutes)}`
      );
      if (checklistStartMinutes < roundWindowEndMinutes + 1) {
        pushCue(
          "checklist_start",
          checklistStartMinutes,
          checklistBlock?.label || "Checklist",
          `${getAnnouncementCueAudienceLabel("checklist_start")} · ${formatLiveFlowDurationLabel(configuredChecklistMinutes)}`
        );
      }
      if (feedbackStartMinutes < roundWindowEndMinutes + 1) {
        pushCue(
          "feedback_start",
          feedbackStartMinutes,
          feedbackBlock?.label || "Feedback",
          `${getAnnouncementCueAudienceLabel("feedback_start")} · ${formatLiveFlowDurationLabel(configuredFeedbackMinutes)}`
        );
      }
      if (transitionStartMinutes < roundWindowEndMinutes + 1) {
        pushCue(
          "transition",
          transitionStartMinutes,
          transitionBlock?.label || "Transition",
          `${getAnnouncementCueAudienceLabel("transition")} · ${formatLiveFlowDurationLabel(configuredTransitionMinutes)}`
        );
      }

      supportingWindowBlocks.forEach((block) => {
        const cueKind = isAnnouncementBlockMatch(block.label, /lunch/)
          ? "lunch"
          : isAnnouncementBlockMatch(block.label, /debrief|wrap|close|end of event/)
            ? "wrap_up"
            : "break";
        pushCue(
          cueKind,
          block.startMinutes,
          block.label,
          `${getAnnouncementCueAudienceLabel(cueKind)} · ${formatLiveFlowDurationLabel(
            Math.max(block.endMinutes - block.startMinutes, 1)
          )}`
        );
      });

      return cueEntries
        .sort((a, b) => a.timeMinutes - b.timeMinutes || a.phaseLabel.localeCompare(b.phaseLabel))
        .filter((entry, index, entries) => index === 0 || entry.key !== entries[index - 1]?.key);
    },
    [
      activeDateRotationRounds,
      announcementCueTextOverrides,
      liveFlowBlocks,
      rotationRounds,
      scheduleBuilderPreviewDraft?.checklistMinutes,
      scheduleBuilderPreviewDraft?.encounterMinutes,
      scheduleBuilderPreviewDraft?.facultyPrebriefMinutes,
      scheduleBuilderPreviewDraft?.feedbackMinutes,
      scheduleBuilderPreviewDraft?.spPrebriefMinutes,
      scheduleBuilderPreviewDraft?.studentPrebriefMinutes,
      scheduleBuilderPreviewDraft?.transitionMinutes,
    ]
  );
  const announcementCueTimeline = useMemo(
    () =>
      activeDateRotationRounds.flatMap((round, index) =>
        buildAnnouncementTimelineForRound(round, index)
      ),
    [activeDateRotationRounds, buildAnnouncementTimelineForRound]
  );
  const selectedRoundAnnouncementTimeline = useMemo(
    () =>
      selectedRotationRound
        ? buildAnnouncementTimelineForRound(selectedRotationRound, activeSelectedRotationRoundIndex)
        : ([] as AnnouncementCueTimelineEntry[]),
    [activeSelectedRotationRoundIndex, buildAnnouncementTimelineForRound, selectedRotationRound]
  );
  const selectedRoundAnnouncementExportRows = useMemo(
    () =>
      selectedRoundAnnouncementTimeline.map((entry) => ({
        ...entry,
        message: entry.announcement,
      })),
    [selectedRoundAnnouncementTimeline]
  );
  const selectedRoundAnnouncementExportText = useMemo(() => {
    const eventName = event?.name || "Untitled Event";
    const eventDate = selectedRotationRound?.session_date
      ? formatHumanDate(selectedRotationRound.session_date, importedYearHint) || selectedRotationRound.session_date
      : event?.date_text || "Date TBD";
    const timeWindow =
      selectedRotationRound?.start_time || selectedRotationRound?.end_time
        ? `${formatDisplayTime(selectedRotationRound.start_time)}${selectedRotationRound.end_time ? ` - ${formatDisplayTime(selectedRotationRound.end_time)}` : ""}`
        : summaryTimeLabel || "Time TBD";
    const selectedRoundLabel = selectedRotationRound
      ? `Round ${activeSelectedRotationRoundIndex + 1}`
      : "Selected timeline";
    const lines = [
      "ANNOUNCEMENT SCHEDULE",
      eventName,
      `Date: ${eventDate}`,
      `Time Window: ${timeWindow}`,
      `Scope: ${selectedRoundLabel}`,
      "",
      ...selectedRoundAnnouncementExportRows.flatMap((entry, index) => [
        `${index + 1}. ${entry.timeLabel} - ${entry.phaseLabel}`,
        `Audience: ${entry.audienceLabel}`,
        entry.detail ? `Context: ${entry.detail}` : "Context: Operational announcement",
        `Message: ${entry.message}`,
        "",
      ]),
      "OPERATOR NOTES",
      "--------------",
      "",
    ];
    return lines.join("\n");
  }, [
    activeSelectedRotationRoundIndex,
    event?.date_text,
    event?.name,
    importedYearHint,
    selectedRotationRound,
    selectedRoundAnnouncementExportRows,
    summaryTimeLabel,
  ]);
  const announcementCueEntries = useMemo(() => {
    const nowMs = countdownNowMs ?? Date.now();
    return announcementCueTimeline.map((entry) => {
      const persistedState = announcementCueStateMap[entry.key];
      const persistedStatus = persistedState?.status;
      const snoozedUntilMs = persistedState?.snoozedUntil ? new Date(persistedState.snoozedUntil).getTime() : 0;
      const isSnoozed = snoozedUntilMs > nowMs;
      const hasTriggeredDueState = Boolean(announcementDueCueKeys[entry.key]);
      const minutesUntilCue = entry.timeMinutes - simulatedLiveMinutes;
      const shouldActivateDue =
        announcementLiveModeActive &&
        !persistedStatus &&
        !isSnoozed &&
        minutesUntilCue <= 0 &&
        minutesUntilCue >= -1;
      const status =
        persistedStatus === "delivered"
          ? "Delivered"
          : persistedStatus === "skipped"
            ? "Skipped"
            : isSnoozed
              ? "Snoozed"
              : hasTriggeredDueState || shouldActivateDue
              ? "Due now"
              : "Upcoming";
      const timingDetail =
        status === "Due now"
          ? "Announcement Due"
          : status === "Snoozed"
            ? `Snoozed until ${new Date(snoozedUntilMs).toLocaleTimeString([], { hour: "numeric", minute: "2-digit" })}`
            : minutesUntilCue < -1
              ? "Past cue - not auto-armed on load"
              : formatCueCountdown(Math.max(minutesUntilCue, 0));
      return {
        ...entry,
        announcementText: entry.announcement,
        persistentStatus: persistedStatus,
        status,
        timingDetail,
        minutesUntilCue,
        isSnoozed,
        hasTriggeredDueState,
        shouldActivateDue,
      };
    });
  }, [
    announcementCueStateMap,
    announcementCueTimeline,
    announcementDueCueKeys,
    announcementLiveModeActive,
    countdownNowMs,
    simulatedLiveMinutes,
  ]);
  const announcementCueEntriesByKey = useMemo(
    () => new Map(announcementCueEntries.map((entry) => [entry.key, entry] as const)),
    [announcementCueEntries]
  );
  const selectedRoundAnnouncementCueEntries = useMemo(
    () =>
      selectedRoundAnnouncementTimeline
        .map((entry) => announcementCueEntriesByKey.get(entry.key) || null)
        .filter((entry): entry is NonNullable<typeof entry> => Boolean(entry)),
    [announcementCueEntriesByKey, selectedRoundAnnouncementTimeline]
  );
  const liveAttendanceCurrentAnnouncementCue = useMemo(
    () =>
      selectedRoundAnnouncementCueEntries.find((entry) => entry.status === "Due now") ||
      selectedRoundAnnouncementCueEntries.find((entry) => entry.status === "Upcoming") ||
      selectedRoundAnnouncementCueEntries.find((entry) => entry.status === "Snoozed") ||
      selectedRoundAnnouncementCueEntries.find((entry) => entry.status !== "Delivered" && entry.status !== "Skipped") ||
      selectedRoundAnnouncementCueEntries[0] ||
      null,
    [selectedRoundAnnouncementCueEntries]
  );
