  async function handleHideRelatedMatch(eventIdToHide: string) {
    if (!id || !event) return;
    const currentHidden = new Set(parseRelatedEventsHiddenIds(parsedEventMetadata.training.related_events_hidden));
    if (currentHidden.has(eventIdToHide)) return;

    setRemovingRelatedMatchId(eventIdToHide);
    setEventSaveError("");

    const nextHidden = Array.from(new Set([...currentHidden, eventIdToHide])).sort().join(", ");
    try {
      await persistTrainingMetadataFields(
        { related_events_hidden: nextHidden },
        "Related match removed from embedded view."
      );
      setRelatedOperationalEvents((current) =>
        current.filter((node) => node.id !== eventIdToHide)
      );
      setShowRelatedMatchesModal(false);
    } catch (error) {
      setEventSaveError(
        error instanceof Error ? error.message : "Could not remove related match."
      );
    } finally {
      setRemovingRelatedMatchId("");
    }
  }

  async function handleConfirmRelatedMatch(eventIdToConfirm: string) {
    if (!id || !event) return;
    const currentConfirmed = new Set(
      parseRelatedEventsConfirmedIds(parsedEventMetadata.training.related_events_confirmed)
    );
    if (currentConfirmed.has(eventIdToConfirm)) return;

    setConfirmingRelatedMatchId(eventIdToConfirm);
    setEventSaveError("");

    const nextConfirmed = Array.from(new Set([...currentConfirmed, eventIdToConfirm])).sort().join(", ");
    try {
      await persistTrainingMetadataFields(
        { related_events_confirmed: nextConfirmed },
        "Related match confirmed."
      );
      setRelatedOperationalEvents((current) =>
        current.map((node) =>
          node.id === eventIdToConfirm
            ? {
                ...node,
                isConfirmed: true,
              }
            : node
        )
      );
    } catch (error) {
      setEventSaveError(
        error instanceof Error ? error.message : "Could not confirm related match."
      );
    } finally {
      setConfirmingRelatedMatchId("");
    }
  }

  async function handleConfirmAllExactMatches() {
    if (!id || !event) return;
    const exactMatches = relatedOperationalEvents.filter(
      (node) =>
        (node.isConfirmed === true ||
          node.match_confidence === "exact_course" ||
          node.match_confidence === "title_family" ||
          node.match_confidence === "source_batch") &&
        !parseRelatedEventsConfirmedIds(parsedEventMetadata.training.related_events_confirmed).has(node.id)
    );
    if (exactMatches.length === 0) return;

    const nextConfirmed = new Set<string>([
      ...parseRelatedEventsConfirmedIds(parsedEventMetadata.training.related_events_confirmed),
      ...exactMatches.map((node) => node.id),
    ]);
    setConfirmingAllMatches(true);
    setEventSaveError("");

    try {
      await persistTrainingMetadataFields(
        { related_events_confirmed: Array.from(nextConfirmed).sort().join(", ") },
        "Exact-course related matches confirmed."
      );
      setRelatedOperationalEvents((current) =>
        current.map((node) => ({
          ...node,
          isConfirmed: node.isConfirmed || nextConfirmed.has(node.id),
        }))
      );
    } catch (error) {
      setEventSaveError(
        error instanceof Error ? error.message : "Could not confirm all exact matches."
      );
    } finally {
      setConfirmingAllMatches(false);
    }
  }

  const exactMatchRelatedEvents = useMemo(
    () =>
      relatedOperationalEvents.filter(
        (node) =>
          node.match_confidence === "exact_course" ||
          node.match_confidence === "title_family" ||
          node.match_confidence === "source_batch" ||
          node.isConfirmed
      ),
    [relatedOperationalEvents]
  );
  const eventFamilyQueryKey = useMemo(
    () =>
      asText(searchParams.get("family")) ||
      getDefaultRelatedEventKeyword(event?.name) ||
      normalizeRelatedEventFamilyTitle(event?.name).replace(/\s+/g, "-"),
    [event?.name, searchParams]
  );
  const relatedEventDateOptions = useMemo(() => {
    if (!id || !event) return [] as Array<{ id: string; dateText: string; statusLabel: string; statusDetail: string }>;
    const currentKeyword = getDefaultRelatedEventKeyword(event.name).toLowerCase();
    const currentNormalizedTitle = normalizeRelatedEventFamilyTitle(event.name);
    const optionMap = new Map<string, { id: string; dateText: string; statusLabel: string; statusDetail: string; sortKey: number }>();
    const addOption = (args: {
      id: string;
      dateText?: string | null;
      status?: string | null;
      location?: string | null;
      trainingMetadata?: Partial<TrainingEventMetadata> | null;
      statusLabel: string;
    }) => {
      const dateText = asText(args.dateText) || normalizeLooseDateToIso(args.trainingMetadata?.event_session_date) || "";
      optionMap.set(args.id, {
        id: args.id,
        dateText,
        statusLabel: args.statusLabel,
        statusDetail: [args.statusLabel, asText(args.status) || "", asText(args.location) || ""].filter(Boolean).join(" · "),
        sortKey: dateText ? new Date(dateText).getTime() : Number.MAX_SAFE_INTEGER,
      });
    };
    addOption({
      id,
      dateText: event.date_text,
      status: event.status,
      location: event.location,
      trainingMetadata,
      statusLabel: scheduleCompleted
        ? "Schedule complete"
        : staffingRelevant && hasPrimaryStaffingShortage
          ? "Needs staffing"
          : scheduleInProgress
            ? "Draft schedule"
            : getRelatedEventScheduleStatusLabel({ status: event.status, trainingMetadata }),
    });
    relatedOperationalEvents.forEach((node) => {
      if (!node.id || node.kind === "training") return;
      const confidenceMatch =
        node.match_confidence === "exact_course" ||
        node.match_confidence === "title_family" ||
        node.match_confidence === "source_batch" ||
        node.isConfirmed;
      if (!confidenceMatch) return;
      const nodeKeyword = getDefaultRelatedEventKeyword(node.name).toLowerCase();
      const nodeNormalizedTitle = normalizeRelatedEventFamilyTitle(node.name);
      const sameFamily =
        Boolean(currentNormalizedTitle && nodeNormalizedTitle && currentNormalizedTitle === nodeNormalizedTitle) ||
        Boolean(currentKeyword && nodeKeyword && currentKeyword === nodeKeyword);
      if (!sameFamily) return;
      addOption({
        id: node.id,
        dateText: node.date_text,
        status: node.status,
        location: node.location,
        trainingMetadata: node.trainingMetadata || null,
        statusLabel: getRelatedEventScheduleStatusLabel({
          status: node.status,
          trainingMetadata: node.trainingMetadata || null,
        }),
      });
    });
    return Array.from(optionMap.values()).sort((a, b) => a.sortKey - b.sortKey || a.dateText.localeCompare(b.dateText));
  }, [
    event,
    hasPrimaryStaffingShortage,
    id,
    relatedOperationalEvents,
    scheduleCompleted,
    scheduleInProgress,
    staffingRelevant,
    trainingMetadata,
  ]);
