  const activeSavedCommunicationTemplates = emailTemplateSource === "database"
    ? emailTemplates.filter((template) => template.is_active !== false)
    : [];
  const knownSpEmailSet = new Set(
    mergeEmailAddressLists(
      sps.map((sp) => getEmail(sp)).filter(Boolean),
      assignedBccEmails,
      hiringPollBccEmails,
      confirmationBccEmails,
      availabilityPollClosedBccEmails,
      cancellationEmailBccEmails,
      payrollEmailBccEmails
    )
  );

  function fallbackCardMatchesTemplate(card: FallbackCommunicationCard, template: EmailTemplateRecord) {
    const templateName = normalizeEmailTemplateMatchValue(template.name);
    const templateCategory = normalizeEmailTemplateMatchValue(template.category);
    const cardCategory = normalizeEmailTemplateMatchValue(card.templateCategory);
    const candidateNames = [card.title, ...card.templateNames].map(normalizeEmailTemplateMatchValue);
    return (
      candidateNames.includes(templateName) ||
      (templateCategory === cardCategory && candidateNames.includes(templateName))
    );
  }

  function getFallbackStatusText(statusCode: CommunicationTemplateStatus): "Needs info" | "Ready to draft" | "Drafted" | "Sent" | "Completed" | "Not needed" {
    return statusCode === "needs_info"
      ? "Needs info"
      : statusCode === "ready_to_draft"
        ? "Ready to draft"
        : statusCode === "drafted"
          ? "Drafted"
          : statusCode === "sent"
            ? "Sent"
            : statusCode === "completed"
              ? "Completed"
              : "Not needed";
  }

  function getCommunicationTemplateSpEmails(template: EmailTemplateRecord) {
    const signal = `${template.category || ""} ${template.name || ""}`.toLowerCase();
    if (signal.includes("poll closed") || signal.includes("availability poll closed")) return availabilityPollClosedBccEmails;
    if (signal.includes("availability poll") || signal.includes("hiring")) return hiringPollBccEmails;
    if (signal.includes("confirmation") || signal.includes("hire")) return confirmationBccEmails.length ? confirmationBccEmails : assignedBccEmails;
    if (signal.includes("cancel")) return cancellationEmailBccEmails;
    if (signal.includes("payroll") || signal.includes("wrap")) return payrollEmailBccEmails;
    if (signal.includes("faculty")) return [];
    return assignedBccEmails;
  }

  function getSavedCommunicationTemplateDraft(template: EmailTemplateRecord) {
    const spTemplateRecipients = getCommunicationTemplateSpEmails(template);
    const context = {
      ...emailTemplateContext,
      spEmails: spTemplateRecipients.join(","),
      Event: emailTemplateContext.eventName,
      Date: emailTemplateContext.eventDate,
      Time: emailTemplateContext.eventTime,
      "Zoom Link": emailTemplateContext.trainingZoomLink,
      "Event Zoom": emailTemplateContext.eventZoomLink,
      "Event Zoom Link": emailTemplateContext.eventZoomLink,
      "Training Zoom": emailTemplateContext.trainingZoomLink,
      senderEmail: emailTemplateContext.senderEmail,
      senderName: emailTemplateContext.senderName,
      faculty: emailTemplateContext.faculty,
    };
    const rendered = renderEmailTemplate(template, context);
    const spSourceByField = {
      to: emailTemplateMentionsSpRecipients(template.default_to),
      cc: emailTemplateMentionsSpRecipients(template.default_cc),
      bcc: emailTemplateMentionsSpRecipients(template.default_bcc),
    };
    const moveSpRecipientsToBcc = (values: string[], sourceMentionsSp: boolean) => {
      const kept: string[] = [];
      const moved: string[] = [];
      values.forEach((email) => {
        const normalized = normalizeEmail(email);
        if (sourceMentionsSp || knownSpEmailSet.has(normalized)) {
          moved.push(normalized);
        } else {
          kept.push(normalized);
        }
      });
      return { kept, moved };
    };
    const toPartition = moveSpRecipientsToBcc(splitEmailAddressList(rendered.to), spSourceByField.to);
    const ccPartition = moveSpRecipientsToBcc(splitEmailAddressList(rendered.cc), spSourceByField.cc);
    const bccEmails = mergeEmailAddressLists(
      splitEmailAddressList(rendered.bcc),
      toPartition.moved,
      ccPartition.moved
    );
    const href = buildMailtoHref({
      to: toPartition.kept.join(","),
      cc: ccPartition.kept,
      bcc: bccEmails,
      subject: rendered.subject,
      body: rendered.body,
    });
    const needsSpRecipients =
      spSourceByField.to ||
      spSourceByField.cc ||
      spSourceByField.bcc ||
      /\b(sp|standardized patient)\b/i.test(`${template.category || ""} ${template.name || ""}`);
    const hasAnyRecipient = Boolean(toPartition.kept.length || ccPartition.kept.length || bccEmails.length);
    const missingReason = needsSpRecipients && !spTemplateRecipients.length
      ? "SP recipients are not available for this saved template."
      : !hasAnyRecipient
        ? "Default recipients did not resolve from the current event."
        : "";
    return {
      href,
      ready: !missingReason,
      statusDetail: missingReason || "Draft uses the saved subject, body, and default recipients from Settings.",
      to: toPartition.kept,
      cc: ccPartition.kept,
      bcc: bccEmails,
      fromLabel: rendered.fromLabel,
    };
  }

  function handleDraftSavedCommunicationTemplate(template: EmailTemplateRecord) {
    const draft = getSavedCommunicationTemplateDraft(template);
    if (!draft.ready) {
      setEventSaveError(draft.statusDetail);
      return;
    }
    setEventSaveError("");
    window.location.href = draft.href;
    showSuccessMessage(`Draft opened from ${template.name}.`);
  }

  const savedCommunicationCards: CommunicationCard[] = activeSavedCommunicationTemplates.map((template) => {
    const matchedFallback = fallbackCommunicationCards.find((card) => fallbackCardMatchesTemplate(card, template));
    const draft = getSavedCommunicationTemplateDraft(template);
    const fallbackStatusText = getFallbackStatusText(matchedFallback?.statusCode || "needs_info");
    const statusCode = matchedFallback?.statusSourceKey
      ? getCurrentCommunicationTemplateStatus(matchedFallback.statusSourceKey, fallbackStatusText)
      : draft.ready
        ? "ready_to_draft"
        : "needs_info";
    const readyToDraft = Boolean(
      statusCode === "ready_to_draft" ||
      statusCode === "drafted" ||
      statusCode === "sent" ||
      statusCode === "completed" ||
      statusCode === "not_needed"
    );
    const fallbackBlocksReadiness = Boolean(matchedFallback && !matchedFallback.ready);
    const actionEnabled = matchedFallback?.actionEnabled ?? (draft.ready || statusCode === "not_needed");
    return {
      key: `saved-template-${template.id || normalizeEmailTemplateMatchValue(template.name)}`,
      title: template.name,
      description: matchedFallback?.description || "Saved email template from Settings.",
      statusCode,
      statusSourceKey: matchedFallback?.statusSourceKey,
      status: communicationTemplateStatusLabel[statusCode],
      statusDetail: statusCode === "not_needed"
        ? `Marked complete without sending ${template.name}.`
        : readyToDraft
          ? `Saved ${getEmailTemplateCategoryLabel(template.category)} template. ${draft.fromLabel ? `From: ${draft.fromLabel}. ` : ""}SP recipients remain in BCC when included.`
          : fallbackBlocksReadiness && matchedFallback
            ? matchedFallback.statusDetail
            : draft.statusDetail,
      ready: readyToDraft,
      href: draft.href,
      cc: draft.cc.length,
      categoryLabel: getEmailTemplateCategoryLabel(template.category),
      templateSource: "saved",
      actionEnabled,
      actionLabel: fallbackBlocksReadiness && matchedFallback ? matchedFallback.actionLabel || "Draft Email" : "Draft Email",
      onMarkDrafted: matchedFallback?.onMarkDrafted,
      onMarkSent: matchedFallback?.onMarkSent,
      onMarkCompleted: matchedFallback?.onMarkCompleted,
      onMarkNotNeeded: matchedFallback?.onMarkNotNeeded,
      onClick: () => {
        if (fallbackBlocksReadiness && matchedFallback) {
          void matchedFallback.onClick();
          return;
        }
        handleDraftSavedCommunicationTemplate(template);
      },
    };
  });
  const fallbackCardsWithoutSavedMatches: CommunicationCard[] = fallbackCommunicationCards
    .filter((card) => !activeSavedCommunicationTemplates.some((template) => fallbackCardMatchesTemplate(card, template)))
    .map((card) => ({
      ...card,
      categoryLabel: getEmailTemplateCategoryLabel(card.templateCategory),
      templateSource: "fallback" as const,
    }));
  const communicationCards: CommunicationCard[] = [
    ...savedCommunicationCards,
    ...fallbackCardsWithoutSavedMatches,
  ];
  const mailtoHref = buildMailtoHref({
    bcc: hiringEmailBccEmails.length ? hiringEmailBccEmails : bccEmails,
    subject: hiringPollEmailDraft.subject || emailSubject,
    body: hiringPollEmailDraft.body || emailBody,
  });

  function clearActionFeedbackTimers() {
    if (feedbackTimeoutRef.current) {
      window.clearTimeout(feedbackTimeoutRef.current);
      feedbackTimeoutRef.current = null;
    }
  }

  function showSuccessMessage(message: string, duration = 4200) {
    setErrorMessage("");
    setAssignmentSuccessMessage("");
    setEventSaveError("");
    setEventSaveMessage(message);
    clearActionFeedbackTimers();
    feedbackTimeoutRef.current = window.setTimeout(() => {
      setEventSaveMessage("");
      feedbackTimeoutRef.current = null;
    }, duration);
  }

  const applyCommandCenterData = useCallback(
    (
      result: CommandCenterData,
      options?: { preserveLocalEdits?: boolean; preserveSelectedSp?: boolean }
    ) => {
      const nextEventEditor = buildEventEditorStateFromEvent(result.event);
      const nextSessionEditor = getEventDetailsSessionEditorState(
        result.sessions,
        result.event?.date_text,
        parseEventMetadata(result.event?.notes).training
      );

      setEvent(result.event);
      if (options?.preserveLocalEdits && hasUnsavedEventEditorChangesRef.current) {
        setEventEditor((current) => {
          const mergedNotes = mergeLiveOperationalNotes(current.notes, nextEventEditor.notes);
          return mergedNotes === current.notes ? current : { ...current, notes: mergedNotes };
        });
      } else {
        setEventEditor(nextEventEditor);
      }
      if (!(options?.preserveLocalEdits && hasUnsavedSessionEditorChangesRef.current)) {
        setSessionEditor(nextSessionEditor);
      }
      setSessions(result.sessions);
      setSps(result.sps);
      setAssignments(result.assignments);
      setAvailabilityRows(result.availabilityRows);
      setRelatedOperationalEvents(result.relatedEvents);
      setViewerRole(result.viewerRole || "unknown");
      setSpPortal(result.spPortal || null);
      setErrorMessage(result.errorMessage);
      setDebugMessage(result.debugMessage || "");
      setSessionErrorMessage(result.sessionErrorMessage);
      setAvailabilityErrorMessage(result.availabilityErrorMessage);
      setAccessDenied(result.accessDenied);
      setNotFound(result.notFound);
      setSelectedSpId((current) => (options?.preserveSelectedSp ? current : ""));
    },
    []
  );

  const refreshData = useCallback(
    async (
      options?: {
        preserveLocalEdits?: boolean;
        preserveSelectedSp?: boolean;
        source?: "initial" | "manual" | "focus" | "realtime" | "fallback";
      }
    ) => {
      if (!id) return null;

      const refreshSource = options?.source || "manual";
      if (refreshSource === "realtime" || refreshSource === "fallback") {
        setLiveSyncState("syncing");
      }

      const result = await fetchCommandCenterData(id, linkedTrainingSourceId);
      if (result.redirectToPrimaryEventId && result.redirectToPrimaryEventId !== id) {
        router.replace(`/events/${encodeURIComponent(result.redirectToPrimaryEventId)}?trainingSource=${encodeURIComponent(result.sourceTrainingEventId || id)}`);
        return result;
      }
      if (result.redirectToEventsSearch) {
        router.replace(`/events?search=${encodeURIComponent(result.redirectToEventsSearch)}&trainingSource=${encodeURIComponent(result.sourceTrainingEventId || id)}`);
        return result;
      }

      applyCommandCenterData(result, {
        preserveLocalEdits: options?.preserveLocalEdits,
        preserveSelectedSp: options?.preserveSelectedSp,
      });

      const nextAttendanceRecords = await fetchLearnerAttendanceRecordsForEvent(id);
      if (nextAttendanceRecords) {
        setPersistedLearnerAttendanceRecords(nextAttendanceRecords);
      }

      if (refreshSource !== "manual") {
        setLiveSyncLastUpdatedAt(new Date().toISOString());
      }
      if (refreshSource === "realtime" || refreshSource === "fallback" || refreshSource === "focus") {
        setLiveSyncState("connected");
      }

      return result;
    },
    [applyCommandCenterData, id, linkedTrainingSourceId, router]
  );

  const commandCenterFinderEntries = useMemo(
    () => finderEvents.map((finderEvent) => buildFinderIndexedEvent(finderEvent)),
    [finderEvents]
  );

  async function saveAssignmentRequest(method: "POST" | "PATCH" | "DELETE", body: object) {
    const response = await fetch(`/api/events/${encodeURIComponent(id)}`, {
      method,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });

    if (!response.ok) {
      throw new Error(await parseApiError(response));
    }

    const payload = await response.json().catch(() => null);
    if (!payload || payload.ok === false) {
      throw new Error(sanitizePublicErrorMessage(payload?.message || payload?.error, "The assignment request did not complete."));
    }
    return payload;
  }

  async function assignMultipleSpIds(
    spIds: string[],
    successLabel: string,
    options?: AssignSpOptions
  ) {
    if (!id || spIds.length === 0) return;

    setSaving(true);
    setAssigningSpId("");
    setAssignmentSuccessMessage("");
    setErrorMessage("");
    setEventSaveMessage("Saving...");
    setEventSaveError("");

    try {
      for (const spId of spIds) {
        const importedPollNote = asText(options?.notesBySpId?.[String(spId)]);
        const assignmentNotes = mergeImportedPollNoteIntoAssignmentNotes("", importedPollNote);
        await saveAssignmentRequest("POST", {
          sp_id: spId,
          status: options?.status,
          confirmed: options?.confirmed,
          notes: assignmentNotes || undefined,
        });
      }

      await refreshData();
      showSuccessMessage(successLabel);
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : "Could not save assignment.");
    } finally {
      setSaving(false);
    }
  }

  async function saveEventDetails() {
    if (!id) return;

    const nextSpNeeded = Number(eventEditor.sp_needed);
    const spNeeded =
      eventEditor.sp_needed.trim() === "" || Number.isNaN(nextSpNeeded)
        ? 0
        : Math.max(0, Math.round(nextSpNeeded));
    const trimmedSessionDate = sessionEditor.session_date.trim();
    const startTime = toStoredTimeValue(sessionEditor.start_time);
    const endTime = toStoredTimeValue(sessionEditor.end_time);
    const nextEventNotes = upsertEventMetadata(eventEditor.notes, {
      training: {
        event_session_date: trimmedSessionDate,
        event_start_time: startTime || "",
        event_end_time: endTime || "",
        training_date: trainingMetadata.preferred_training_date || trainingMetadata.training_date,
        training_start_time: trainingMetadata.preferred_training_time || trainingMetadata.training_start_time,
        training_end_time: trainingMetadata.preferred_training_end_time || trainingMetadata.training_end_time,
      },
      eventTypes: activeEventTypes,
    });
    const shouldUpdateStructuredSessionFromEventDetails = sessions.length <= 1;

    setSaving(true);
    setEventSaveMessage("Saving...");
    setEventSaveError("");

    try {
      const response = await fetch(`/api/events/${encodeURIComponent(id)}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          event_updates: {
            name: eventEditor.name,
            status: eventEditor.status,
            visibility: eventEditor.visibility,
            location: eventEditor.location,
            notes: nextEventNotes,
            date_text: trimmedSessionDate || null,
            sp_needed: spNeeded,
          },
          session_updates: shouldUpdateStructuredSessionFromEventDetails
            ? {
                session_date: trimmedSessionDate || null,
                start_time: startTime,
                end_time: endTime,
              }
            : undefined,
        }),
      });

      if (!response.ok) {
        throw new Error(await parseApiError(response));
      }

      showSuccessMessage("Saved");
      await refreshData();
    } catch (error) {
      setEventSaveError(
        error instanceof Error ? error.message : "Could not save event details."
      );
      setSaving(false);
      return;
    }

    setSaving(false);
  }

  function handleCloseCreateFollowUpModal() {
    if (followUpSaving) return;
    setShowCreateFollowUpModal(false);
  }

  function handleFollowUpDraftChange<K extends keyof FollowUpSimulationDraft>(
    key: K,
    value: FollowUpSimulationDraft[K]
  ) {
    setFollowUpError("");
    setFollowUpSuccess(null);
    setFollowUpDraft((current) => ({ ...current, [key]: value }));
  }

  function handleToggleFollowUpCopyOption(key: keyof FollowUpCopyOptions) {
    setFollowUpError("");
    setFollowUpSuccess(null);
    setFollowUpDraft((current) => {
      const nextCopyOptions = { ...current.copyOptions };

      if (key === "copyLearnerRoster" && current.copyOptions.copyScheduleStructure) {
        return current;
      }

      nextCopyOptions[key] = !current.copyOptions[key];

      if (key === "copyScheduleStructure" && nextCopyOptions.copyScheduleStructure) {
        nextCopyOptions.copyLearnerRoster = true;
      }
      if (key === "copyScheduleStructure" && !nextCopyOptions.copyScheduleStructure) {
        nextCopyOptions.createCompletedSchedule = false;
      }
      if (key === "createCompletedSchedule" && nextCopyOptions.createCompletedSchedule) {
        nextCopyOptions.copyScheduleStructure = true;
        nextCopyOptions.copyLearnerRoster = true;
      }

      return {
        ...current,
        copyOptions: nextCopyOptions,
      };
    });
  }

  async function handleCreateFollowUpSimulation() {
    if (!id) return;

    if (!followUpDraft.name.trim()) {
      setFollowUpError("Enter a name for the follow-up simulation.");
      return;
    }
    if (!followUpDraft.date.trim()) {
      setFollowUpError("Choose a date for the follow-up simulation.");
      return;
    }

    setFollowUpSaving(true);
    setFollowUpError("");
    setFollowUpSuccess(null);

    try {
      // IMPORTANT FOLLOW-UP SIMULATION GUARD:
      // Follow-up simulations copy operational structure, not live completion state.
      // Do not copy attendance, delivered announcements, completed checklist state,
      // or old live event statuses into the new event.
      const response = await fetch(`/api/events/${encodeURIComponent(id)}/create-follow-up`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: followUpDraft.name,
          date: followUpDraft.date,
          startTime: followUpDraft.startTime,
          endTime: followUpDraft.endTime,
          location: followUpDraft.location,
          status: followUpDraft.status,
          visibility: followUpDraft.visibility,
          notes: followUpDraft.notes,
          copyOptions: followUpDraft.copyOptions,
        }),
      });
      const body = (await response.json().catch(() => null)) as
        | { error?: string; event?: { id?: string; name?: string | null }; redirectUrl?: string }
        | null;

      if (!response.ok || !body?.event?.id || !body.redirectUrl) {
        throw new Error(body?.error || "Could not create follow-up simulation.");
      }

      setFollowUpSuccess({
        id: body.event.id,
        name: asText(body.event.name) || followUpDraft.name,
        redirectUrl: body.redirectUrl,
      });
      setEventSaveMessage("Follow-up simulation created.");
      setEventSaveError("");
      await refreshData({
        preserveLocalEdits: true,
        preserveSelectedSp: true,
        source: "manual",
      });
    } catch (error) {
      setFollowUpError(
        error instanceof Error ? error.message : "Could not create follow-up simulation."
      );
    } finally {
      setFollowUpSaving(false);
    }
  }

  const handleDeleteEvent = useCallback(async () => {
    if (!id || !event) return;

    const eventTitle = event?.name || "this event";
    const confirmed = window.confirm(
      `Delete "${eventTitle}"?\n\nThis will remove the event and its related sessions and SP assignments.`
    );
    if (!confirmed) return;

    setDeletingEvent(true);
    setEventSaveMessage("");
    setEventSaveError("");

    try {
      const response = await fetch(`/api/events/${encodeURIComponent(id)}`, {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
      });

      if (!response.ok) {
        throw new Error(await parseApiError(response));
      }

      router.push("/events");
      router.refresh();
    } catch (error) {
      setEventSaveError(error instanceof Error ? error.message : "Could not delete event.");
      setDeletingEvent(false);
    }
  }, [event, id, router]);

  useEffect(() => {
    const existing = document.getElementById("cfsp-delete-event-floating-button");
    if (existing) existing.remove();

    const button = document.createElement("button");
    button.id = "cfsp-delete-event-floating-button";
    button.type = "button";
    button.textContent = "Delete Event";
    button.title = "Delete this event";
    button.style.position = "fixed";
    button.style.right = "18px";
    button.style.bottom = "18px";
    button.style.zIndex = "2147483647";
    button.style.padding = "8px 10px";
    button.style.borderRadius = "10px";
    button.style.border = "1px solid rgba(220, 38, 38, 0.28)";
    button.style.background = "rgba(255, 255, 255, 0.92)";
    button.style.color = "#dc2626";
    button.style.fontSize = "11px";
    button.style.fontWeight = "800";
    button.style.boxShadow = "0 8px 22px rgba(15, 23, 42, 0.16)";
    button.style.opacity = "0.55";
    button.style.cursor = "pointer";
    button.style.backdropFilter = "blur(10px)";

    button.onmouseenter = () => {
      button.style.opacity = "1";
      button.style.background = "#fef2f2";
    };

    button.onmouseleave = () => {
      button.style.opacity = "0.55";
      button.style.background = "rgba(255, 255, 255, 0.92)";
    };

    button.onclick = () => {
      void handleDeleteEvent();
    };

    document.body.appendChild(button);

    return () => {
      button.remove();
    };
  }, [event?.id, handleDeleteEvent]);


