  async function persistAnnouncementCueMetadata(args: {
    cueState?: Record<string, AnnouncementCueStateRecord>;
    alertSettings?: {
      liveModeActive?: boolean;
      muteAlerts?: boolean;
      notificationsEnabled?: boolean;
      lastStartedAt?: string;
    };
    successMessage?: string;
    quiet?: boolean;
  }) {
    if (!id) return false;

    setAnnouncementCueSaving(true);
    setEventSaveError("");
    try {
      const nextNotes = upsertEventMetadata(sanitizeScheduleWorkflowNotes(eventEditor.notes), {
        training: {
          announcement_cue_state: serializeAnnouncementCueState(args.cueState || announcementCueStateMap),
          announcement_alert_settings: serializeAnnouncementAlertSettings(args.alertSettings || announcementAlertSettingsState),
        },
      });
      const response = await fetch(`/api/events/${encodeURIComponent(id)}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          event_updates: {
            notes: nextNotes,
          },
        }),
      });

      if (!response.ok) {
        throw new Error(await parseApiError(response));
      }

      setEvent((current) => (current ? { ...current, notes: nextNotes } : current));
      setEventEditor((current) => ({ ...current, notes: nextNotes }));
      await refreshData({
        preserveLocalEdits: true,
        preserveSelectedSp: true,
        source: "manual",
      });
      if (!args.quiet) {
        showSuccessMessage(args.successMessage || "Announcement cues updated.");
      }
      return true;
    } catch (error) {
      setEventSaveError(error instanceof Error ? error.message : "Could not update announcement cues.");
      return false;
    } finally {
      setAnnouncementCueSaving(false);
    }
  }

  function buildAnnouncementAlertSettingsNotes(settings: AnnouncementAlertSettings) {
    return upsertEventMetadata(sanitizeScheduleWorkflowNotes(eventEditor.notes), {
      training: {
        announcement_alert_settings: serializeAnnouncementAlertSettings(settings),
      },
    });
  }

  async function persistAnnouncementAlarmSettings(
    nextSettings: AnnouncementAlertSettings,
    successMessage: string
  ) {
    if (!id) return false;

    const previousSettings = announcementAlertSettingsState;
    setAnnouncementCueSaving(true);
    setAnnouncementAlertSaveStatus("saving");
    setAnnouncementAlertSaveError("");
    setEventSaveError("");
    setAnnouncementAlertSettingsState(nextSettings);

    try {
      const response = await fetch(`/api/events/${encodeURIComponent(id)}/announcement-alarms`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          alert_settings: nextSettings,
        }),
      });
      const parsed = await readSafeJsonResponse<{ ok?: boolean; alert_settings?: AnnouncementAlertSettings }>(
        response,
        `/api/events/${id}/announcement-alarms`,
        "Could not save announcement alarm settings."
      );

      if (!parsed.ok) {
        throw new Error(formatSafeJsonDiagnostic(parsed));
      }

      const nextNotes = buildAnnouncementAlertSettingsNotes(nextSettings);
      setEvent((current) => (current ? { ...current, notes: nextNotes } : current));
      setEventEditor((current) => ({ ...current, notes: nextNotes }));
      setAnnouncementAlertSaveStatus("saved");
      setAnnouncementAlertSaveError("");
      showSuccessMessage(successMessage);
      return true;
    } catch (error) {
      const message = sanitizePublicErrorMessage(
        error instanceof Error ? error.message : "",
        `Failed to save alarm settings via /api/events/${id}/announcement-alarms.`
      );
      setAnnouncementAlertSettingsState(previousSettings);
      setAnnouncementAlertSaveStatus("error");
      setAnnouncementAlertSaveError(message);
      setEventSaveError(message);
      return false;
    } finally {
      setAnnouncementCueSaving(false);
    }
  }

  async function handleUpdateAnnouncementCueStatus(
    key: string,
    status: "delivered" | "skipped",
    successMessage: string
  ) {
    const timestamp = new Date().toISOString();
    const nextCueState = {
      ...announcementCueStateMap,
      [key]: {
        ...announcementCueStateMap[key],
        status,
        updatedAt: timestamp,
        updatedBy: me?.scheduleName || me?.fullName || me?.email || "",
        snoozedUntil: "",
      },
    };
    const saved = await persistAnnouncementCueMetadata({
      cueState: nextCueState,
      successMessage,
    });
    if (saved) {
      setAnnouncementDueCueKeys((current) => {
        if (!current[key]) return current;
        const next = { ...current };
        delete next[key];
        return next;
      });
    }
  }

  async function handleSnoozeAnnouncementCue(key: string) {
    const timestamp = new Date().toISOString();
    const nextCueState = {
      ...announcementCueStateMap,
      [key]: {
        ...announcementCueStateMap[key],
        updatedAt: timestamp,
        updatedBy: me?.scheduleName || me?.fullName || me?.email || "",
        snoozedUntil: new Date(Date.now() + 60 * 1000).toISOString(),
      },
    };
    delete nextCueState[key].status;
    const saved = await persistAnnouncementCueMetadata({
      cueState: nextCueState,
      successMessage: "Announcement snoozed for 1 minute.",
    });
    if (saved) {
      setAnnouncementDueCueKeys((current) => {
        if (!current[key]) return current;
        const next = { ...current };
        delete next[key];
        return next;
      });
    }
  }

  async function handleToggleAnnouncementAlertsMuted() {
    await persistAnnouncementAlarmSettings(
      {
        ...announcementAlertSettingsState,
        liveModeActive: announcementLiveModeActive,
        muteAlerts: !announcementAlertsMuted,
        notificationsEnabled: announcementNotificationsEnabled,
      },
      announcementAlertsMuted ? "Announcement alerts unmuted." : "Announcement alerts muted."
    );
  }

  async function handleToggleAnnouncementLiveMode() {
    const nextLiveModeActive = !announcementLiveModeActive;
    const saved = await persistAnnouncementAlarmSettings(
      {
        ...announcementAlertSettingsState,
        liveModeActive: nextLiveModeActive,
        muteAlerts: announcementAlertsMuted,
        notificationsEnabled: announcementNotificationsEnabled,
        lastStartedAt: nextLiveModeActive ? new Date().toISOString() : announcementAlertSettingsState.lastStartedAt || "",
      },
      nextLiveModeActive ? "Live cue board started." : "Live cue board stopped."
    );
    if (saved) {
      if (nextLiveModeActive) {
        setAnnouncementAlarmArmedMap((current) => {
          const next = { ...current };
          selectedRoundAnnouncementReminders.forEach((reminder) => {
            next[reminder.id] = true;
          });
          return next;
        });
      } else {
        setAnnouncementDueCueKeys({});
      }
    }
  }

  async function handleToggleAnnouncementNotifications() {
    if (typeof window === "undefined" || typeof Notification === "undefined") {
      setEventSaveError("Browser notifications are not available in this browser.");
      return;
    }

    let nextPermission = Notification.permission;
    if (!announcementNotificationsEnabled && nextPermission === "default") {
      nextPermission = await Notification.requestPermission();
    }
    setAnnouncementNotificationsPermission(nextPermission);
    if (nextPermission !== "granted" && !announcementNotificationsEnabled) {
      setEventSaveError("Browser notification permission was not granted.");
      return;
    }

    await persistAnnouncementAlarmSettings(
      {
        ...announcementAlertSettingsState,
        liveModeActive: announcementLiveModeActive,
        muteAlerts: announcementAlertsMuted,
        notificationsEnabled: !announcementNotificationsEnabled,
      },
      announcementNotificationsEnabled
        ? "Browser notifications disabled."
        : "Browser notifications enabled."
    );
  }

  async function handleTestAnnouncementAlert() {
    await playAnnouncementCueAlert("Announcement Due", "Test alert: cue board alarm.");
    showSuccessMessage("Test alert sent.");
  }

  async function handleCopyRoundAnnouncement(text: string) {
    const announcementText = asText(text);
    if (!announcementText) return;
    try {
      if (typeof navigator === "undefined" || !navigator.clipboard?.writeText) {
        throw new Error("Clipboard is unavailable in this browser.");
      }
      await navigator.clipboard.writeText(announcementText);
      setEventSaveMessage("Announcement copied.");
      setEventSaveError("");
    } catch (error) {
      setEventSaveError(error instanceof Error ? error.message : "Could not copy announcement.");
    }
  }

  function escapeAnnouncementHtml(value: unknown) {
    return asText(value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
  }

  function getAnnouncementExportSlug(value: unknown) {
    return asText(value)
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "")
      .slice(0, 72) || "event";
  }

  function buildAnnouncementPrintHtml() {
    const eventName = event?.name || "Untitled Event";
    const eventDate = selectedRotationRound?.session_date
      ? formatHumanDate(selectedRotationRound.session_date, importedYearHint) || selectedRotationRound.session_date
      : event?.date_text || "Date TBD";
    const timeWindow =
      selectedRotationRound?.start_time || selectedRotationRound?.end_time
        ? `${formatDisplayTime(selectedRotationRound.start_time)}${selectedRotationRound.end_time ? ` - ${formatDisplayTime(selectedRotationRound.end_time)}` : ""}`
        : summaryTimeLabel || "Time TBD";
    const scope = selectedRotationRound ? `Round ${activeSelectedRotationRoundIndex + 1}` : "Selected timeline";
    const rowsHtml = selectedRoundAnnouncementExportRows
      .map(
        (entry, index) => `
          <tr>
            <td>${index + 1}</td>
            <td>${escapeAnnouncementHtml(entry.timeLabel)}</td>
            <td>${escapeAnnouncementHtml(entry.phaseLabel)}</td>
            <td>${escapeAnnouncementHtml(entry.audienceLabel)}</td>
            <td>${escapeAnnouncementHtml(entry.detail || "Operational announcement")}</td>
            <td>${escapeAnnouncementHtml(entry.message)}</td>
          </tr>
        `
      )
      .join("");

    return `<!doctype html>
      <html>
        <head>
          <meta charset="utf-8" />
          <title>Announcement Schedule - ${escapeAnnouncementHtml(eventName)}</title>
          <style>
            body { margin: 0; padding: 28px; font-family: Arial, sans-serif; color: #14304f; background: #ffffff; }
            h1 { margin: 0; font-size: 24px; letter-spacing: 0.03em; }
            .meta { margin: 12px 0 20px; display: grid; gap: 6px; font-size: 13px; font-weight: 700; color: #45657d; }
            table { width: 100%; border-collapse: collapse; font-size: 12px; }
            th { text-align: left; background: #e8f4ff; color: #145b96; text-transform: uppercase; letter-spacing: 0.06em; font-size: 10px; }
            th, td { border: 1px solid #cfe0eb; padding: 9px; vertical-align: top; }
            td:last-child { font-size: 14px; font-weight: 800; line-height: 1.45; color: #14304f; }
            .notes { margin-top: 24px; border: 1px solid #cfe0eb; min-height: 120px; padding: 12px; }
            .notes-title { font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; color: #145b96; }
            @media print { body { padding: 18px; } button { display: none; } }
          </style>
        </head>
        <body>
          <h1>Announcement Schedule</h1>
          <div class="meta">
            <div>Event: ${escapeAnnouncementHtml(eventName)}</div>
            <div>Date: ${escapeAnnouncementHtml(eventDate)}</div>
            <div>Time Window: ${escapeAnnouncementHtml(timeWindow)}</div>
            <div>Scope: ${escapeAnnouncementHtml(scope)}</div>
          </div>
          <table>
            <thead>
              <tr>
                <th>#</th>
                <th>Time</th>
                <th>Cue</th>
                <th>Audience</th>
                <th>Timing Context</th>
                <th>Message</th>
              </tr>
            </thead>
            <tbody>${rowsHtml}</tbody>
          </table>
          <div class="notes">
            <div class="notes-title">Operator Notes</div>
          </div>
        </body>
      </html>`;
  }

  function handlePrintAnnouncementSchedule() {
    if (typeof window === "undefined") return;
    const printWindow = window.open("", "_blank", "noopener,noreferrer,width=960,height=720");
    if (!printWindow) {
      setEventSaveError("Could not open print window. Check popup settings.");
      return;
    }
    printWindow.document.open();
    printWindow.document.write(buildAnnouncementPrintHtml());
    printWindow.document.close();
    printWindow.focus();
    window.setTimeout(() => {
      printWindow.print();
    }, 250);
  }

  async function handleCopyAnnouncementScript() {
    if (!selectedRoundAnnouncementExportText.trim()) return;
    try {
      if (typeof navigator === "undefined" || !navigator.clipboard?.writeText) {
        throw new Error("Clipboard is unavailable in this browser.");
      }
      await navigator.clipboard.writeText(selectedRoundAnnouncementExportText);
      setEventSaveMessage("Announcement script copied.");
      setEventSaveError("");
    } catch (error) {
      setEventSaveError(error instanceof Error ? error.message : "Could not copy announcement script.");
    }
  }

  function handleDownloadAnnouncementText() {
    if (typeof document === "undefined") return;
    const blob = new Blob([selectedRoundAnnouncementExportText], { type: "text/plain;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = `${getAnnouncementExportSlug(event?.name || "event")}-announcement-schedule.txt`;
    document.body.appendChild(anchor);
    anchor.click();
    anchor.remove();
    URL.revokeObjectURL(url);
  }

  async function handleTrainingAttendanceToggle(assignment: AssignmentRow, checked: boolean) {
    if (!isTrainingAttendanceInteractive) return;
    setAttendanceSaving(true);
    setAttendanceError("");
    setAttendanceSuccess("");

    try {
      const body = await saveAssignmentRequest("PATCH", {
        assignment_id: assignment.id,
        updates: {
          training_attended: checked,
          training_checked_in_at: checked ? new Date().toISOString() : null,
        },
      });

      if (body?.assignment) {
        setAssignments((current) =>
          current.map((item) => (item.id === assignment.id ? { ...item, ...body.assignment } : item))
        );
      } else {
        await refreshData();
      }
      setAttendanceSuccess(checked ? "Attendance updated." : "Attendance cleared.");
    } catch (error) {
      setAttendanceError(error instanceof Error ? error.message : "Could not update training attendance.");
    } finally {
      setAttendanceSaving(false);
    }
  }

  async function handleEventSpAttendanceAction(
    assignment: AssignmentRow,
    action: "expected" | "arrived" | "late" | "missing" | "in_room" | "completed",
    note?: string,
    options?: { silent?: boolean }
  ) {
    const now = new Date().toISOString();
    const nextCheckedInAt = action === "expected" || action === "missing" ? null : (assignment.event_checked_in_at || now);
    const savingKey = `sp:${assignment.id}`;
    const previousAssignment = assignments.find((item) => item.id === assignment.id) || assignment;
    const optimisticAssignment = {
      ...previousAssignment,
      event_checked_in_at: nextCheckedInAt,
      event_attendance_status: action,
      ...(note !== undefined ? { attendance_note: note } : {}),
    };

    setAttendanceSavingKeys((current) => ({ ...current, [savingKey]: true }));
    setAssignments((current) => current.map((item) => (item.id === assignment.id ? optimisticAssignment : item)));
    setAttendanceError("");
    setAttendanceSuccess("");

    try {
      const body = await saveAssignmentRequest("PATCH", {
        assignment_id: assignment.id,
        updates: {
          event_checked_in_at: nextCheckedInAt,
          event_attendance_status: action,
          ...(note !== undefined ? { attendance_note: note } : {}),
        },
      });

      if (body?.assignment) {
        setAssignments((current) =>
          current.map((item) => (item.id === assignment.id ? { ...item, ...body.assignment } : item))
        );
      }

      if (!options?.silent) {
        setAttendanceSuccess(`SP marked ${getEventAttendanceStatusLabel(action).toLowerCase()}.`);
      }
      return true;
    } catch (error) {
      setAssignments((current) => current.map((item) => (item.id === assignment.id ? previousAssignment : item)));
      setAttendanceError(error instanceof Error ? error.message : "Could not update event attendance.");
      return false;
    } finally {
      setAttendanceSavingKeys((current) => {
        const next = { ...current };
        delete next[savingKey];
        return next;
      });
    }
  }

  function handleEventSpAttendanceNote(assignment: AssignmentRow) {
    const note = window.prompt("Attendance note", asText(assignment.attendance_note));
    if (note === null) return;
    const currentStatus = asText(assignment.event_attendance_status);
    const safeStatus = ["expected", "arrived", "late", "missing", "in_room", "completed"].includes(currentStatus)
      ? (currentStatus as "expected" | "arrived" | "late" | "missing" | "in_room" | "completed")
      : "expected";
    void handleEventSpAttendanceAction(
      assignment,
      safeStatus,
      note
    );
  }

  async function handleLiveLearnerAttendanceAction(
    token: {
      attendanceKey: string;
      learnerName: string;
      roomName: string;
      status: LearnerAttendanceStatus;
    },
    action: LearnerAttendanceStatus | "clear",
    note?: string,
    options?: { silent?: boolean }
  ) {
    if (!id || !token.attendanceKey) return;

    const now = new Date().toISOString();
    const savingKey = `learner:${token.attendanceKey}`;
    const previousRecords = { ...liveLearnerAttendanceRecords };
    const nextRecords: LearnerAttendanceMap = { ...liveLearnerAttendanceRecords };
    if (action === "clear" || action === "expected") {
      delete nextRecords[token.attendanceKey];
    } else {
      nextRecords[token.attendanceKey] = {
        status: action,
        updatedAt: now,
        roomName: token.roomName,
        roundKey: asText(currentLiveReferenceRound?.key) || asText(selectedRotationRound?.key),
        note: note !== undefined ? note : nextRecords[token.attendanceKey]?.note,
      };
    }
    if (note !== undefined && nextRecords[token.attendanceKey]) {
      nextRecords[token.attendanceKey] = {
        ...nextRecords[token.attendanceKey],
        note,
      };
    }

    const nextNotes = upsertEventMetadata(eventEditor.notes, {
      training: {
        live_learner_attendance: serializeLearnerAttendanceMetadata(nextRecords),
      } as Partial<TrainingEventMetadata>,
    });

    setAttendanceSavingKeys((current) => ({ ...current, [savingKey]: true }));
    setPersistedLearnerAttendanceRecords(nextRecords);
    setAttendanceError("");
    setAttendanceSuccess("");

    try {
      const attendanceResponse = await fetch(`/api/events/${encodeURIComponent(id)}/learner-attendance`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          round_id: asText(currentLiveReferenceRound?.key) || asText(selectedRotationRound?.key),
          room: token.roomName,
          learner_name: token.learnerName,
          status: action === "clear" ? "expected" : action,
          checked_in_at: action === "clear" || action === "expected" ? null : now,
          ...(note !== undefined ? { note } : {}),
        }),
      });

      if (!attendanceResponse.ok) {
        throw new Error(await parseApiError(attendanceResponse));
      }

      const response = await fetch(`/api/events/${encodeURIComponent(id)}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          event_updates: {
            notes: nextNotes,
          },
        }),
      });

      if (!response.ok) {
        throw new Error(await parseApiError(response));
      }

      setEventEditor((current) => ({ ...current, notes: nextNotes }));
      setEvent((current) => (current ? { ...current, notes: nextNotes } : current));
      if (!options?.silent) {
        setAttendanceSuccess(
          action === "arrived"
            ? `${token.learnerName} marked arrived.`
            : action === "late"
              ? `${token.learnerName} marked late.`
              : action === "absent"
                ? `${token.learnerName} marked absent.`
                : action === "in_room"
                  ? `${token.learnerName} moved to room.`
                  : action === "completed"
                    ? `${token.learnerName} marked complete.`
                    : `${token.learnerName} attendance reset.`
        );
      }
      return true;
    } catch (error) {
      setPersistedLearnerAttendanceRecords(previousRecords);
      setAttendanceError(error instanceof Error ? error.message : "Could not update learner attendance.");
      return false;
    } finally {
      setAttendanceSavingKeys((current) => {
        const next = { ...current };
        delete next[savingKey];
        return next;
      });
    }
  }

  async function handleBulkEventSpAttendance(action: "arrived" | "expected") {
    const targets = visibleEventAttendanceSpTokens;
    if (!targets.length) return;
    setAttendanceError("");
    setAttendanceSuccess("");
    const results = await Promise.all(targets.map((token) => handleEventSpAttendanceAction(token.assignment, action, undefined, { silent: true })));
    const successCount = results.filter(Boolean).length;
    if (successCount === targets.length) {
      setAttendanceSuccess(action === "arrived" ? "Visible SPs marked arrived." : "Visible SPs reset to expected.");
      return;
    }
    setAttendanceError(`${targets.length - successCount} SP update${targets.length - successCount === 1 ? "" : "s"} failed. Retry the highlighted rows.`);
  }

  async function handleBulkEventLearnerAttendance(action: "arrived" | "expected") {
    const targets = visibleEventAttendanceLearnerTokens;
    if (!targets.length) return;
    setAttendanceError("");
    setAttendanceSuccess("");
    const results = await Promise.all(targets.map((token) => handleLiveLearnerAttendanceAction(token, action, undefined, { silent: true })));
    const successCount = results.filter(Boolean).length;
    if (successCount === targets.length) {
      setAttendanceSuccess(action === "arrived" ? "Visible learners marked arrived." : "Visible learners reset to expected.");
      return;
    }
    setAttendanceError(`${targets.length - successCount} learner update${targets.length - successCount === 1 ? "" : "s"} failed. Retry the highlighted rows.`);
  }

  function handleEventLearnerAttendanceNote(token: {
    attendanceKey: string;
    learnerName: string;
    roomName: string;
    status: LearnerAttendanceStatus;
  }) {
    const note = window.prompt("Learner attendance note", asText(liveLearnerAttendanceRecords[token.attendanceKey]?.note));
    if (note === null) return;
    void handleLiveLearnerAttendanceAction(token, token.status || "expected", note);
  }

  async function handleBulkTrainingAttendance(action: "confirm_all" | "clear_all") {
    if (!sortedAssignments.length) return;
    if (!isTrainingAttendanceInteractive) return;

    setAttendanceSaving(true);
    setAttendanceError("");
    setAttendanceSuccess("");

    try {
      const body = await saveAssignmentRequest("PATCH", {
        attendance_action: action,
      });

      if (Array.isArray(body?.assignments)) {
        setAssignments(body.assignments);
      } else {
        await refreshData();
      }
      setAttendanceSuccess(action === "confirm_all" ? "All assigned SPs marked present." : "Training attendance cleared.");
    } catch (error) {
      setAttendanceError(error instanceof Error ? error.message : "Could not update training attendance.");
    } finally {
      setAttendanceSaving(false);
    }
  }

